INSERT INTO `contact_form` (`id`, `name`, `email`, `subject`, `message`, `submitted_at`) VALUES
(1, 'Piyush Bhagat', 'piyush.bhagat14@gmail.com', '9 days trip - need car with a driver', '\r\n\r\nSubject: Request for Best Quotation – Private Car with Driver (May 8–16, 2025)\r\n\r\nRespected Sir\r\n\r\nI am planning a family trip to Sri Lanka from May 8 to May 16, 2025, and would like to book a private air-conditioned sedan with an experienced driver for the full duration—from airport pickup on May 8 to airport drop on May 16.\r\n\r\nWe are 2 adults and 1 child (3 years old), and our itinerary covers Colombo, Anuradhapura, wilpattu,Trincomalee, Kandy, Nuwara Eliya, Bentota, and back to Colombo.\r\n\r\nKindly send me your best discounted all-inclusive quotation for this 9-day journey. Please ensure your quote covers:\r\n\r\nVehicle, fuel, and driver charges\r\n\r\nDriver’s accommodation and meals\r\n\r\nToll, parking, and taxes\r\n\r\nAny daily kilometer limits, if applicable\r\n\r\nBooking terms and payment policy\r\n\r\n\r\nWe are looking for a clean, comfortable, and budget-friendly option, with a reliable and courteous driver who understands basic English.\r\n\r\nLooking forward to your competitive offer.\r\n\r\nWarm regards,\r\nDr. Piyush Bhagat\r\n+919265299419', '2025-05-02 20:29:05'),
(2, 'Anand Vishwanath', 'anand.vishwanath@anvisinc.com', 'Car rental with driver : 09 May-15 May ', 'Hello, We are a family of three visiting Srilanka from 09 May to 15 May. We are looking to hire a new model, well maintained SUV with a polite, english speaking driver.\nOur Itinerary is somewhat like this Colombo-Bentota-Ahangama-Ella-Kandy-Colombo. We may add a few other places in and around these. Approx kms of travel is 1000 kms. \nPlease can you share a quote with your best rates at the earliest. Thanks.', '2025-05-04 09:09:53'),
(4, 'Phillipp Rautert ', 'phira84@gmail.com', 'Rental car ', 'I would like to rent a car for at least 4 months... smallest and cheapest car ... Can you give any discounts? Your cheapest car was 30 Euro per week online. Best regards ', '2025-05-05 13:14:31'),
(5, 'Mayank Dalmia', 'mayankdalmia95@gmail.com', 'Car rental from 20th - 25th may', 'Whats app +91 9703003004', '2025-05-06 16:21:18'),
(6, 'Shamir Mohideeen', 'shamir.mohideen@gmail.com', 'Rent a 14-seater Van from Kandy ', 'Hi, I’m looking to rent a 14-seater van (like a Toyota HiAce High Roof or similar) with a driver for 8 adults, 3 kids, and 1 infant.\r\nTrip details:\r\n\r\nMay 10: Pickup from 58 Senpathi Parami Kulathunga Mawatha, Kandy → Drop at 6375+WH3, Bridge, Ambalangoda\r\nMay 12: Pickup from Ambalangoda → Drop some family in Colombo → Final drop in Kandy\r\nWe need:\r\n\r\nRear A/C\r\nSpace for luggage\r\n1 infant seat + 2 child boosters\r\nPlease confirm availability and total cost for the 3-day hire, including fuel, driver, and any overnight stay charges.\r\n\r\nThank you,\r\nShamir Mohideen', '2025-05-06 23:18:18'),
(7, 'Alessandro Negrini', 'ALESSANDRONEGRINI@LIBERO.IT', 'Rent a Car', 'we would like to rent a car for 4 people:\r\nfrom 03 August at 5.30 AM\r\nto 13 August at 4.30 AM.\r\nDelivery and return point: Colombo Bandaranaike airport\r\nCould you make us an offer for a medium car or for a 4x4 car?\r\n\r\nWe have 2 children (7 years old - 120 cm tall and 10 years old - 140 cm tall) are child seats necessary for traveling in Sri Lanka?\r\n\r\nI have an Italian driving license, what do I have to do to be able to drive in Sri Lanka?\r\n\r\nThanks\r\nNegrini Alessandro', '2025-05-12 08:23:26'),
(8, 'SINNATHURAI SUBRAMANIAM', 'samsubra31@gmail.com', 'CAR RENTAL - 5 June 2025. ', 'Can you please cancel my booking?  I will rebook once I have booked the flight.\r\nPlease confirm the cancellation.', '2025-05-16 13:56:24'),
(9, 'Masayo Tsuchikawa', 'yeti.tsuchikawa@gmail.com', 'Please tell me the amount', 'Hello. I and husband would like to travel by car from Colombo city to Ayurvedic lanka wellness hotel on June 7th, and then travel back to Colombo city from this hotel on June 10th. Can you please give me a quote for the transfer?\r\nhttps://ayurvediclanka.com/', '2025-05-18 08:49:28'),
(10, 'Kumanan', 'kumanan.k@gmail.com', 'SUV - 8.07 - 30.07 ', 'Hi, \r\n\r\nCould you please send me your offers for a self-drive car rental?\r\n\r\n    Vehicle type: SUV (model year 2020 or newer, low mileage)\r\n\r\n    Rental period: 23 days — from 8 July to 30 July\r\n\r\n    Pickup location: Colombo\r\n\r\n    Drop-off location: Negombo\r\n\r\n    Passengers: 4 people\r\n\r\nLooking forward to your offer.\r\n\r\nBest regards,\r\nKumanan', '2025-05-20 14:34:07'),
(11, 'HÜSEYİN MERCİMEK', 'yenicilh@gmail.com', 'Rezevaryon', 'Merhaba, fiyat öğrenmeye çalılırken rezervasyom yaptım. İptal etmek istiyorum', '2025-05-20 14:49:29'),
(12, 'FRANCK PHILIPPET', 'franckphilippet@bbox.fr', 'question?', '\r\nHello\r\n\r\nI just rent a car whis oppodo number \r\nLK185564690\r\nstart JUNE 30 9H30 AM\r\nfinisch 11 JULY 8H30 PM\r\na reservation tell me \r\nHOTEL DELIVERY TO ALL 5 STAR HOTEL IN COLOMBO\r\n whitch hotel?\r\nFor us the best one is HOTEL GALLE FACE \r\npease contact me by email\r\n\r\ncordially franck\r\n\r\n', '2025-05-21 17:43:26'),
(13, 'arthur camain', 'arthur.camain@gmail.com', 'Rent a car', 'Hello, my name is Arthur Camain. I am traveling to Sri Lanka and I’m interested in renting a car (automatic transmission) from 09/08 to 24/08 inclusive.\r\nI have an international driving permit — do I need anything else to drive, or is that sufficient in case I get stopped by the police?\r\nI would also like to bring my surfboard with me (2 meters long), so I need a car that is long enough (not necessarily wide) to fit the board in the back without having to lower the front seat. What do u suggest as car ?\r\nDo you have an idea of the price per day? Is it possible to pick up the car at the airport?\r\nThank you,\r\nKind regards,\r\nArthur Camain\r\n', '2025-05-24 04:27:19'),
(14, 'Pulathisi  Godahewa ', 'pulathisilk@gmail.com', 'Hire car return ', 'Hi,\r\n\r\nI got to return the car at 11pm. Just thinking to return it couple of hours early and you don’t have to drop me at the airport. Unfortunately it says your mobile number is out of order. \r\n\r\nIs there any alternative number to reach you. \r\n\r\nThanks,\r\nPulathisi ', '2025-05-25 04:19:52'),
(15, 'Daniel', 'fahr.daniel@gmail.com', 'Inquiry', 'Rental Car Inquiry – Mid-Size Vehicle with Full Insurance and Driving Permits\r\nDear Madam, dear Sir,\r\n\r\nI hope this message finds you well.\r\n\r\nI would like to request a quote and availability for renting a mid-size vehicle for self-driving in Sri Lanka. Below are the key booking details and requirements:\r\nRental Dates & Details\r\n- Pick-up Date: [17.08.2025]\r\n- Drop-off Date: [02.09.2025]\r\n- Pick-up Location: [Colombo Airport]\r\n- Drop-off Location: [same]\r\nVehicle Requirements\r\n- Mid-size car (e.g., Toyota Axio, Honda Grace, or similar)\r\n- Automatic transmission preferred\r\n- Air conditioning\r\n- Reliable for long-distance travel\r\nInsurance & Extras\r\n- Full comprehensive insurance (including collision damage waiver)\r\n- Glass & tire coverage\r\n- Second driver included\r\n- Both drivers require the official Sri Lankan driving permit – we kindly ask you to assist with obtaining the permits from the Automobile Association of Ceylon (AAC) in advance of our arrival.\r\nDocuments we can provide:\r\nWe are ready to send scans of:\r\n- National driving licenses\r\n- International driving permits (if required)\r\n- Passports\r\n- Passport-sized photos (digital format)\r\nPlease let us know:\r\n- The total cost including all insurance, fees, and services\r\n- The process and documents you need from us\r\n- Whether a deposit or advance payment is required\r\nThank you in advance for your assistance – we look forward to your reply and hope to confirm the booking with you.\r\n\r\nBest regards,\r\nDaniel Fahr\r\nWhatsApp +491632435670\r\nfahr.daniel@gmail.com\r\n', '2025-05-25 12:47:50'),
(16, 'Thiru', 'prathapan9@hotmail.com', 'car Rental', 'Hi\r\nI would like to Rent car.\r\n18/06/2025 To 30/06/2025\r\nCan you please tell me available this dates.\r\n\r\nThanks', '2025-05-26 12:23:48'),
(17, 'Sandra ABINADER ', 'scarnereau@yahoo.fr', 'RENT and TEMPORARY PERMIT ', 'Hello,\r\n \r\nCan you clarify and tell me if when renting a car from your agency, you take care of the necessary arrangements with the office in Colombo to obtain the necessary temporary permit, in advance ? \r\n\r\nDo you give it to us at the same time as the car ?\r\n\r\nThanks \r\n\r\nBest regards ', '2025-05-27 21:29:24'),
(18, 'Gerhard Botha', 'gerrie0botha@gmail.com', 'Rental', 'I made a booking true Bookin.com.\r\nPlease send me requirements and email addres to send documents to apply for SL driving permit\r\n\r\nThanks', '2025-05-30 04:48:26'),
(19, 'Richard Grainger', 'richardgrainger1@hotmail.com', 'Enquiry ', 'ear Sir/Madam,\r\n\r\nI am looking for a quotation for renting a self-drive SUV from 29 June to 4 July. I would need to vehicle dropped off and collected from an address in Rajagirya (If this is available)\r\n\r\nCould you please provide quotes for cars and SUVs.\r\n\r\nKind regards,\r\n\r\nRichard Grainger', '2025-05-31 10:25:01'),
(20, 'Abdullah AlGhamdi', 'abdullah94362@gmail.com', 'Car rental', 'Greetings\r\nI want to rent a car for 20 days starting from July 12\r\nNew model 1500 cc car / Automatic transmission / with Bluetooth feature / fully comprehensive insurance\r\nI only have an international license\r\nI want you to get me a Sri Lankan license\r\n..\r\nHow much will the total cost be?', '2025-06-04 13:10:42'),
(21, 'Bernt Ola Bjørkedal', 'berntola@gmail.com', 'Renting a car from 22 of june to 11 of july 2025', 'Hi \r\nIm considering renting a car from you from 22 of june to 11 of july 2025,\r\nI have checked out the nissan Sunny in the standard cars category, eith as dayly rate of 45 euro,\r\nWe will arrive at the Colombo internationale airport (CMB) 22 of june at 1800 a clock (6 PM) -And we will drop the car at the same airport 11 of july at 0600 o clock (0600 AM) \r\nAND my question is, will you meet ut at the airport with driving license and the car ready? \r\nWill there bee any ekstra charges? \r\nWill there be any ekstra inshurance costs?\r\nI Need you also to help me with a sri lanka driver license to me and my wife. How mutch will that cost us?\r\n\r\nBest regards\r\nBernt Ola Bjorkedal\r\nfrom norway', '2025-06-09 22:19:50'),
(22, 'Alejandro Verde Cantero', 'averde4b@gmail.com', 'Rent a car', 'Hi, I would like to rent a car, but I dont have a credit card. Is there any posibility?\r\n\r\nThanks and regards', '2025-06-11 19:24:25'),
(23, 'Maggie Pucci ', 'maggiepucci.mp@gmail.com', 'Information ', 'Hi,\r\nI’m Maggie Pucci and I’m Italian citizen. I will come in Sri Lanka in August and I would like to take a Rental car. I know that I can drive with my italian drive licence, right?\r\nBut I read that I have to get a temporary permit of 1.000 rupees, right?\r\n\r\nHow can I do this?\r\n\r\nThank you,\r\nBest Regards,\r\nMaggie Pucci.', '2025-06-12 11:33:03'),
(24, 'Nooraini ', 'noorainiabdulaziz@gmail.com', 'Car Rental', 'Morn.\r\n\r\nLooking for car hire without driver with unlimited mileage.\r\n\r\nPickup:\r\n19/06 colombo \r\nDropoff: 22/06 nuwara eliya\r\n\r\nPickup:22/06 ella\r\nDropoff: 25/06 colombo', '2025-06-15 02:27:07'),
(25, 'Mica', 'jomicaborja@gmail.com', 'Inquiry about 6 months to 1 year car rent with driver', 'Good Day, I would like to inquire of your estimated monthly rental price (with driver)? For 1 month, 3 months, 6 months or 1 year contract rent.\r\n\r\nLocation: Around Colombo\r\nUse: Employee transportation\r\n\r\nHoping to hear from you soon. Thank you.', '2025-06-16 07:22:44'),
(26, 'Moosa ', 'greenside@oasiswater.co.za', 'Rent a Car', 'Good day\r\n\r\nPlease quote me for a car rental, 7th July to 21st July, Unlimited mileage, automatic,a small car  for 2 x people\r\n\r\n\r\nThank you \r\n', '2025-06-16 07:48:38'),
(27, 'Catherine', '105307811@qq.com', 'Can I rent a car with Chinese passport+HongKong Drive License+IDP?', 'Hi there, \r\nI want to know if I can rent a car from your company with my Chinese passport + Hongkong Drive License + IDP\r\nCan you please help? Thanks in advance\r\nCatherine', '2025-06-17 04:42:36'),
(28, 'Laura', 'lauragil.cot@gmail.com', 'Car rental', 'Dear SR Rent A Car team,\r\n\r\nI want to confirm that the following itinerary is possible as I cannot choose it at the website:\r\n\r\nPick up at Colombo Airport on July 27\r\n\r\nDrop off at Nuwara Eliya on August 1\r\n\r\nRe‑pick up at Ella on August 2\r\n\r\nFinal drop‑off at Colombo Airport on August 10\r\n\r\nPlease confirm if you could accommodate this “one‑way” plan, including the temporary Sri Lankan driving permit (we already have the international driving license).\r\n\r\nWe would like an standard car for 4 passengers (just 1 of us is driving).\r\n\r\nIf it’s possible, could you give us an approximated price for everything and tell me how to book it?\r\n\r\nThank you,\r\nLaura', '2025-06-17 09:17:49'),
(29, 'Nicolas', 'alemanyrmn@gmail.com', 'Car rental inquiry', 'Dear team,\r\nI’m trying to make a reservation but can’t get the hang of the website. I would like to check the prices and conditions for renting either an standard or an economy or a mini suv car for 10 days in January. Could you send me the details?\r\nI have the international drivers license as issued in Spain\r\nBest regards,', '2025-06-18 15:58:02'),
(30, 'Nils Meyer', 'nils.meyer.1@gmx.ch', ' Inquiry Regarding Payment with Debit Card and Sri Lankan Driving Permit', 'Hello dear SR Team\r\nI hope this message finds you well.\r\n\r\nI have an upcoming car rental with your company:\r\n	•	Name: Nils Meyer\r\n	•	Booking Reference Number: D010777001-QR9Y\r\n	•	Rental Date: 10 August 2025\r\n\r\nI would like to ask two questions in advance of my arrival:\r\n	1.	Payment with Debit Card\r\nI currently have a Visa debit card, which I have successfully used to rent cars before. Could you please confirm if I can use this card to make the payment and deposit with your company as well?\r\n	2.	Sri Lankan Driving Permit\r\nI understand that a local Sri Lankan driving permit is required to drive in Sri Lanka. I already have an international driving permit.\r\nWould it be possible for you to arrange the Sri Lankan permit for me? If so, could you kindly let me know:\r\n\r\n	•	What is the cost for this service?\r\n	•	What documents or information do you need from me?\r\n\r\nThank you very much for your support. I look forward to your response.\r\n\r\nBest regards,\r\nNils Meyer\r\n', '2025-06-23 12:51:52'),
(31, 'Namasivayam ITHAYAKUMAR', 'Ithayakumar@hotmail.com', 'Rental Rates', 'Hello,\r\nWhat currency is used here in this app for Self Driving rental cars?\r\nDo you have any special rates for like 4 weeks rentals?\r\nPlease advise\r\nThank you', '2025-06-26 00:44:32'),
(32, 'Muhammad Salman', 'smsiblings606@gmail.com', 'Srilanka License for tourist ', 'Can I get Srilanka temporary license with my UAE license as I have no time to apply for IDP', '2025-06-26 09:22:55'),
(33, 'Daniel Fraile Gonzalez', 'danifraile@hotmail.com', 'Car rental', 'I want to rent an economic vehicle, with full insurance, from 08/24/2025 to 09/06/2025. I would pick it up at Bandaranaike airport. I also need to get my Spanish driving license validation in Sri Lanka. Above all, I would appreciate if you could inform me about the rate with the most complete insurance that you have, indicating the coverage that it has. Thank you.', '2025-06-26 19:51:05'),
(34, 'Viktor Gelhorn', 'big-vik@gmx.de', 'Looking for a car for a roundtrip 22.07.2025 -04.08.2025', 'Hello Camellia -team,\r\nwe are going to visit Sri Lanka from 21. July 2025 arriving at 22 a clock till 4. August 2025 and need a litle car for this time.\r\nwe are 4 persons.\r\nDo you have one available in this time? \r\nHow much would it costs an what are the conditions?\r\nPlease make me an offer!\r\nWe are from Germany and i have an International Driving Permit and Visa but need a temporary driving license.\r\nCann you help me with? Or is it easy to visit AAC in the morning of 22.07.2025 and get the license?\r\nThank You!\r\nBest Gerards', '2025-06-26 20:20:41'),
(35, 'Schmitt ', 'morottichristelle@gmail.com', 'Location voiture ', 'Bonjour \r\nNous sommes français.\r\nNous voyageons au Sri Lanka du 18/08 au 03/09.\r\nPouvez vous nous faire une proposition de devis pour un Suzuki wagon r.\r\n2 passagers conducteur homme âgé de 53 ans avec permis international.\r\nDans l attente \r\nCordialement ', '2025-06-29 14:18:49'),
(36, 'Server Shaikh', 'Serverrockstar@gmail.com', 'Rent SUV', 'Hello, I would like to rent an suv preferably a Kia sorento or Hyundai Tucson (pls provide all options in the category). Can you provide me the rates for a  5 day rental and also latest pictures of the cars?', '2025-06-29 19:03:26'),
(37, 'Prateek Vadhera', 'pkvadhera@gmail.com', 'Car Rental', 'Hi,\r\n\r\nI am looking for a car on rent for 6 days.\r\nPick-up: 5th July, 2:00 p.m. Colombo International Airport \r\nDrop: 11th July, 1:00 p.m. Around One Galle Face Mall\r\n\r\nI am an Indian National so need a temporary driving permit as well for 1 driver. Please let me know the charges. Good Condition vehicle of standard size like Prius, Bezza, Rio is needed.\r\n\r\n', '2025-06-29 20:24:52'),
(38, 'Carlos Vicente Meseguer Godinez', 'carlosmeseguer26@gmail.com', 'Price', 'I would like to know if the price to rent a car has extras like insurance or other things.', '2025-07-01 10:42:14'),
(39, 'Shreyas Mahadeva', 'shreyasmahadev2@gmail.com', 'Renting a car (Self drive)', 'Hello Sir/Madam,\r\n\r\nI hope this message finds you well.\r\n\r\nI’m interested in renting a Swift car from 17th July to 26th July (10 days) to explore Sri Lanka. Based on our current itinerary, we expect to drive less than 1000 km during our trip.\r\n\r\nCould you please provide me with the following information:\r\n\r\nRental cost for the mentioned period\r\nDeposit requirements\r\nInsurance coverage options\r\nDriving permit requirements for Sri Lanka\r\nDo you also assist with obtaining the necessary driving permits?\r\n\r\nLooking forward to your response.\r\n\r\nWarm regards,\r\nShreyas M', '2025-07-01 11:08:10'),
(40, 'Barry Kimberlin', 'kimberlin006@aol.com', 'Sri lanka driving permit ', 'Hi looking to rent a car from you in September,  can  you arrange a sri lanken driving permit. \r\n\r\nMany thanks Barry ', '2025-07-03 17:59:21'),
(41, 'Manan Mehta', 'manan.leviathan@gmail.com', 'Cancel my booking ', 'Hi - Please cancel my booking - SR/RENT 07-16176', '2025-07-03 18:06:26'),
(42, 'Fabio Benedetti', 'fabio.benedetti.it@mgail.com', 'Infor for renting a car in August', 'I hope this message finds you well.\r\n\r\nI will be arriving in Sri Lanka on August 10, 2025 at 08:35 AM, and my departure flight is on August 24, 2025 at 02:55 AM.\r\nI’m interested in renting a car for this period to be fully autonomous during my stay.\r\n\r\nI would like to ask:\r\n\r\nHow does the process work regarding the driving permit and documentation?\r\n\r\nSince I arrive on a weekend, is it possible to handle all necessary procedures (endorsement or temporary driving license) on the weekend?\r\n\r\nDo you provide assistance with the driving permit application before my arrival?\r\n\r\nLooking forward to your reply and rental options.\r\n\r\nBest regards,\r\nFabio', '2025-07-04 12:21:24'),
(43, 'Olf', 'olfboes@hotmail.com', 'Arrange AA license and rent a self-drive car one-way', 'Hi,\r\nI would like to rent a self-drive care from the Airport to Kandy. Additionally, I would like to ask you if you can arrange the needed AA-licence for me. I can sent you a copy of my passport and international drivers license.\r\nThe date of pick-up will be 31 July and return at 1 August. During my 3 week holiday, I need more of these kind of bookings, but those can be discussed later. Can you support me with this request?\r\nBest Regards,\r\nOlf\r\n\r\n', '2025-07-07 11:55:39'),
(44, 'Jane Schütze', 'Janyjane@hotmail.com', 'International Drivers Licence', 'We are renting a car from saturday 12.07. Till 23.07.2025 from the airport Colombo... I have an international drivers Licence and a german one. Is this enough for driving in Sri Lanka or what do you need? Kind regards Jane\r\nThis is the booking nummer 686663469', '2025-07-09 06:37:09'),
(45, 'Heino Jannerup', 'heino_jannerup@hotmail.com', 'IDP, turist from Denmark', 'Hi, I will arrive during night (02:30 AM) August 15 at Colombo airport and stay for 6 days. I plan to rent a car and have it ready when I arrive. I need a car and IDP.\r\nCan you help? \r\n\r\nRegards \r\nHeino Jannerup', '2025-07-12 09:04:13'),
(46, 'Nuwantha', 'nuwantha@hotmail.co.uk', 'Pick up at Bandaranaike Airport', 'Hello,\r\nI am going to be in Sri Lanka this week. I wanted to rent a car the following week and pick it up from the airport. Can I do this? I will be driving from there to the city so would be easy for me. Thanks', '2025-07-13 15:12:47'),
(47, 'Gorka', 'gorkeles@gmail.com', 'Rent a car', 'Hello, we would like to rent a car from August 23 to September 3. We need a small car. How much would it cost? Thank you very much.', '2025-07-13 17:22:03'),
(48, 'Richard Cullen', 'richardcullen99@gmail.com', 'car rental', 'Hi we are from the UK\r\nwe would like a rental car for 22.7.25  at Paradise Holiday Village to return to Hilton Residence  Columbo on 4.8.25.\r\nWe would like a medium sized car with air conditioning and a sat nav if possible.\r\ndo you have any cars available please.\r\nwe have a blue light discount card but cant use on the website.\r\nthank you Richard', '2025-07-13 17:26:45'),
(49, 'Oren Julian', 'orengolian@gmail.com', 'Rent a car', 'Hi,\r\nWe are 3 adults irriving in Sri Lanka on friday 18/7 16:30 and would like to rent a car.\r\nI have an international license, can you take care of the required driving permit in the country until I arrive?\r\nAlso, can you bring the car to the airport or is there a shuttle to you?', '2025-07-15 08:14:23'),
(50, 'Oren Julian', 'orengolian@gmail.com', 'Rent a car', 'Hi,\r\nI just make an reservation.\r\nThe price of the car was 110 euro.\r\nFor nine days the price should be 990 euro before the extras.\r\nBut in the invoice it says 1100 euro - why?', '2025-07-15 08:43:52'),
(51, 'Tomasz Kurnatowski', 'tkurnatowski@outlook.com', 'car for 4 people', 'Hello\r\nI need a car like Perodua Bezza, for 4 people and bags, from 24 July to 9 August. Please send me your offer with insurance included\r\n\r\nShould I get Sri Lankan driving licence if I have international licence?\r\n\r\nThanks & Regards,\r\nTomasz', '2025-07-16 11:09:08'),
(52, 'Prem Pathmanathan', 'prempathmanathan682@gmail.com', 'Rent car', 'I booked the car July 25th  2025\r\nFlight number QR 662 landing in 2: 05 am \r\nBooking number D011031614 2 weeks ago I speak to someone in WhatsApp.  I sent my documents passport pictures and driving license. International driving license.\r\nTwo drivers .my cell 0014389856410\r\n\r\n', '2025-07-18 12:55:42'),
(53, 'Aditya Apte', 'aaditya.apte@gmail.com', 'Self Drive Car - Colombo', 'I need a self drive car for 6 days (7th Aug 2025 - 12th Aug 2025).\r\nPickup and Drop at Bandaranaike International Airport\r\nNeed small vehicle with automatic transmission in good condition.\r\nI have a internation driving permit and will need assistance to get \r\nDRIVERS ENDORSEMENT FROM AUTOMOBILE ASSOCIATION-SRI LANKA\r\nThanks', '2025-07-18 16:12:55'),
(54, 'Guido Walter', 'guidowalter44@hotmal.com', 'Recognition Permit', 'Dear Sir an Madam,\r\n\r\nwe have a reservation with you from 26. july 2025 (International Airpot Bandaranayake Colombo) until 18. august 2025 und wouldt like to know, if it is absolutely necessary to have a recognition permit. What I do have is a valid national driving licence and also an international driving licence - is this already sufficient?\r\n\r\nFurther we are not sure, if you have our flight number, so that you can catch us at the airport.\r\n\r\nThanks in advance for answering.\r\n\r\nGuido Walter\r\n', '2025-07-19 18:41:27'),
(55, 'EDWARD COX', 'eccox@hotmail.co.uk', 'HOTEL TO AIRPORT TRANSFER TOMORROW', 'Hi, \r\nI booked a transfer from Ekho Surf Hotel, Bentota to CMB tomorrow evening.\r\nThis is for 2 pax to depart CMB on EK655 Dep 2205.\r\nI guess pick-up will be around 1700 tomorrow.\r\nPlease confirm.\r\nMany thanks.\r\nEDWARD', '2025-07-20 06:05:17'),
(56, 'Toby Shillito', 'tobyshillitouk@gmail.com', 'Car Rental Request 25 July - 31 August', 'Hello,\r\nCan you please give us a Best Price quotation for a car rental for these dates (39 days)? We are a family of four, so may need a large car or small SUV. \r\nAre you in the airport or do you meet us with a shuttle bus?\r\nToby', '2025-07-21 04:56:34'),
(57, 'Jeet Golchha', 'jeet@fashionformal.com', 'Need SUV with driver for 5 days ', 'Arrive to Colombo on 25th July.\r\nDrive to Galle \r\n26 - 27 in Galle \r\n28 Galle to Colombo \r\n29 drop to Colombo airport . \r\n4 adults + 4 suitcases ', '2025-07-22 13:10:06'),
(58, 'Daniel Fraile Gonzalez', 'danifraile@hotmail.com', 'Sri Lankan Temporary Driving Permit', 'Hello. I have booked a car with you trough Edreams web. I want to obtain obtain a Sri Lankan Temporary Driving Permit. I know that you can arrange this for me before my arrival for a fee. What shoud I do to do this process? Thanks.', '2025-07-23 22:07:31'),
(59, 'Neil Kuruppu', 'kuruppu.neil@gmail.com', 'Visiting Sri Lanka between 14th SEP to 27th SEP', 'We are visiting family in Sri Lanka between 14-27 September. We want to hire a 6 or 7-seater van and driver (full time) during this period mainly for local Colombo travel but also for a trip to Unwatuna in Galle and back. We also want to be collected from and dropped off at Bandanayake International Airport.\r\n\r\n•	Arrival 14 SEP (22: 25hrs)\r\n•	Depart 27 SEP (00: 25hrs)\r\n\r\nWe have two small children. We need \r\n\r\n•	1x booster seat (for a 7-year-old)\r\n•	1x baby seat      (for a 4-year-old) \r\n\r\nWe need the seats properly fitted into the van by the seat belt straps. Could you let me know if you have these child seats and can have them properly fitted into the van before we are picked up from the airport?\r\n\r\nCould you provide an all-inclusive quotation?\r\n\r\nMany Thanks\r\nNeil Kuruppu\r\n', '2025-07-28 03:56:40'),
(60, 'Tsachi Oved', 'tsachi678@gmail.com', 'Car rental request', 'Hi \r\nI would like to book a car with you . \r\nI am looking for a nice car to travel in Sri lanka , from 2 Aug , to 28 Aug. \r\nSometthing with some place for suitcases , not too small . \r\nWith a baby seat included. \r\nPlease send me a quatation for some cars in this dates. \r\nAlso , I wanted to know , If I need to do any special driving license? \r\nI have Israeli international driving license.\r\n', '2025-07-28 19:54:21'),
(61, 'Stefano Paterna', 'Stefano.Paterna@gmail.com', 'Optional Insurance Upgrade', 'Hi\r\nI am interested in renting a car for 7 days. \r\nSomething like the Toyota Belta for 34 Euros per day. How much is the optional Insurance Upgrade? Do you have upgrade for fully covered insurance?\r\n\r\nRegards,\r\nStefano Paterna', '2025-07-29 17:21:28'),
(62, 'francis ben', 'francemapping44@gmail.com', 'https://maper.info/GoogleAddress', 'https://maper.info/GoogleAddress', '2025-07-29 22:40:18'),
(63, 'Edward SONG ', 'peidong.song2000@gmail.com', 'Car rental Colombo airport', 'Hi there, \r\nI am looking to rent a car for 7 days from the 9th of August. \r\n\r\nI have a German drivers license and aware that this needs to be converted. Do you take care of this as well? \r\n\r\nThanks and pls let me know soon. ', '2025-07-30 01:18:19'),
(64, 'Trung Bui', 'dtrungb@gmail.com', 'inquiries', 'Hi there, \r\n\r\nWe are a group of 4 people planning to travel in Sri Lanka from 4-7/9. We would like to rent an SUV (Hyundai Tucson or similar sized vehicle) with driver to carry out the following planned itinerary:\r\n\r\n- Early morning on 4/9 pick up at Negombo - Dambulla Cave Temple - Ancient City of Polonnaruwa - Sigiriya - Explore around Sigiriya - Stay at Sigiriya\r\n\r\n- 5/9 Sigiriya - Anuradhapura - Wilpattu national park - back to Anuradhapura and stay at Anuradhapura.\r\n\r\n- 6/9 Anuradhapura - Kandy - exploring Kandy - stay in Kandy\r\n\r\n- 7/9 Kandy - Colombo - drop off at Colombo airport at around 22:00\r\n\r\nPlease send your quotation for above itinerary and let me know if your have further question,\r\n\r\nThanks,\r\n\r\nTrung Bui', '2025-07-30 02:49:42'),
(65, 'Kevin Lahr', 'marinalahr94@gmail.com', 'Car Accident', 'We had an accident with our car. What should we do? Do you have a number we can reach you at? Best regards, Kevin Lahr\r\n\r\n', '2025-07-31 10:36:18'),
(66, 'Alicia ', 'alicia.villelo@gmail.com', 'Car rental request (Aug 14–24) + driving permit assistance', 'Dear SR Rent a car,\r\n\r\nWe are a couple from Spain (41 and 32 years old) planning to visit Sri Lanka in August, and we would like to rent a car with the following details:\r\n\r\nPick-up date: August 14, 2025 around 12 AM\r\nPick-up location: Our hotel near Bandaranaike International Airport (Airoport Colombo Pocket paradise)\r\nDrop-off date: August 24, 2025 around 8:30 AM\r\nDrop-off location: Colombo Airport (CMB)\r\n\r\nWe do not have an International Driving Permit, only our valid Spanish driving licenses. Could you help us arrange the necessary local driving permit?\r\n\r\nWe are also looking for Full insurance coverage (zero excess) and Fuel policy Full to Full\r\n\r\nCould you please confirm:\r\nAvailability\r\nTotal price (including insurance and permit assistance)\r\nVehicle options\r\n\r\nThank you very much in advance. We look forward to your reply.\r\n\r\nBest regards,\r\nAlicia Villegas', '2025-07-31 16:37:13'),
(67, 'Konstantin', 'k.kvayt@mail.ru', 'Car rental from 21.09.25 till  04.10.25', 'Hi ,\r\nI would like to rent a car   in Colombo international airport  from 21.09.25 till  04.10.25. Could you please share the rates for Executive cars and Mini SuV , \r\nplus  Sri Lanka Drive Permit', '2025-07-31 20:02:27'),
(68, 'Thusin King', 'thusinking6@gmail.com', 'Car rent', 'Rent a car unlimited kilometre 1 month price how much Toyota chr Honda vessel \r\n', '2025-08-04 04:37:16'),
(69, 'INDRAN GIRI', 'INDRANGIRI@GMAIL.COM', 'Need to make car rental reservation', 'Hi ,\r\n\r\nI am not able to submit the form online for car rental reservation. Need Toyota Corolla for self drive from 29th Aug till 4th Sept. Pls send me the link for the reservation \r\n\r\nRegards\r\nIndran Giri', '2025-08-04 08:10:22'),
(70, 'ANNA', 'anna.narozna.pl@gmail.com', 'SRI LANKA DRIVING LICENCE', 'Good morning.\r\nWe are planing our trip to Sri Lanka for our wedding aniversary and I was checking the opinions of the rental cars companies and we would like to do it with you. Is it posibble you take care of the Sri Lanka driving licence for us so we can rent a car with no problem on the 22nd of August?\r\nThank you for your help.\r\nKind regards', '2025-08-06 09:35:28'),
(71, 'simone maher', 'simone.maher@yahoo.com', 'Rental - self Drive  Large SUV', 'Can you please provide a quote to rent a non V8 large SUV for 5 people from 2/4/26 to 30/4/26. Pickup Negombo airport/Drop Negombo Airport.\r\nWe will have an IDP ( to be endorsed in Sri Lanka)\r\nCan you please include this and all costs in quote please.\r\nPlease also state insurance cover.\r\nPlease quote in SR dollars\r\nThanks', '2025-08-07 01:15:10'),
(72, 'Jins Thodukayil', 'thodukayil@hotmail.com', 'Rental from 13.8 -27.8', 'Hello together \r\n\r\nI would like to rent a car from your company. Which small car are available?', '2025-08-07 20:02:02'),
(73, 'Manon Screve', 'manon.sc@hotmail.fr', 'Rent a car', 'Hello i want to rent from 02/17/26 to 03/09/26 to the international airport for 5 persons (me,m’y husband And our 3 children 3,6 And 8 years old) i want the moré economical car And self driver car. CAN you send me a quotation?', '2025-08-09 05:45:37'),
(74, 'johnny chan', 'johnny23@live.com.sg', 'car rental with request for additional transfer', 'Hi, \r\n\r\nWe are visiting sri lanka and we are driving from colombo to kandy by driving. after that, we are going to take a train from kandy to ella which is highly recommended. Could we hire a driver from you to help us drive the car from kandy and meet us in ella? Thank you. ', '2025-08-09 10:51:30'),
(75, 'Alexander', 'a.ehrhardt@yahoo.de', 'Self driving car rental', 'Hello,\r\nI am looking for a car rental, self driving, five persons from 17th August to 31 August. I would be pleased if you can make me in over. Favourable  Pickup location and return would be Bandaraneike  Airport.\r\nRegards \r\nAlexander', '2025-08-09 15:45:26'),
(76, 'Kiran', 'kiranmulakaluris@gmail.com', 'Need 2 self drive cars', 'Hi,\r\n\r\nI am from India arriving at Colombo on 15th Aug and looking for 2 self drive sedans for 5 days.\r\n\r\nTrying to reach you, could u call me on +91 9959900302 and available on WhatsApp app on the same number.\r\n\r\nThank you!', '2025-08-10 08:40:45'),
(77, 'Kiran', 'kiranmulakaluris@gmail.com', 'Need 2 self drive cars', 'Hi,\r\n\r\nI am from India arriving at Colombo on 15th Aug and looking for 2 self drive sedans for 5 days.\r\n\r\nTrying to reach you, could u call me on +91 9959900302 and available on WhatsApp app on the same number.\r\n\r\nThank you!', '2025-08-10 08:40:45'),
(78, 'Ferrera', 'ferrera.cecile@icloud.com', 'Question ', 'Good evening,\r\n\r\nWe are planning to travel to Sri Lanka in February. We would like to rent a car for 15 days. We will be applying for the international driving permit ourselves. Could you take care of the local approval (endorsement) issued by the Automobile Association (AA) of Colombo?\r\n\r\nCould you please let me know the cost of this procedure, as well as the price for the 15-day rental? We are 2 adults with 2 suitcases.\r\n\r\nHave a nice evening.\r\n', '2025-08-11 18:54:51'),
(79, 'barath', 'barathramesh001@gmail.com', 'car rental', 'Hi i need car rental on 15/08/2025 at 4.00 am at colombo airport', '2025-08-12 11:23:10'),
(80, 'MARIA VALERY ', 'valalvir@gmail.com', 'MARIA', 'HELLO\r\nI need information to reserve a small, economical, automatic car.\r\nPick-up on March 27th at 10:00 a.m. and return on April 9th at 6:00 p.m.\r\nI would like to know the price, cancellation policy, fuel policy, and read the terms and conditions.\r\nAnd comprehensive insurance.\r\nThank you.', '2025-08-12 15:09:29'),
(81, 'Sanjaya Peiris', 'sanjaya002@yahoo.com', 'Self driving Rent a Van - Nissan Caravan', 'Hi\r\nI am planning a vacation in Sri Lanka in Mid January 2026 , we are 6 in the family, looking at your website for a rental and noticed Nissan Caravan might suite our purpose. Could you please advise the best deal for 20 days picking up from the airport on 15/01/26 and return on 04/2/26. Appreciate if you could advise, my phone +61424360167.\r\nthanks', '2025-08-13 00:49:23'),
(82, 'Polly', 'polly30108252@gmail.com', 'Enquiry from a booking ', 'Hi SR RENT A CAR, \r\n\r\n\r\nI’ve booked a car from you guys for the period of 2nd Sept to 10th Sept through booking.com under name Yeung Bo Ting. Just wanna confirm the pick up information, as I request to have the car picked at cinnamon grand hotel but the pick up address is somewhere else. Just wanna make sure we will be able to get our car from Cinnamon Grand Hotel instead. \r\n\r\nMany Thanks, \r\nP ', '2025-08-13 07:52:26'),
(83, 'Dinis Martins', 'dinissaragoca@gmail.com', 'Car Rental', 'Hello,\r\n\r\nWe are planning a trip in Sri Lanka and would like to know if it is possible to rent a sel driving car from your company with the following arrangement:\r\n	•	We would pick up the car at the start of our trip in Negombo, or near Colombo.\r\n	•	After driving to Kandy, we would like someone from your company to take the car to Ella, as we would like to travel between Kandy and Ella by train.\r\n	•	After our time in Ella, we would like to use the car again and then return it near Yala National Park or Mirissa, as we plan to do the rest of our journey by tuk-tuk.\r\n\r\nCould you please let us know if this would be possible, and if so, what the additional costs or arrangements would be?\r\n\r\nThank you in advance for your help.\r\nBest regards,\r\nDinis', '2025-08-13 20:41:52'),
(84, 'Eros Echise', 'echise.eros@gmail.com', 'Local Driving Permit ', 'Buongiorno, ho una prenotazione di un auto a nome Eros Echise il 19 agosto a Colombo per la durata fino al 5 settembre, dispongo già di patente internazionale e volevo chiedere poteste occuparvi voi di farmi ottenere il permesso di guida locale in modo di averlo pronto già al mio arrivo al momento del ritiro della macchina. Fatemi sapere che documenti vi occorrono, grazie', '2025-08-14 09:10:20'),
(85, 'Matteo Scalerandi', 'scalematte@hotmail.it', 'Temporary driving permit', 'Hello,\r\n\r\nI have a reservation to rent a car starting from 23 August 2025 (Voucher: 770906549). I would like to receive the temporary driving permit when I come to get the car. Can you apply and get it for me? \r\n\r\nThank you,\r\nMatteo Scalerandi', '2025-08-18 12:58:03'),
(86, 'Giovanni', 'gianpaolodelgrosso@gmail.com', 'Driving License Endorsement (TDP)', 'Hi.\r\nMy name is Giovanni and I will arrive in Sri Lanka on 14 September 2025 and will be in Galle. I would like to rent a car/tuktuk\r\n\r\nI have an Italian driving license and I have not the International Driving Permit (IDP). I understand that I also need the local AA Ceylon endorsement / temporary driving license to drive legally (TDP)\r\n\r\nCould you please:\r\n\r\nConfirm if you can arrange this endorsement in advance for me?\r\n\r\nTell me the total cost (rental + endorsement)?\r\n\r\nProvide the documents you need (passport scan, Italian license scan, etc.) and the timeline?\r\n\r\nDo I have to pick up the TDP from your office? Or is there an equally valid digital format?\r\n\r\nThank you very much for your support.\r\n\r\nBest regards\r\n', '2025-08-19 21:19:53'),
(87, 'Caroline Reijs', 'reijs.caroline@gmail.com', 'Rent a Car + Apply for Sri Lankan Drivers License', 'Hi! \r\nMy boyfriend and I are traveling to Sri Lanka soon and would like to rent a Toyota Aqua for our trip. \r\n\r\nI have two questions regarding the following: \r\n1. Can you help apply for a temporary Sri Lankan Drivers License before we arrive? If so, how does this process work and how long does it take. (My boyfriend will be driving and he has a international license). \r\n2. We want to pick up the car from Colombo Airport on August 30th, and return the car from Weligama on September 9. Is this possible? \r\n\r\nThank you very much! \r\nCaroline', '2025-08-21 07:08:52'),
(88, 'Caroline Reijs', 'reijs.caroline@gmail.com', 'Rent a Car + Apply for Sri Lankan Drivers License', 'Hi, \r\nMy boyfriend and I will visit Sri Lanka soon and are looking to rent a Toyota Aqua. I have two questions that I hope you can help me answer: \r\n1. Can you help with applying for a Sri Lankan Drivers License? (My boyfriend will be driving and he has an international drivers license and can send documents beforehand). If so, can you let me know how this process works and how long it would take? \r\n2. We would like to pick up the car from Colombo Airport on August 30, and return the car in Weligama on September 9. Is this possible? \r\n\r\nThank you! \r\nCaroline', '2025-08-21 07:11:54'),
(89, 'Vikum De Silva', 'vikumdesilva45@gmail.com', 'Rent a Car Query', 'Hey,\r\nI was just wondering how much it was to book a Mitsubishi Montero for 7 days, with 150 kilometres a day limit. Thank you ', '2025-08-25 00:53:33'),
(90, 'Jessie Chang', 'jessiechang0214@gmail.com', 'Does SCDW availible', 'Hi, I would like to know does company offer SCDW (0 excess) insurance? How much per day?', '2025-08-25 13:53:05'),
(91, 'Alex', 'alexanderweyers@gmx.net', 'Car rental', 'Hello,\r\nwe think about to book a rental car from 30 August to 14 September (14 days).\r\nWe are 2 adults and 2 children and will have 3 suitcases with us.\r\n\r\nCould you please let us know the different insurance options you offer and the costs for each?\r\nWe will also need the issuance of a Sri Lankan driving license for our stay. From Germany \r\n\r\nThank you in advance!', '2025-08-26 07:10:49'),
(92, 'Jey', 'jeyaruban74@hotmail.com', 'Renting with UK driving license.', 'Hi there, hope you are well. We are planning to hire a car for our stay from the 12th of September to the 19th of September, and wanted to know what the procedure would be for a UK citizen with a UK driving license? Any information would be appreciated. Thank you.', '2025-08-27 20:07:44'),
(93, 'Carlos', 'carlosmsegarravols@gmail.com', 'Rental car Ella to Colombo', 'Hello,\r\nIs it possible to rent a car to pickup from Ella the 3rd of September and to drop off at Colombo Airport the 7th of september?? What is the cheapest car you have.\r\n\r\nThanks', '2025-08-28 14:14:55'),
(94, 'Chinsik Kim', 'chinsikkim@gmail.com', 'B12337776', 'Hello, this is Chinsik and I have reserved a rental car. Here is the Booking number B12337776. I have two questions. 1. Am I going to see your booth when I arrive at the CMB airport?  2. Can you help me get the AAC permit? I found that Rento will help me online, but I would like to use your service instead. How much will it cost you to process for me? ', '2025-08-31 01:38:27'),
(95, 'Markus Beck', 'markus.beck-mail@arcor.de', 'car with a manual transmission from December 2nd to December 30th, 2025.', 'Dear Sir or Madam,\r\nI would like to inquire whether you are renting a car with a manual transmission (very important) from the Economy, Standard, and Semi-Executive categories from December 2nd to December 30th, 2025.\r\n\r\nBest regards,\r\n\r\nMarkus Beck\r\nWislenstrasse 1\r\nCH-9467 Frümsen\r\nSwitzerland', '2025-08-31 10:01:50'),
(96, 'janaka rathnayake', 'jana2mail@gmail.com', 'rent a car', 'hi,\r\ni was looking for car from airport. i already checked in website. whats is the best car i have 2large bag and 2small bags', '2025-08-31 15:29:09'),
(97, 'Piyal Fernando ', 'piyalfernando@yahoo.com', 'Ren a car', 'Hi \r\nLooking for spacious  japanese car for 13 days rental ,pls send me rental details  \r\nCheers\r\n', '2025-09-05 06:25:56'),
(98, 'Maarten Letsch', 'maartenletsch@hotmail.com', 'Local (Sri Lankan) driving licence.', 'Dear Sir/Madam,\r\n\r\nLast week I made a reservation for car rental through your company (via EconomyBookings.com) from the 20th of September until 11th October. Of course I will bring my own (Dutch) driving licence including an international driving licence, but is it also essential to have/buy a Sri Lankan driving licence? Is there a possibility to buy it directly in your office when we pick up the car?\r\n\r\nThank you in advance,\r\n\r\nKind regards,\r\n\r\nMaarten Letsch\r\nBooking number: B31176846', '2025-09-06 05:29:45'),
(99, 'James Boughton', 'jimboacm@yahoo.com', 'Car Hire', 'Hi \r\n\r\nI am looking for car hire (Suzuki Swift ideal) from 20th December to 3rd Jan, can you let me know price. Pick up from Colombo Bandaranakie Aiport at 13.00', '2025-09-07 16:40:45'),
(100, 'Francisco ', 'needsandlinks@gmail.com', 'Rent a car', 'Hello\r\nI Will pick Up and Drop off at Colombo internacional airport.\r\nKind regards', '2025-09-13 19:28:10'),
(101, 'TAN FANG WEI', 'fangwei.tan@lge.com', 'CAR RENTAL', 'Hi we are looking dor 1 unit 2000CC car for 36 month contract for my director in sri lanka. can you let me know what rae the available card you have ', '2025-09-15 07:27:30'),
(102, 'saurabh p ', 'spatesaria@gmail.com', 'self drive car rental ', 'looking for a self drive car from 30th septmebr to 5th October from bandaraniyeke airport ', '2025-09-16 06:26:54'),
(103, 'Mariam Kokaia', 'mariam.kokaia@flatrocktech.com', 'Car rental', 'I am arranging transport for our CEO, who will be in Colombo from 13 to 17 October on a business trip. We are looking for a suitable executive car with a driver during these dates.\r\n\r\nCould you please let me know:\r\n\r\nWhat vehicle options do you have available for these dates?\r\n\r\nAre the cars chauffeur-driven, and do your drivers speak English?\r\n\r\nWhat are your daily rates, and what is included in the price?\r\n\r\nHow do you usually handle fuel, tolls, and waiting time?\r\n\r\nDo you provide airport/hotel pick-up and drop-off?\r\n\r\nWhat are your booking and payment terms?\r\n\r\nOnce I receive your response, I will share the details with my CEO so we can confirm the booking.', '2025-09-17 09:11:22'),
(104, 'Nihal', 'hello@limitless.institute', 'Need help with the reservation', 'Hi,\r\n\r\nI would be landing in SriLanka on the 24th, early morning, 2.30 am. Will your office be open if I book a reservation?\r\n\r\nIf yes, what would be the procedure to get the car?\r\n\r\nIf no, what time does your office open?', '2025-09-18 06:36:53'),
(105, 'Muksin Nimung ', 'vecran.muksin@gmail.com', 'Rent Car', 'Hi,\r\n\r\nI want to rent the car. Is it available on 2 Oct until 6 Oct.\r\n\r\nCan you give good price and without deposit.\r\n\r\nThank you.\r\n\r\nMuksin', '2025-09-18 15:26:32'),
(106, 'Thomas Frank', 'tfr.01@t-online.de', 'Inquiry', 'Dear Sir or Madam,\r\nI am interested in renting a Perodua Bezza Sedan (automatic, self-drive) during my upcoming trip to Sri Lanka in January/February 2026. I would appreciate more information on the following points:\r\n\r\nRental Period\r\n-  Pick-up: 18 January 2026, from 09:00 AM at Bandaranaike International Airport (CMB).\r\n-  Return: 09 February 2026, in the evening at the airport (if possible?)\r\n\r\nInsurance Coverage\r\n- Comprehensive insurance.\r\n- Excess/deductible.\r\n- Coverage for damages to windows, tires, underbody, and roof.\r\n- Theft protection.\r\n- Third-party liability insurance.\r\n- Roadside assistance in case of breakdowns.\r\n\r\nVehicle Features\r\n- Confirmation that the car is equipped with air conditioning.\r\n\r\nDriving Permit\r\n- Assistance with applying for the “Recognition Permit” through the Automobile Association of Ceylon (AAC).\r\n-  Which documents/information do you require from me for this process? (I already hold a valid international driving permit.)\r\n- How long in advance should the Recognition Permit be applied for?\r\n\r\nLogistics\r\n- Is it possible to arrange a delivery of the car directly from the Airport?\r\n- I would be grateful if you could also send me a detailed quotation including all costs, fees, and possible surcharges (e.g., for excess mileage).\r\n\r\nThank you very much in advance for your assistance. I look forward to your reply.\r\n\r\nBest regards,\r\nThomas Frank', '2025-09-22 05:40:49'),
(107, 'CONSTANTIN SERBAN', 'cfserban@yahoo.com', 'Car rental price inquiry ', 'Hello, I would like to know how much would be to rent a mini suv (4x4) from 25.12.2025 until 10.01.2026 with pickup from Bandaranaike International Airport and return to the same location. Thank you', '2025-09-23 14:07:15'),
(108, 'cecilia morosi', 'ceciliamorosi@gmail.com', 'rent a car', 'Hi I need to rent a car from the morning of Saturday 04.10 at 6.30 am to Sunday 05.10 4 pm.\r\nWe are a couple need to go to Galle and back.\r\nI’ve already a valid driving permit.\r\n\r\nCan you please advise on the best offer for a medium range car?', '2025-09-23 19:46:40'),
(109, 'Priya Bera', 'priyabera.bera@gmail.com', 'SElf drive rental  Car', 'Needed self drive from 28th Dec - 2nd Jan in premium segment car\r\nPickup and Drop pff - Colombo Airport', '2025-09-27 08:26:12'),
(110, 'Christopher Hashim', 'ahashim1957@gmail.com', 'Rent a van with a driver for a week', 'I would be very much appreciated if you could send me a breakdown of prices for the above request. And also need know Wht are the availability \r\nThank you\r\n', '2025-09-29 01:00:12'),
(111, 'Rafi Shamsuddin', 'rafi325@gmail.com', 'Rent Car--Srilanka', 'Hello,\r\n\r\nI hope you are doing well. My name is Rafi Shamsuddin. I am planning a 10-day family trip in Sri Lanka and would like to hire one compact SUV with a professional English-speaking driver for the entire journey. The same vehicle and driver should stay with us from 08 Oct 2025 (arrival at CMB Airport) until 17 Oct 2025 (departure from CMB Airport).\r\n\r\nImportant Notes:\r\n\r\nThe SUV must be able to comfortably accommodate 2 large suitcases.\r\n\r\nAt Nuwara Eliya → Ella (11 Oct), we will travel by train. The driver will take our luggage by car and meet us at Ella station.\r\n\r\nThe car should be modern, air-conditioned, and well-maintained. Please suggest available SUV models (compact SUV category).\r\n\r\nOur Travel Plan & Routes\r\n08 Oct: CMB Airport pickup 05:30 AM→ Negombo (short rest) → Kandy (overnight)\r\n09 Oct: Kandy → Nuwara Eliya (Gregory Lake, Ramboda Falls, Tea Factory, etc.)\r\n10 Oct: Nuwara Eliya city tour (Race Course, Victoria Lake, Little England)\r\n11 Oct: Nuwara Eliya → drop at Nanu Oya train station → train to Ella → driver goes with luggage to Ella → meet us there (overnight Ella)\r\n12 Oct: Ella sightseeing (Ravana Falls, Ravana Pool Club, Halpé Tea Factory)\r\n13 Oct: Ella → Mirissa (via Dondra Lighthouse)\r\n14 Oct: Mirissa beaches (Secret Beach, Coconut Hill, Parrot Rock) → afternoon visit Galle Fort → back to Mirissa\r\n15 Oct: Mirissa → Weligama & Ahangama cafés/beach clubs → proceed to Galle for overnight stay\r\n16 Oct: Galle → Balapitiya (Madu River Safari) → Colombo (Granbell Hotel)\r\n17 Oct: Colombo city tour (Lotus Tower, Galle Face Green, Pettah Market, Red Mosque, Mount Lavinia, Colombo Fort, Gem Market) → evening drop at CMB Airport (21:30 flight)\r\n\r\nRequest:\r\nPlease send me:\r\n- Available compact SUV models with English-speaking driver All-inclusive quote (vehicle + driver + fuel + insurance + unlimited mileage) \r\n- Photos of the proposed SUV(s) \r\n- Payment method & terms \r\n\r\nThank you very much. Looking forward to your response.\r\n\r\nRafi Shamsuddin \r\nWhatsapp: +8801711596153\r\nEmail: rafi325@gmail.com', '2025-09-30 06:34:41');
INSERT INTO `contact_form` (`id`, `name`, `email`, `subject`, `message`, `submitted_at`) VALUES
(112, 'Hasintha Kuruppu', 'hasintha74@yahoo.com', 'Rent a Car', 'I would like to rent a car for 06 pers from 14 NOV 25. Duration 08 days. Please let me know available vehicle with price, milage and other details.', '2025-10-04 02:32:17'),
(113, 'Maail Hashim', 'maailhashim@gmail.com', 'Renting a self drive car', 'I am planning on going to Sri lanka on the 31st of December 2025 and leave on the 6th of January 2026. I want to get a rent a car from the airport and drop it off at the airport. Could you please give me some options of cars that I could rent for this period with their costs. Find some details of the trip:\r\n\r\n1. Will go on a trip to Nuwera Eliya, Kandy and Colombo.\r\n2. Will be travelling with a 3 year old and 1 adult.\r\n3. I have Maldives full drivers licence and international Drivers Permit and will obtain temp licence from the airport.\r\n4. Will have 2 large suitcases.\r\n5. No budget has been set yet, so provide me a range of cars for me to look at from cheap to expensive.\r\n\r\nBest regards,\r\nMaail\r\n+9607720990', '2025-10-04 09:59:26'),
(114, 'Dilhara Naveen', 'dilharanaveen0911@gmail.com', 'Inquiry About Renting My Toyota Vitz to SR Rent A Car', 'Dear SR Rent A Car Team,\r\n\r\nI hope this message finds you well. I own a Toyota Vitz in good condition, and I am interested in offering it for your rental fleet if you accept privately owned vehicles.\r\n\r\nCould you please let me know if SR Rent A Car allows individuals to register their vehicles for rent through your company? If so, I would appreciate it if you could share the process and any requirements or documents needed.\r\n\r\nThank you for your time and assistance. I look forward to your response.', '2025-10-05 13:21:47'),
(115, 'Lorena', 'lorenagarcesalarcon@gmail.com', 'Long-term car rental enquiry', 'Hello! Do you have any automatic and small cars available for long-term rental pleasE? From this tuesday to the end of April. If so, what cars, conditions and prices per month? Thanks!', '2025-10-05 16:27:09'),
(116, 'Waihowe', 'waihowe@gmail.com', 'Car Rental', 'Hi There,\r\n\r\nI am looking to rent a car from the 28-Dec-25 to 03-Jan-26. I am looking for the following:\r\n\r\nCar: Toyota Prius or Bezza (or similar)\r\nDriver: Please quote for both\r\nRequire Sri Lankan international permit\r\n\r\nPlease help to quote the price to me.\r\n\r\nThank you!\r\n\r\nKind Regards,\r\nWaihowe', '2025-10-07 10:23:47'),
(117, 'Uttam Dave', 'uttamdave1958@gmail.com', 'Cheauffer-Driver Car Rental 8-Hour Package October 13-17 ', 'Need 5 days rentals 9am to 10pm\r\n\r\nPlease send me your best prices for a sedan like Toyota Altis', '2025-10-08 11:07:03'),
(118, 'Nikita', 'nikita.sharma@clubconcierge.in', 'Quote Request — Self-Drive JLR SUV (Colombo ↔ Bentota/Galle) | 7–11 Nov', 'Please share a quote for a self-drive JLR SUV with the following requirements:\r\nTrip details\r\n•	Pick-up: 7 Nov, 15:30 — Colombo Airport (CMB) (Flight arrives at 15:00 hours)\r\n•	Drop-off: 11 Nov, 13:00 — Colombo Airport (CMB) (Flight departs at 16:00 hours)\r\n•	Route: Colombo ⇄ Bentota (Galle District)\r\n•	Passengers: 4 adults\r\nMandatory requirements\r\n•	Vehicle: JLR SUV (Apple CarPlay required)\r\n•	Usage: Unlimited mileage on the Colombo–Bentota/Galle corridor\r\n•	Coverage: Written confirmation that inter-district travel (Colombo + Galle) is permitted under the rental agreement\r\n•	Airport delivery/collection included\r\nPlease include in the quote\r\n•	Total rental cost (base rate + taxes) for the above dates\r\n•	Insurance details: CDW/LDW, theft cover, third-party limits, excess amount & options to reduce it\r\n•	Security deposit/pre-authorisation and accepted payment cards\r\n•	Additional driver policy/fees (if applicable)\r\n•	Fuel policy, tolls, and any one-time fees (airport, delivery, admin, etc.)\r\n•	Required documents and age/license rules for foreign drivers\r\n•	Roadside assistance availability (24×7) and contact\r\n•	Exact model year/variant and confirmation of Apple CarPlay\r\nKindly share your best available rate and terms at the earliest. If a specific JLR variant is unavailable for these dates, please list the closest JLR alternatives in the same class with identical terms.\r\n\r\n', '2025-10-09 04:54:43'),
(119, 'James', 'sirjman@gmail.com', 'Car Rental', 'Hello,\r\n\r\nIs it possible to pickup in Kandy on 7 Nov and drop off in Colombo on 14 Nov? Smallest car possible please. \r\n\r\nCould you give me a quote for a Colombo pickup on 5 Nov and return on 14 Nov please? ', '2025-10-09 06:19:20'),
(120, 'Ashish Nigam', '1ashishnigam@gmail.com', 'Car rental enquiry 19th Oct to 26th Oct', 'Hi, i am interested in renting a car from 19th to 26th October. please provide rates for semi executive and executive car category.\r\nmy whatsapp number is +919620031080 please contact me', '2025-10-09 10:40:27'),
(121, 'Nihal Ranjith Jameen', 'jameen82@gmail.com', 'cancelled my booking ', 'invoice number SR/RENT 10-16555', '2025-10-10 11:41:00'),
(122, 'MADHAVAN PATHANGI NARASIMHAN', 'madhavanpn1971@gmail.com', 'Car rental for self drive 21st to 26th December 2025', 'Hi I am planning to be in Sri Lanka from 21st to 26th December 2025 for holiday. I would like to rent a car for self drive from Colombo airport start time approximately 12 noon on 21st Dec 2025 and return time approximately 12 noon on 26th Dec 2025. Can you help me to apply for my temporary Sri Lankan driving permit as I understand this is required for me to drive in SL. Pls let me know if you can help me to apply and get the temporary Sri Lankan driving permit for me.', '2025-10-12 03:14:14'),
(123, 'Roman Cadek', 'rcadek@yahoo.com', 'Car rental', 'Hallo, do you have any SUV available from Saturday 18.10.,arrival at 22.15 Air Asia FD140  until Friday 24.10. departure AirAsia AK44 at 10.40 a.m. ?\r\nPrefer Honda Vezel,Nissan X trail,Kia Sorento with automatic gear.\r\nThank you for your answer.Roman', '2025-10-13 04:25:21'),
(124, 'Remigijus Paškauskas', 'jurepa@gmail.com', 'rent-a-car', 'Hello. I filled out a car rental form a few days ago.  I want to cancel because my travel plans have changed (Invoice number SR/RENT 10-16556) Please inform. Thanks', '2025-10-13 08:47:42'),
(125, 'Robert Jones', 'robertleejones999@gmail.com', 'car hire', 'I am a regular visitor to SL and I want to rent a car . I am 81 years old and a UK resident . Can you advice if my age is a problem for renting with you', '2025-10-14 13:12:03'),
(126, 'Steven Watkins', 'sjwatkins13@gmail.com', 'car rental ', 'I am trying to book car rental but your web page doesn’t seem to be accepting reservations. I am trying to book something like a Suzuki Swift with full insurance. We are arriving on the flight UL504 at 12.30pm on the 28 of November and will be returning the car on Friday the 12th of December at 1700. We need full CDW / CDW and meeting at the airport if possible? My name is Steven Watkins, DOB 13/12/1966, I will need a Sri Lankan driving licence. ', '2025-10-14 15:19:47'),
(127, 'Priyanka', 'priyankamantena@gmail.com', 'enquiry for car rental', 'Hi. Could you please let me know what the cost of a small economy car for 6 or 7 days be? Im looking for a  car for 2 people, and a reasonable price. Please let me know the per day rental.The dates would be around 14th to 20th april tentatively. Please give me the car options along with prices and your best price :)', '2025-10-15 09:04:11'),
(128, 'Ambrish Arora ', 'ambrisharora@gmail.com', 'Self Drive Car rental', 'Hi I wanted to book a self drive standard crossover SUV / sedan.. from Bandarnaike airport on the Oct 18th 9.30 am drop off in Colombo ciry on 21st evening 6.30 pm. Could you let me know if its possible and the price pls?', '2025-10-15 18:26:49'),
(129, 'Anna', 'shashkova.aa@gmail.com', 'Self-drive car 9-22 november', 'Hello!\r\nMy name is Anna, we are looking for a car for the period from 9 to 22 November 2025.\r\nCould you please send what car do you have and your conditions', '2025-10-16 11:47:53'),
(130, 'Sofia ', 'sofia.burdeina@mytaxicrm.com', 'Partnership', ' Looking for a smarter, more profitable way to manage your fleet?\r\nMyTaxiCRM is now available in Sri Lanka,  let’s talk!', '2025-10-16 11:48:08'),
(131, 'Marcos Lezaun Guindulain', 'lezaunmarcos@gmail.com', 'Deposit not returned', 'Good afternoon,\r\n\r\nI rent a car with you from 8-19th september. I returned the car on perfect conditions but havent received the deposit yet. Can you tell me when is expected to be paid back?', '2025-10-18 06:35:36'),
(132, 'Gary Bridge', 'domebridge@btinternet.com', 'Vehicle Rates', 'Hi, looking to hire a mid size SUV from 30/1225 to 20/1/2026, pick up from Colombo airport at 13.30, return time 7.30am on 20/1/2026.\r\nWhat rates and insurance please.\r\nGary', '2025-10-19 12:33:55'),
(133, 'Armin Finkenstedt ', 'Armin.finkenstedt@gmail.com', 'Car Rental ', 'Hello,\r\nI will visit Sri Lanka from Nov 3rd, arrival at Bandaranaike Intl. airport at ~15:15 to Nov 15, departure from Bandaranaike at 21:30.\r\nI am looking for a rental car that fits 2 persons and a bag with small surfboards in the back, for example a Nissan X-Trail.\r\n\r\nCan you make me a quote?\r\nIs there an insurance option that covers the damage excess in case of damage?\r\nI have an Austrian (European Union) driving license - for driving in SL you need a local permit, would I get this over your company.\r\n\r\nBest regards,\r\n\r\nArmin Finkenstedt ', '2025-10-20 13:19:54'),
(134, 'lucy boston', 'lucyboston1@gmail.com', 'self drive car rental ', 'Hello \r\nWe would like to hire a self drive car from 11-22 January 2026. \r\nPreferably a small to medium  SUV with low mileage, automatic gearbox,  air conditioning and full insurance. Do you have those available and can you give me an approximate price to include airport pick up?\r\nAlso can you help us get the required permit/paperwork to drive in Sri Lanka. We come from the UK and have UK  driving licences.      Many thanks! Lucy Boston', '2025-10-21 16:07:39'),
(135, 'Viktoria Volanska', 'vvolanska@gmail.com', 'Car rental with the driver in Sri Lanka', 'Hello, \r\nI am looking for rent a car (stanard small) in Sri Lanka with the driver/chauffeur  driven and would like to ask you to share with me the offer and conditions for such a rental.  It will be two passangers who are renting. \r\nPick up location - Bandaranaayke International airport \r\nDrop off location - Panthegama \r\nPick up date - 17/12/2025 6am \r\nDrop off date 21/12/2025 around 4pm\r\nCan you please specify what is and what is not included in the rental price - car? fuel? any limitation with km driven?parking fees? highway fees? accomodation for driver? food for the driver? flexibility around route? \r\n\r\nLooking foward for receiving respective information from you \r\nKind regards, \r\nViktoria \r\n', '2025-10-26 19:14:24'),
(136, 'Kiran', 'koretyk@gmail.com', 'Car Rental with Driver', 'From Dec27-Jan02 - 7 Days. Looking for renting a mid size SUV for 3 adults. Pls give Quote.', '2025-10-28 08:33:34'),
(137, 'Connor Western', 'connor@cowboyclosers.com', 'Car rental', 'I want to rent a car please. November 10-16th\r\nIf you have available?', '2025-10-28 09:25:39'),
(138, 'Ashley Franks', 'ashleyfranks@gmail.com', 'car rental', 'We are intereted in renting a mini SUV 22/12/25-1/1/2026. We will be in Colombo 3 so a pick up and drop off around there would be good. We would also like help with the international drivers lisence. Could you let me know the costs \r\n', '2025-10-29 22:30:08'),
(139, 'Julia', 'juliablakowska@gmail.com', 'Rental', 'Hello I want to ask how much is it for Toyota Prius for 10 days? ( rental) ', '2025-10-30 08:37:23'),
(140, 'Ben', 'verhagen.ben@telenet.be', 'Helo goodmorning, Ben here from Car CMB 5661', 'We need to return our car tommorow, our flight is at 07:30 in the morning, can you advise on the smoothest transfer of the car.\r\n\r\nI have tried to call a few times.\r\n\r\nWhatsapp +32473873074', '2025-10-31 06:17:29'),
(141, 'SANKA  NAVARATNA', 'sanka000@yahoo.com', 'Van Rental with Driver for 29th December to 10th January 2025 (13 days)', 'Dear Vehicle Rental Team,\r\nI would like to inquire about renting a Toyota KDH 200 or KDH 220 with a driver for the period from 29th December 2024 to 10th January 2025 (13 days).\r\nCould you please provide me with your best rental rate for this period, including the driver’s charges and any other applicable fees?\r\nThank you, and I look forward to your response.\r\nKind regards,\r\nSanka Navaratna JP\r\n', '2025-11-01 07:22:03'),
(142, 'Faezeh Zahedi', 'Zahedifaezeh94@gmail.com', 'Quote  for renting a car ', 'Hi there, \r\nWe are planning to travel around Sri Lanka and I am after a quote for your Suzuki Swift car but your website doesnt offer quotes. How much is it to hire this car from Bandaranaike International Airport on 20 November at 11:30pm (night time) until 4 December. We would prefer dropping the car off in Colombo but if there are so options then we can drop off the car by 4pm at the airport as well. Please add full cover insurance as well. \r\nWe will try to get our license sorted at the airport before picking up the car.\r\nLet me know how much it is with and without a driver.  \r\nThank you. ', '2025-11-01 23:24:13'),
(143, 'ash stewart', 'aashstewart@icloud.com', '19th february - 2nd march', 'hi, I would like to learn about your rates ', '2025-11-02 18:18:53'),
(144, 'Pranat Damani', 'pranatdamani@gmail.com', 'Inquiry for 8-Day Self-Drive Car Rental (2 Dec – 9 Dec, Airport Pickup & Drop)', 'Hi.\r\n\r\nI hope you’re doing well.\r\n\r\nI’m planning an 8-day trip to Sri Lanka from 2 December to 9 December, and I would like to rent a self-drive car for the entire duration.\r\n\r\nPlease let me know the availability of suitable cars during this period.\r\n\r\nI would prefer to pick up and drop off the car at Colombo Airport.\r\n\r\nKindly also share:\r\nDaily/weekly rental cost\r\nDeposit amount and insurance coverage details\r\nMileage limit (if any)\r\nAny additional or hidden charges\r\nPickup and drop-off process at the airport\r\nInternational driving permit (IDP) requirements for tourists\r\n\r\nThank you for your assistance. Looking forward to your reply.\r\n\r\nWarm regards,\r\nPranat Damani\r\npranatdamani@gmail.com', '2025-11-03 03:17:47'),
(145, 'Arist von Dehn', 'vondehn@web.de', 'car rental', 'Today I booked a car from Jan. 24 - Feb. 11 (Invoice 11-16679) but I could not pay (??). Can you please help!\r\nvondehn@web.de', '2025-11-03 17:42:07'),
(146, 'Arist von  Dehn', 'vondehn@web.de', 'car rental', 'I got your invoice for a rental from Jan 24-Feb. 11 with invoice 11-16679 but no confirmation and paymant info!\r\nPlease help!', '2025-11-03 17:46:03'),
(147, 'SRINIVAS RAO', 'srirao17@gmail.com', 'RENT A CAR', 'HI\r\n\r\ncan you provide quote for rent a car on below dates\r\n\r\npick-up :from Colombo International Air port on 31/12/2025 @3am\r\nreturn back : Colombo International Air Port on 10/01/2026 @2pm\r\n\r\nmillage: Unlimited\r\nTransmission: Automatic\r\n\r\nPlease provide quote for Wagon R vehicle', '2025-11-10 08:30:16'),
(148, 'Gowtham', 'connectgowtham@gmail.com', 'Self rental car from November 29 to December 7', 'Hi Sir,\r\n\r\nThis is Gowtham from Tamil Nadu, India. We are a group of 6 adults and 2 infants (total 8 people) planning to visit Sri Lanka from November 29 to December 7.\r\n\r\nWe would like to rent two hatchback cars from November 29 (1:00 PM pick-up at Colombo Airport) to December 7 (9:00 AM drop-off at Colombo Airport).\r\n\r\nCould you please share the tentative rental price for this period?\r\n\r\nThank you in advance! 🙏\r\n\r\nBest regards,\r\nGowtham', '2025-11-12 10:26:08'),
(149, 'Kyunga lee', 'kyunga5440@gmail.com', 'Rent a car', 'Hello, we, 2 of us, are visiting Sri lanka from December 5th to December 19th.\r\nWe would like to rent a car.\r\n1. Interested in an economic car( cheapest) or SUV\r\n2. from December 5, 9:00pm to December 19, 8:00pm.\r\n3. Full coverage insurance ( zero-deductible )\r\n4. 1 additional driver\r\n5. Automatic \r\n\r\nLet me know the rental cost.\r\n\r\nBest regards,\r\nKyunga', '2025-11-12 11:54:51'),
(150, 'Siddharth Garg', 'siddharthgarg74@gmail.com', 'Rent a car for 7 days', 'Hi Team,\r\nI am travelling from India and will be landing in Sri Lanka on 18th Dec 11PM. Could you please help me with the car and the requirements for IDP?\r\n\r\nThanks\r\nSiddharth', '2025-11-12 16:32:56'),
(151, 'Rolands Valdemars', 'rolands.valdemars@inbox.lv', 'car rent', 'Hello, I am interested in car rent in Colombo. It would be 08.January (12:00) NH Collection Colombo hotel and return at 17.01.25 (23:00) Colombo Bandaranaike International Airport. I am interested in economy car, 2 adults and 1 todler 2 years old. What kind of car can you offer and what is pricing - deposit rules. I have international driving permit. Kind regards, Rolands Valdemars', '2025-11-13 16:35:00'),
(152, 'Jordi Benages', 'jordibenages@yahoo.es', 'SELF CAR RENTAL', 'I would like to know the rental prices from 4 december 2025 10:00AM to 17 december 2025  9:30 AM, 150 km per day. \r\n\r\nI would like to know insurance conditions.', '2025-11-13 17:23:55'),
(153, 'Bharath Shetty', 'BHARAT199SRIRAMA@GMAIL.COM', 'Request for cars', 'Hi, We are looking to rent self drive car from 26 December 2025 to 3 January 2026.  Cann you please reach out to me on +91 7760082700 (whatsapp available). \r\n\r\nRegards,\r\n\r\nBharath', '2025-11-13 19:04:10'),
(154, 'Mishael Abu Imam', 'mishael.imam@gmail.com', 'Car available 28 Dec 25 to 02 Jan 25', 'I am coming to Sri Lanka and looking for a self driven car, hence would appreciate if someone contacts me.', '2025-11-14 17:28:41'),
(155, 'Agnieszka Marczak', 'agnieszka.marczakxx@gmail.com', 'rent a car SUV  for 14 days stay, without driver', 'Hi,\r\n\r\nWe would like to rent a car for a whole stay in Sri Lanka (17-30.01.26) What would your offer be for a long rent?', '2025-11-15 12:02:44'),
(156, 'Uthayakumar Iyadurai', 'jathusza@hotmail.com', 'Inquiry About Car Rental with Unlimited Mileage', 'Dear SR Car Rental Company, \r\nI am writing to inquire about renting a small car with unlimited mileage from November 19, 2025, for a period of 10 days.\r\nI came across a car on your website that seems suitable and would like to know:\r\n1) Whether this type of car is available during the requested dates\r\n2)The rental price for the 10-day period\r\n3) If you have any more economical options with the same conditions (unlimited mileage)\r\nI need the car from Colombo AirPort. \r\n\r\nThank you very much for your assistance. I look forward to your reply.\r\n\r\nKind regards,\r\nKumar. \r\n', '2025-11-15 14:03:12'),
(157, 'SAMA SALES', 'samasales123@gmail.com', 'rent a car', 'If i take suzuki alto for 1 day how muchit will be per a day\r\n', '2025-11-17 07:35:41'),
(158, 'SAMA SALES', 'samasales123@gmail.com', 'rent a car', 'If i take suzuki alto for 1 day how muchit will be per a day\r\n', '2025-11-17 07:35:41'),
(159, 'BAS-PEREZ Angel', 'angel.basperez@gmail.com', 'Information', 'Hello,\r\nI plan to come for 4 weeks in Sri Lanka for birdwatching in Jaunuary 2026\r\nI am 67 years old and I am from Belgium\r\nCan you help me for a small car ( I travel alone) ?\r\nThank you for your help\r\nBest regards\r\nAngel BAS-PEREZ\r\n', '2025-11-17 14:44:18'),
(160, 'Varun Dhingra', 'varundhingra10@gmail.com', 'Self drive car rental', 'Require self drive car for 8 days from Colombo airport to airport with unlimited mileage. Let me know the availability and prices', '2025-11-21 09:03:06'),
(161, 'de longueville', 'ndelongueville@gmail.com', 'location van 9 places', 'bonjour\r\navez vous des véhicules 9 places à à louer pour 10 jours au mois de décembre. et quel prix ?\r\nmerci de votre retour\r\nbien cordialement', '2025-11-22 08:57:08'),
(162, 'Ivan Roca', 'ivan.oliveira.roca@gmail.com', 'Licence to Drive in SriLanka', 'Dear Sir or Madam,\r\nI have rented a car from your company from the 2nd to the 12th of January, 2026.\r\nI would like to know if it possible to arrange the necessary driving authorization from Sri Lanka prior to my arrival?\r\nI have booked through Economic Booking and my booking reference is B52975906.\r\nI look forward to your kind response.\r\nMany regards,\r\nIvan Roca \r\n', '2025-11-24 14:23:32'),
(163, 'Piergiorgio Matteini', 'piergiorgio.matteini@blubud.it', 'Car rental and driving license permit', 'Hi we are planning to visit Sri Lanka for a week in February. We need to rent a car and we wish to self drive. We are a family. Please send offer and details\r\nthanks\r\nPiergiorgio', '2025-11-30 15:45:19'),
(164, 'Piergiorgio Matteini', 'piergiorgio.matteini@blubud.it', 'Car rental and driving license permit', 'Please send details about renting a car including driving license permit\r\nWe are italian family\r\nthanks', '2025-11-30 15:46:21'),
(165, 'FRAIOLI', 'j.fraioli@jbn-evasion.fr', 'Reserve a vehicle ', 'Hello, we are unable to reserve a vehicle via the website.', '2025-11-30 17:08:02'),
