INSERT INTO `coverage_packages` (`id`, `title`, `description`, `percentage`, `features`, `created_at`, `updated_at`) VALUES
(1, 'Without Full Coverage', 'If there’s damage or theft, the rental company will charge you for the items not covered.', NULL, '[\"Damage, theft, vandalism, hit-and-run\", \"Windows, mirrors, lamps, wheels, tires\", \"Bodywork, underbody, roof, mechanical damage\", \"Roadside assistance, towing, and taxi expenses\", \"Lost keys and lockout fees\", \"Misfuelling-related costs\", \"Administrative fees related to the damage\" , \"No drivers covered\"]', '2026-03-17 05:36:49', '2026-03-18 06:38:31'),
(2, 'Plus Coverage', 'Balanced protection for common incidents with reduced financial risk during your rental.', 45.00, '[\"Coverage for damage, theft, and vandalism\", \"Partial protection for windows, mirrors, and tires\", \"Roadside assistance included\", \"Reduced financial liability\", \"Covers basic administrative fees\"]', '2026-03-17 05:36:49', '2026-03-17 05:36:49'),
(3, 'Premium Coverage', 'Comprehensive protection covering most risks, giving you peace of mind during your journey.', 90.00, '[\"Full coverage for damage, theft, and vandalism\", \"Includes windows, mirrors, tires, and underbody\", \"Roadside assistance, towing, and taxi costs covered\", \"Lost keys and lockout protection\", \"Misfuelling protection included\"]', '2026-03-17 05:36:49', '2026-03-17 05:36:49'),
(4, 'Premium Plus Coverage', 'Maximum protection with full reimbursement and zero stress during your rental.', 200.00, '[\"All damage and theft fully covered\", \"All vehicle parts covered including roof and mechanical\", \"Full roadside assistance and recovery costs\", \"Lost keys, lockouts, and misfuelling covered\", \"All administrative fees covered\", \"All drivers included under coverage\", \"Priority support and fastest claim handling\"]', '2026-03-17 05:36:49', '2026-03-17 05:36:49');
