(6, 'document', 'contact_us', 'Congratulations!', '', 'contact-us', '', 1, 0, 0, 0, 0, '', '  \r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n<section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n	<div class=\"overlay\"></div>\r\n	<div class=\"container\">\r\n		<div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n		<div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n			<h1 class=\"mb-2 bread\">Contact Us</h1>\r\n			<p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Contact Us <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n		</div>\r\n		</div>\r\n	</div>\r\n</section>\r\n\r\n<section class=\"contact-modern\">\r\n	<div class=\"container\">\r\n\r\n		<div class=\"row align-items-center\">\r\n\r\n		<!-- LEFT: Contact Info -->\r\n		<div class=\"col-lg-5\">\r\n			<div class=\"contact-card\">\r\n\r\n			<h2 class=\"text-white\">Get In Touch</h3>\r\n			<p>We’re here to help you with rentals, transfers, and reservations. Reach out anytime.</p>\r\n\r\n			<div class=\"contact-item\">\r\n				<span class=\"contact-icon\">📍</span>\r\n					<div>\r\n				<strong>Address</strong>\r\n				<p>\r\n					<a href=\"https://maps.app.goo.gl/N69GRNHpC4VfgpWs5\"\r\n					target=\"_blank\"\r\n					class=\"contact-link\">\r\n					SR Rent A Car (Pvt.) Ltd,<br>\r\n					371/5, Negombo Road, Seeduwa, Sri Lanka\r\n					</a>\r\n				</p>\r\n				</div>\r\n			</div>\r\n\r\n			<div class=\"contact-item\">\r\n				<span class=\"contact-icon\">📞</span>\r\n				<div>\r\n				<strong>Phone</strong>\r\n				<p><a href=\"tel:+94777780729\">+94 77 778 0729</a></p>\r\n				</div>\r\n			</div>\r\n\r\n			<div class=\"contact-item\">\r\n				<span class=\"contact-icon\">✉️</span>\r\n				<div>\r\n				<strong>Email</strong>\r\n				<p><a href=\"mailto:bookings@srilankarentacar.com\">bookings@srilankarentacar.com</a></p>\r\n				</div>\r\n			</div>\r\n\r\n			<div class=\"social-section\">\r\n				<h6>Follow Us</h6>\r\n				<div class=\"social-icons\">\r\n\r\n					<a href=\"https://www.linkedin.com/company/31174684/admin/dashboard/\" \r\n						target=\"_blank\" \r\n						class=\"social-btn linkedin\">\r\n						<i class=\"fab fa-linkedin-in\"></i>\r\n					</a>\r\n\r\n					<a href=\"https://www.facebook.com/srrentacar\" \r\n						target=\"_blank\" \r\n						class=\"social-btn facebook\">\r\n						<i class=\"fab fa-facebook-f\"></i>\r\n					</a>\r\n\r\n					<a href=\"https://www.instagram.com/srrentacarsrilanka/\" \r\n						target=\"_blank\" \r\n						class=\"social-btn instagram\">\r\n						<i class=\"fab fa-instagram\"></i>\r\n					</a>\r\n\r\n					</div>\r\n			</div>\r\n\r\n			</div>\r\n		</div>\r\n\r\n		<!-- RIGHT: Contact Form -->\r\n		<div class=\"col-lg-7\">\r\n			<div class=\"contact-form-box\">\r\n\r\n			<h3>Send Us a Message</h3>\r\n\r\n			<form id=\"contactForm\" method=\"POST\">\r\n				<div class=\"floating-group\">\r\n				<input type=\"text\" name=\"name\" required placeholder=\"Your Name\">\r\n				<!-- <label>Your Name</label> -->\r\n				</div>\r\n\r\n				<div class=\"floating-group\">\r\n				<input type=\"email\" name=\"email\" required placeholder=\"Your Email\">\r\n				<!-- <label>Your Email</label> -->\r\n				</div>\r\n\r\n				<div class=\"floating-group\">\r\n				<input type=\"text\" name=\"subject\" required placeholder=\"Subject\">\r\n				<!-- <label>Subject</label> -->\r\n				</div>\r\n\r\n				<div class=\"floating-group\">\r\n				<textarea name=\"message\" rows=\"5\" required placeholder=\"Your Message\"></textarea>\r\n				<!-- <label>Your Message</label> -->\r\n				</div>\r\n\r\n				<button type=\"submit\" class=\"contact-btn\">\r\n				Send Message →\r\n				</button>\r\n\r\n			</form>\r\n\r\n			<div id=\"formMessage\"></div>\r\n\r\n			</div>\r\n		</div>\r\n\r\n		</div>\r\n	</div>\r\n</section>\r\n     \r\n<div class=\"row\">\r\n	<div class=\"col-12\">\r\n		<div class=\"map\">\r\n			<iframe\r\n				src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3958.971183150275!2d79.87322757499844!3d7.129329892874595!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3ae2f9da7f0d8cad%3A0x23cc584d58386b05!2sSR%20Rent%20A%20Car%20Sri%20Lanka!5e0!3m2!1sen!2slk!4v1724917513316!5m2!1sen!2slk\"\r\n				width=\"100%\" height=\"450\" style=\"border:2;\" allowfullscreen=\"\" loading=\"lazy\"></iframe>\r\n		</div>\r\n	</div>\r\n</div>      \r\n\r\n<script>\r\ndocument.getElementById(\"contactForm\").addEventListener(\"submit\", function(e) {\r\n    e.preventDefault();\r\n\r\n    const form = this;\r\n    const button = form.querySelector(\"button[type=\'submit\']\");\r\n    const msg = document.getElementById(\"formMessage\");\r\n\r\n    button.disabled = true;\r\n    button.innerHTML = \"Sending...\";\r\n    msg.innerHTML = \"\";\r\n\r\n    const formData = new FormData(form);\r\n\r\n    fetch(\"assets/includes/save-contact.php\", {\r\n        method: \"POST\",\r\n        body: formData\r\n    })\r\n    .then(response => response.json())\r\n    .then(data => {\r\n\r\n        if (data.success) {\r\n            msg.innerHTML = \"<p style=\'color:green;font-weight:600;\'>✔ Message submitted successfully!</p>\";\r\n\r\n            form.reset();\r\n\r\n            setTimeout(() => {\r\n                msg.innerHTML = \"\";\r\n            }, 3000);\r\n\r\n        } else {\r\n            msg.innerHTML = \"<p style=\'color:red;\'>\" + data.message + \"</p>\";\r\n        }\r\n\r\n        button.disabled = false;\r\n        button.innerHTML = \"Send Message →\";\r\n    })\r\n    .catch(error => {\r\n        msg.innerHTML = \"<p style=\'color:red;\'>Server error. Please try later.</p>\";\r\n\r\n        button.disabled = false;\r\n        button.innerHTML = \"Send Message →\";\r\n        console.log(error);\r\n    });\r\n});\r\n</script>', 1, 2, 4, 1, 1, 1, 1724916257, 1, 1774258548, 0, 0, 0, 1724916240, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'contact-us.html', 0, 0, 1, NULL, 1),
(7, 'document', 'Navigating a Vehicle Accident in Sri Lanka as a Foreigner', 'Congratulations!', '', 'navigating-a-vehicle-accident-in-sri-lanka-as-a-foreigner', '', 1, 0, 0, 0, 0, '', '  \r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n      <div class=\"overlay\"></div>\r\n      <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Blog</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n		\r\n<section class=\"blog-article-modern py-5\">\r\n  <!-- reading progress -->\r\n  <div class=\"reading-progress\" id=\"readingProgress\"></div>\r\n\r\n  <div class=\"container\">\r\n    <div class=\"row\">\r\n\r\n      <!-- MAIN -->\r\n      <div class=\"col-lg-9\">\r\n        <article class=\"article-card\">\r\n\r\n          <!-- Hero -->\r\n          <header class=\"article-hero\">\r\n            <div class=\"article-meta\">\r\n              <span class=\"meta-pill\"><i class=\"far fa-clock\"></i> April 19, 2024</span>\r\n              <span class=\"meta-pill\"><i class=\"fas fa-user\"></i> Sri Lanka Travel Guide</span>\r\n              <span class=\"meta-pill\"><i class=\"fas fa-car-crash\"></i> Safety</span>\r\n            </div>\r\n\r\n            <h1 class=\"article-title\">\r\n              Navigating a Vehicle Accident in Sri Lanka as a Foreigner: A Comprehensive Guide\r\n            </h1>\r\n\r\n            <figure class=\"article-cover\">\r\n              <img src=\"assets/images/blog/car_crashed.jpg\" alt=\"\" class=\"img-fluid\">\r\n            </figure>\r\n          </header>\r\n\r\n          <!-- TOC -->\r\n          <div class=\"article-toc\" id=\"articleToc\">\r\n            <div class=\"toc-head\">\r\n              <strong>On this page</strong>\r\n              <span class=\"toc-mini\">Jump to section</span>\r\n            </div>\r\n            <div class=\"toc-list\" id=\"tocList\"></div>\r\n          </div>\r\n\r\n          <!-- CONTENT -->\r\n          <div class=\"article-body\" id=\"articleBody\">\r\n\r\n            <p>\r\n              Driving in a foreign country can be an exciting experience, but it’s essential to be prepared for unexpected situations like a vehicle accident...\r\n            </p>\r\n\r\n            <h2>Immediate Actions to Take After an Accident</h2>\r\n\r\n            <h3>Ensure Safety</h3>\r\n            <p>\r\n              Ensuring safety after a vehicle accident is paramount to protecting lives, preventing further harm, and handling the situation effectively...\r\n            </p>\r\n\r\n            <p><strong>How to ensure safety after an accident?</strong></p>\r\n            <ul>\r\n              <li><strong>Check for Injuries:</strong> The first and most critical step is to check yourself and others involved...</li>\r\n              <li><strong>Assess the Surroundings:</strong> Be aware of any potential hazards such as leaking fuel...</li>\r\n              <li><strong>Move to a Safe Location:</strong> If the vehicle is obstructing traffic and it is safe to do so, move it...</li>\r\n              <li><strong>Seek Medical Attention:</strong> Even if you do not feel injured immediately...</li>\r\n            </ul>\r\n\r\n            <h3>Document the Scene</h3>\r\n            <p>\r\n              Documenting the scene after a vehicle accident is crucial to ensure that all necessary information is collected...\r\n            </p>\r\n\r\n            <div class=\"callout\">\r\n              <div class=\"callout-icon\">📸</div>\r\n              <div class=\"callout-body\">\r\n                <strong>Quick tip</strong>\r\n                <p>Take photos/videos from multiple angles: vehicle damage, road signs, skid marks, debris, and injuries (if safe).</p>\r\n              </div>\r\n            </div>\r\n\r\n            <p>\r\n              If you have rented with SR Rent A Car, please submit any accident-related documentation to us via WhatsApp or email:\r\n            </p>\r\n\r\n            <div class=\"contact-callout\">\r\n              <a class=\"contact-chip\" href=\"https://wa.me/94777780729\" target=\"_blank\">\r\n                <i class=\"fab fa-whatsapp\"></i> WhatsApp: +94 777 780 729\r\n              </a>\r\n              <a class=\"contact-chip\" href=\"mailto:info@srilankarentacar.com\">\r\n                <i class=\"far fa-envelope\"></i> info@srilankarentacar.com\r\n              </a>\r\n            </div>\r\n\r\n            <h3>Notify Rental Company</h3>\r\n            <p>\r\n              If you were driving a rental vehicle at the time of the accident, it is crucial to inform the rental agency...\r\n            </p>\r\n            <ul>\r\n              <li><strong>Insurance Policy:</strong> The rental company’s insurance policy may not cover accidents...</li>\r\n              <li><strong>Rental Terms:</strong> Failure to notify may result in full responsibility for damages...</li>\r\n              <li><strong>Assistance:</strong> Informing us allows repairs/replacements and claim guidance...</li>\r\n            </ul>\r\n\r\n            <h3>Inform the Insurance Company</h3>\r\n            <p>\r\n              Notifying your insurance company after a vehicle accident is necessary to comply with policy terms...\r\n            </p>\r\n\r\n            <figure class=\"article-image\">\r\n              <img src=\"assets/images/blog/insurance.jpg\" class=\"img-fluid\" alt=\"\">\r\n            </figure>\r\n\r\n            <h2>Reporting the Accident to Authorities</h2>\r\n            <p>\r\n              In Sri Lanka, it is mandatory to report any accidents to the police, even if they seem minor...\r\n            </p>\r\n\r\n            <h2>Conclusion</h2>\r\n            <p>\r\n              Navigating a vehicle accident in Sri Lanka as a foreigner can be challenging, but with the right information...\r\n            </p>\r\n\r\n            <!-- CTA -->\r\n            <div class=\"article-cta\">\r\n              <div class=\"cta-text pl-0\">\r\n                <h4>Need help right now?</h4>\r\n                <p>Contact SR Rent A Car for guidance during accidents, claims, or replacements.</p>\r\n              </div>\r\n              <div class=\"cta-actions\">\r\n                <a class=\"cta-btn align-items-center\" href=\"tel:+94777780729\"><i class=\"fas fa-phone-alt pr-3\"></i> Call</a>\r\n                <a class=\"cta-btn align-items-center outline\" href=\"https://wa.me/94777780729\" target=\"_blank\"><i class=\"fab fa-whatsapp pr-3\"></i> WhatsApp</a>\r\n              </div>\r\n            </div>\r\n\r\n          </div>\r\n        </article>\r\n      </div>\r\n\r\n      <!-- SIDEBAR -->\r\n      <div class=\"col-lg-3\">\r\n        <aside class=\"sidebar-sticky\">\r\n\r\n          <div class=\"sidebar-card\">\r\n            <h5 class=\"sidebar-title\">Previous Blogs</h5>\r\n\r\n            <a class=\"side-post\" href=\"[[~8]]\">\r\n              <span class=\"thumb\" style=\"background-image:url(assets/images/blog/hidden_gems.jpg)\"></span>\r\n              <span class=\"side-text\">\r\n                <span class=\"side-heading\">Hidden Gems near Kandy to Discover with Your Rental Car</span>\r\n                <span class=\"side-date\"><i class=\"far fa-calendar\"></i> Sep 20, 2023</span>\r\n              </span>\r\n            </a>\r\n\r\n            <a class=\"side-post\" href=\"[[~12]]\">\r\n              <span class=\"thumb\" style=\"background-image:url(assets/images/blog/driving_license.jpg)\"></span>\r\n              <span class=\"side-text\">\r\n                <span class=\"side-heading\">Valid Driving Licenses To Rent A Car In Sri Lanka</span>\r\n                <span class=\"side-date\"><i class=\"far fa-calendar\"></i> Nov 01, 2021</span>\r\n              </span>\r\n            </a>\r\n\r\n            <a class=\"side-post\" href=\"[[~13]]\">\r\n              <span class=\"thumb\" style=\"background-image:url(assets/images/blog/road_sign.jpg)\"></span>\r\n              <span class=\"side-text\">\r\n                <span class=\"side-heading\">Essential Guide to Sri Lanka’s Traffic Rules for Drivers</span>\r\n                <span class=\"side-date\"><i class=\"far fa-calendar\"></i> Oct 27, 2021</span>\r\n              </span>\r\n            </a>\r\n\r\n            <a class=\"side-post\" href=\"[[~14]]\">\r\n              <span class=\"thumb\" style=\"background-image:url(assets/images/blog/drive_road.jpg)\"></span>\r\n              <span class=\"side-text\">\r\n                <span class=\"side-heading\">How to travel in Sri Lanka at your own pace?</span>\r\n                <span class=\"side-date\"><i class=\"far fa-calendar\"></i> Apr 19, 2024</span>\r\n              </span>\r\n            </a>\r\n\r\n            <a class=\"side-post\" href=\"[[~15]]\">\r\n              <span class=\"thumb\" style=\"background-image:url(assets/images/blog/short_term.jpg)\"></span>\r\n              <span class=\"side-text\">\r\n                <span class=\"side-heading\">How to Rent a Car in Sri Lanka: Step-by-Step Process</span>\r\n                <span class=\"side-date\"><i class=\"far fa-calendar\"></i> Jun 21, 2021</span>\r\n              </span>\r\n            </a>\r\n\r\n          </div>\r\n\r\n        </aside>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<script>\r\n(function () {\r\n  // Progress bar\r\n  const bar = document.getElementById(\"readingProgress\");\r\n  window.addEventListener(\"scroll\", () => {\r\n    const h = document.documentElement;\r\n    const scrolled = (h.scrollTop) / (h.scrollHeight - h.clientHeight);\r\n    bar.style.width = (scrolled * 100) + \"%\";\r\n  });\r\n\r\n  // Auto TOC\r\n  const body = document.getElementById(\"articleBody\");\r\n  const toc = document.getElementById(\"tocList\");\r\n  if (!body || !toc) return;\r\n\r\n  const headings = body.querySelectorAll(\"h2, h3\");\r\n  headings.forEach((h, idx) => {\r\n    const id = \"sec-\" + idx;\r\n    h.id = id;\r\n\r\n    const a = document.createElement(\"a\");\r\n    a.href = \"#\" + id;\r\n    a.textContent = h.textContent;\r\n    a.style.paddingLeft = (h.tagName === \"H3\") ? \"18px\" : \"10px\";\r\n\r\n    a.addEventListener(\"click\", (e) => {\r\n      e.preventDefault();\r\n      document.getElementById(id).scrollIntoView({ behavior: \"smooth\", block: \"start\" });\r\n      history.replaceState(null, \"\", \"#\" + id);\r\n    });\r\n\r\n    toc.appendChild(a);\r\n  });\r\n})();\r\n</script>\r\n		\r\n    ', 1, 2, 5, 1, 1, 1, 1724994788, 1, 1772528462, 0, 0, 0, 1724994780, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'navigating-a-vehicle-accident-in-sri-lanka-as-a-foreigner.html', 0, 0, 1, NULL, 1),
(8, 'document', 'Hidden Gems near Kandy', 'Congratulations!', '', 'hidden-gems-near-kandy', '', 1, 0, 0, 0, 0, '', '  \r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n      <div class=\"overlay\"></div>\r\n      <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Blog</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n        \r\n        <section class=\"ftco-section\">\r\n            <div class=\"container\">\r\n                <div class=\"row\">\r\n          <div class=\"col-lg-8 ftco-animate\">\r\n            <h2 class=\"mb-3\" style=\"font-weight: 900;\">Hidden Gems near Kandy to Discover with Your Rental Car</h2>\r\n            <p>\r\n              <img src=\"assets/images/blog/hidden_gems.jpg\" alt=\"\" class=\"img-fluid\">\r\n            </p>\r\n            <p style=\"text-align: justify;\">\r\n              Kandy, the cultural jewel of Sri Lanka, beckons travellers with its rich history, vibrant culture, and captivating landscapes. While the city itself teems with attractions, the true essence of this region lies in the undiscovered gems hidden in its environs. For an authentic exploration of these treasures, renting a car is an excellent choice. It grants you the liberty to stray from the tourist trail and uncover the often-overlooked marvels of the region. In this article, we’ll take you on a journey to explore 10 hidden gems near Kandy that come alive when you have the freedom of your own rental car.\r\n              </p>\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">1. Udawatta Kele Sanctuary: Nature’s Hideaway</h3>\r\n              <p>\r\n                  <img src=\"assets/images/blog/news/Udawatta-Kele-Sanctuary-980x551.jpg\" alt=\"\" class=\"img-fluid\">\r\n                </p>\r\n              \r\n              <p style=\"text-align: justify;\">\r\n                  Begin your adventure with a visit to the Udawatta Kele Sanctuary, an emerald forest reserve just a stone’s throw away from Kandy’s heart. This verdant haven hosts a variety of wildlife, including vibrant birds, playful monkeys, and enchanting butterflies. As you meander along its forested trails, you’ll stumble upon ancient ruins and hidden Buddhist shrines. This sanctuary’s tranquillity offers a perfect escape from the city’s hustle and bustle.\r\n              </p>\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\"> 2. Knuckles Mountain Range: A Hiker’s Paradise</h3>\r\n              <p>\r\n                  <img src=\"assets/images/blog/news/Knuckles-Mountain-Range-980x551.jpg\" alt=\"\" class=\"img-fluid\">\r\n                </p>\r\n             \r\n                <p style=\"text-align: justify;\">Venture a bit further from Kandy, and you’ll stumble upon the Knuckles Mountain Range, a UNESCO World Heritage Site. These hidden gems lure avid hikers with a web of challenging trails leading to breathtaking vistas. The rugged terrain, diverse flora, and fauna make this place an exceptional communion with nature. Don’t forget to pack a picnic and relish a meal amidst the awe-inspiring mountain scenery.</p>\r\n\r\n                <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\"> 3. Alagalla Mountain: A Thrill Seeker’s Dream</h3>\r\n              \r\n              <p style=\"text-align: justify;\">\r\n            For those with a taste for adventure, Alagalla Mountain, affectionately known as the Potato Range due to its shape, beckons. The trek to its summit winds through dense forests, tea plantations, and rocky outcrops. The reward at the pinnacle is a sweeping view of the surrounding countryside, making it an ideal spot for witnessing sunrise or sunset.\r\n              </p>\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\"> 4. Bathalegala: The Enigmatic Bible Rock</h3>\r\n              \r\n              <p style=\"text-align: justify;\">\r\n                  Bathalegala, often referred to as the “Bible Rock” due to its unique form, is another hidden treasure worth unearthing. While the climb is challenging, the panoramic vista from the summit is a reward beyond compare. Along the ascent, you’ll discover a cave temple and an ancient stone inscribed with Sinhala script. The sense of accomplishment and the vistas from the peak justify every ounce of effort.\r\n              </p>\r\n              \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\"> 5. Ramboda Falls: Nature’s Masterpiece</h3>\r\n              <p></p>\r\n                  <img src=\"assets/images/blog/news/Ramboda-Waterfalls-980x551.jpg\" alt=\"\" class=\"img-fluid\">\r\n                </p>\r\n              <p style=\"text-align: justify;\">\r\n                  Ramboda Falls, situated approximately 20 kilometres from Kandy, ranks among Sri Lanka’s most magnificent waterfalls. The journey itself is a visual treat as you meander through picturesque tea plantations. Upon arrival, a short walk leads you to the base of the falls, where you can feel the mist on your skin and witness the sheer might of nature. It’s an ideal place for a refreshing interlude.\r\n              </p>\r\n              \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">6. Loolecondera  Estate: Birthplace of Ceylon Tea</h3>\r\n              \r\n          </p><p>\r\n          <img src=\"assets/images/blog/news/Loolecondera-Estate-980x551.jpg\" alt=\"\" class=\"img-fluid\">\r\n        </p>\r\n              <p style=\"text-align: justify;\">\r\n                  For aficionados of coffee, Loolecondera Estate, also known as Pedro Tea Estate, is the birthplace of Ceylon Tea. These hidden gems offer guided tours where you can glean insights into the art of tea-making from seasoned experts. The estate’s allure extends beyond its informative tours, as it is adorned with rolling hills blanketed in vibrant green tea bushes.\r\n              </p>\r\n\r\n             \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">  7. Hulu Ganga: The Serene Oasis</h3>\r\n                            \r\n              <p style=\"text-align: justify;\">\r\n                  Hulu Ganga, or the Hulu River, is a secluded haven, perfect for a tranquil respite. Nestled near Teldeniya, this oasis offers a serene setting enveloped by luxuriant vegetation. The river’s calm waters invite you to swim and picnic, providing an ideal space to unwind and savour the peaceful ambience of Sri Lanka’s countryside.\r\n              </p>\r\n              \r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">8. Degaldoruwa Raja Maha Viharaya: A Hidden Temple</h3>\r\n              <p>\r\n                  <img src=\"assets/images/blog/news/Degaldoruwa-Raja-Maha-Vihara-Kandy-980x551.jpg\" alt=\"\" class=\"img-fluid\">\r\n                </p>\r\n              <p style=\"text-align: justify;\">\r\n                  While the renowned Dambulla Cave Temples often draw hordes of tourists, the lesser-known Degaldoruwa Raja Maha Viharaya near Kandy holds its own allure. This hidden gem boasts a cave temple adorned with exquisite Kandyan-era frescoes and intricate cave architecture. Here, you can immerse yourself in a quieter and more intimate spiritual experience compared to the bustling Dambulla caves.\r\n              </p>\r\n\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\"> 9. Pitawala Pathana: Mini-World’s End</h3>\r\n             \r\n              <p style=\"text-align: justify;\">\r\n                  Pitawala Pathana, an expansive grassland nestled within the Knuckles Forest Reserve, is a destination of unique charm. Its landscape, punctuated by colossal rock formations, has earned it the moniker of Sri Lanka’s “mini-world’s end.” A leisurely walk or a picnic here offers an opportunity to witness the diverse flora, including rare and endemic species, that grace this high-altitude plateau.\r\n              </p>\r\n\r\n\r\n\r\n              <h3 class=\"mb-3 mt-5\" style=\"font-weight: 700;\">10. Bambarakiri Ella Waterfall: Nature’s Oasis</h3>\r\n             \r\n              <p style=\"text-align: justify;\">\r\n                  Hidden deep within the Ududumbara area, the Bambarakiri Ella Waterfall is a true gem awaiting your discovery. To reach this hidden waterfall, you’ll embark on a picturesque drive through the countryside and embark on a short trek. Your reward is the sight of a splendid cascade framed by lush greenery, complete with a natural pool for a refreshing dip.\r\n              </p>\r\n\r\n              <p style=\"text-align: justify;\">\r\n                  In summary, the essence of Kandy and its surroundings lies in its hidden gems. Renting a car opens doors to these treasures, enriching your understanding of the region’s cultural splendour and natural beauty. From serene sanctuaries to challenging hikes and picturesque waterfalls, these 10 hidden gems near Kandy promise an unforgettable Sri Lankan odyssey. Pack your bags, secure a rental car, and embark on a journey to uncover the hidden marvels that await you in the heart of this enchanting island nation.\r\n              </p>\r\n\r\n\r\n\r\n\r\n\r\n          </div> <!-- .col-md-8 -->\r\n\r\n          <div class=\"col-lg-4 sidebar ftco-animate\">\r\n            <div class=\"sidebar-box ftco-animate\">\r\n                <h3>Previous Blogs</h3>\r\n                \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~7]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/hidden_gems.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">Hidden Gems near Kandy to Discover with Your Rental Car</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Sep 20, 2023</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n        \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~12]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/driving_license.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">Valid Driving Licenses To Rent A Car In Sri Lanka</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Nov 01, 2021</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n        \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~13]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/road_sign.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">Essential Guide to Sri Lanka’s Traffic Rules for Drivers</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Oct 27, 2021</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n        \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~14]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/drive_road.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">How to travel in Sri Lanka at your own pace?</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Apr 19, 2024</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n        \r\n                <div class=\"block-21 mb-4 d-flex\">\r\n                    <a href=\"[[~15]]\" class=\"d-flex\">\r\n                        <div class=\"blog-img mr-4\" style=\"background-image: url(assets/images/blog/short_term.jpg);\"></div>\r\n                        <div class=\"text\">\r\n                            <h3 class=\"heading\">How to Rent a Car in Sri Lanka: The Step-by-Step Process</h3>\r\n                            <div class=\"meta\">\r\n                                <div><span class=\"icon-calendar\"></span> Jun 21, 2021</div>\r\n                            </div>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n        \r\n            </div>\r\n        </div><!-- END COL -->\r\n        \r\n            </div>\r\n        </section>\r\n        \r\n    ', 1, 2, 6, 1, 1, 1, 1725001701, 1, 1748924175, 0, 0, 0, 1725001680, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'hidden-gems-near-kandy.html', 0, 0, 1, NULL, 1);
