(9, 'document', 'rentacar', 'Congratulations!', '', 'rent-a-car', '', 1, 0, 0, 0, 0, '', '  \r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/breadcrumb/sr_bc_rentacar.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n        <div class=\"overlay\"></div>\r\n        <div class=\"container\">\r\n          <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n            <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n              <h1 class=\"mb-2 bread\">Rent A  Car</h1>\r\n              <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Rent A  Car <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </section>\r\n    \r\n  \r\n  \r\n    <section class=\"about-section\">\r\n      	<div class=\"container\">\r\n			<div class=\"row clearfix align-items-center\">\r\n				\r\n				<!--Content Column-->\r\n				<div class=\"content-column col-md-6 col-sm-12 col-xs-12\">\r\n					<div class=\"inner-column\">\r\n						<div class=\"sec-title\">\r\n							<h2 style=\"font-size: 30px; color: #a40000;  font-weight: bold;\">Rent A Car In Sri Lanka Has <br> Never Been Easier</h2>\r\n						</div>\r\n\r\n						<div class=\"text\" style=\"text-align: justify;\">\r\n							Want to explore the beautiful island of Sri Lanka freely? Our team is ready to help you find the perfect car rental solution.\r\n						\r\n						</div>\r\n						<div class=\"text\" style=\"text-align: justify;\">\r\n							Based in Seeduwa (10 minutes away from Colombo International Airport), SR Rent A Car is an independent car rental company in Sri Lanka established since 2004. We offer luxurious customer service and affordable rates. Our personalized and professional approach ensures your satisfaction.\r\n							You can conveniently collect and return your vehicle at Bandaranaike International Airport or our Seeduwa office. Choose from a wide range of vehicles to suit your needs. Our helpful staff is available 24/7 to assist you with any queries.\r\n						</div>\r\n	\r\n						<a href=\"[[~4]]\" class=\"theme-btn btn-style-three\">Rent A Car</a>\r\n						<!-- <a href=\"[[~4]]\" class=\"theme-btn btn-style-three\" style=\"margin-left: 35px;\">(+94) 777 780 729</a> -->\r\n					</div>\r\n				</div>\r\n	\r\n					\r\n					<!--Image Column-->\r\n					<div class=\"image-column col-md-6 col-sm-12 col-xs-12\">\r\n					<div class=\"inner-column \" data-wow-delay=\"0ms\" data-wow-duration=\"1500ms\">\r\n						<div class=\"image\">\r\n								<img src=\"assets/images/rentacar/renthome.png\" alt=\"\">\r\n								<div class=\"overlay-box\">\r\n								<div class=\"year-box\"><span class=\"number\">20</span>Years <br> Industry  <br> Expertise</div>\r\n								</div>\r\n							</div>\r\n						</div>\r\n					</div>\r\n					\r\n			</div>\r\n		</div>\r\n    </section>\r\n\r\n       <!-- Topic Cards -->\r\n         <!-- <div id=\"cards_landscape_wrap-2\">\r\n         \r\n			<div class=\"container\">\r\n				<h1 class=\"text-gradient\" style=\"font-size: 40px;text-align: left;\">Short Term Car Rentals</h1>\r\n				<div class=\"row\">\r\n					\r\n					<div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n						<a href=\"\">\r\n							<div class=\"card-flyer\">\r\n								<div class=\"text-box\">\r\n									<div class=\"image-box\">\r\n										<img src=\"assets/images/rentacar/short_term.jpg\" alt=\"\" />\r\n									</div>\r\n									<div class=\"text-container\">\r\n										<h6 style=\"padding-top: 20px;\">Short Term Car Rentals</h6>\r\n										<p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car offer our customers access to a wide variety of the newest vehicles available for short-term hire by the day, week, month.</p>\r\n									</div>\r\n								</div>\r\n							</div>\r\n						</a>\r\n					</div>\r\n					<div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n						<a href=\"\">\r\n							<div class=\"card-flyer\">\r\n								<div class=\"text-box\">\r\n									<div class=\"image-box\">\r\n										<img src=\"assets/images/rentacar/long_term.jpg\" alt=\"\" />\r\n									</div>\r\n									<div class=\"text-container\">                                    \r\n										<h6 style=\"padding-top: 20px;\">Long Term Car Rentals</h6>\r\n										<p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car offer you to hire a vehicle long term basis in Sri Lanka. We offer ultimate flexibility, reliability and affordability for your need.</p>\r\n									</div>\r\n								</div>\r\n							</div>\r\n						</a>\r\n					</div>\r\n					<div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n						<a href=\"\">\r\n							<div class=\"card-flyer\">\r\n								<div class=\"text-box\">\r\n									<div class=\"image-box\">\r\n										<img src=\"assets/images/rentacar/corporate_rental.jpg\" alt=\"\" />\r\n									</div>\r\n	\r\n									<div class=\"text-container\">\r\n										<h6 style=\"padding-top: 20px;\">Corporate Car Rentals</h6>\r\n										<p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car has always been ahead of the game to provide excellent Corporate Car Rental services at competitive rates for businesses.</p>\r\n									</div>\r\n								</div>\r\n							</div>\r\n						</a>\r\n					</div>\r\n					<div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n						<a href=\"\">\r\n							<div class=\"card-flyer\">\r\n								<div class=\"text-box\">\r\n									<div class=\"image-box\">\r\n										<img src=\"assets/images/rentacar/selfdriving.jpg\" alt=\"\" />\r\n									</div>\r\n	\r\n									<div class=\"text-container\">\r\n										<h6 style=\"padding-top: 20px;\">Self Driven Car Rentals</h6>\r\n										<p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car provides a large range of self-drive cars, vans, and SUVs available in selecting shapes, sizes, and specifications. These come in different specifications and sizes and are available by the day, week, month or longer.</p>\r\n									</div>\r\n								</div>\r\n							</div>\r\n						</a>\r\n					</div>\r\n					<div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n					<a href=\"\">\r\n						<div class=\"card-flyer\">\r\n							<div class=\"text-box\">\r\n								<div class=\"image-box\">\r\n									<img src=\"assets/images/rentacar/chauffeur.jpg\" alt=\"\" />\r\n								</div>\r\n	\r\n								<div class=\"text-container\">\r\n									<h6 style=\"padding-top: 20px;\">Chauffeur Driven Car Rentals</h6>\r\n									<p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">SR Rent A Car is best known for its top-notch personal chauffeur services in Sri Lanka. We make sure that you have the perfect chauffeur driven car for your occasion.</p>\r\n								</div>\r\n							</div>\r\n						</div>\r\n					</a>\r\n				</div>\r\n				<div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-4\">\r\n					<a href=\"\">\r\n						<div class=\"card-flyer\">\r\n							<div class=\"text-box\">\r\n								<div class=\"image-box\">\r\n									<img src=\"assets/images/rentacar/vip.jpg\" alt=\"\" />\r\n								</div>\r\n	\r\n								<div class=\"text-container\">\r\n									<h6 style=\"padding-top: 20px;\">Luxury Car Rentals</h6>\r\n									<p style=\"text-align: justify;padding: 20px;font-size: 16px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">Here At SR Rent A Car we pride ourselves in offering a wide range of prestigious vehicles, from luxury saloons to sporty 4x4s.</p>\r\n								</div>\r\n							</div>\r\n						</div>\r\n					</a>\r\n				</div>\r\n				</div>\r\n			</div>\r\n      	</div> -->\r\n  \r\n<section class=\"ftco-section rental-topics\">\r\n	<div id=\"cards_landscape_wrap-2\">\r\n		<div class=\"container\">\r\n			<div class=\"row mb-4 align-items-end\">\r\n				<div class=\"col-lg-8\">\r\n					<h2 class=\"topics-title\">Short Term Car Rentals</h2>\r\n					<p class=\"topics-sub\">\r\n						Choose the rental type that fits your trip — short term, long term, corporate, self-drive, chauffeur, or luxury.\r\n					</p>\r\n				</div>\r\n			</div>\r\n\r\n			<div class=\"row g-4\">\r\n				<!-- 1 -->\r\n				<div class=\"col-12 col-sm-6 col-lg-4\">\r\n				<a href=\"#\" class=\"topic-card\">\r\n					<div class=\"topic-media\">\r\n					<img src=\"assets/images/rentacar/short_term.jpg\" alt=\"Short Term Car Rentals\">\r\n					<span class=\"topic-chip\">Short Term</span>\r\n					</div>\r\n					<div class=\"topic-body\">\r\n					<h6>Short Term Car Rentals</h6>\r\n					<p>SR Rent A Car offer our customers access to a wide variety of the newest vehicles available for short-term hire by the day, week, month.</p>\r\n					<span class=\"topic-cta\">Explore →</span>\r\n					</div>\r\n				</a>\r\n				</div>\r\n\r\n				<!-- 2 -->\r\n				<div class=\"col-12 col-sm-6 col-lg-4\">\r\n				<a href=\"#\" class=\"topic-card\">\r\n					<div class=\"topic-media\">\r\n					<img src=\"assets/images/rentacar/long_term.jpg\" alt=\"Long Term Car Rentals\">\r\n					<span class=\"topic-chip\">Long Term</span>\r\n					</div>\r\n					<div class=\"topic-body\">\r\n					<h6>Long Term Car Rentals</h6>\r\n					<p>SR Rent A Car offer you to hire a vehicle long term basis in Sri Lanka. We offer ultimate flexibility, reliability and affordability for your need.</p>\r\n					<span class=\"topic-cta\">Explore →</span>\r\n					</div>\r\n				</a>\r\n				</div>\r\n\r\n				<!-- 3 -->\r\n				<div class=\"col-12 col-sm-6 col-lg-4\">\r\n				<a href=\"#\" class=\"topic-card\">\r\n					<div class=\"topic-media\">\r\n					<img src=\"assets/images/rentacar/corporate_rental.jpg\" alt=\"Corporate Car Rentals\">\r\n					<span class=\"topic-chip\">Corporate</span>\r\n					</div>\r\n					<div class=\"topic-body\">\r\n					<h6>Corporate Car Rentals</h6>\r\n					<p>SR Rent A Car has always been ahead of the game to provide excellent Corporate Car Rental services at competitive rates for businesses.</p>\r\n					<span class=\"topic-cta\">Explore →</span>\r\n					</div>\r\n				</a>\r\n				</div>\r\n\r\n				<!-- 4 -->\r\n				<div class=\"col-12 col-sm-6 col-lg-4 mt-4\">\r\n				<a href=\"#\" class=\"topic-card\">\r\n					<div class=\"topic-media\">\r\n					<img src=\"assets/images/rentacar/selfdriving.jpg\" alt=\"Self Driven Car Rentals\">\r\n					<span class=\"topic-chip\">Self Drive</span>\r\n					</div>\r\n					<div class=\"topic-body\">\r\n					<h6>Self Driven Car Rentals</h6>\r\n					<p>SR Rent A Car provides a large range of self-drive cars, vans, and SUVs available by the day, week, month or longer.</p>\r\n					<span class=\"topic-cta\">Explore →</span>\r\n					</div>\r\n				</a>\r\n				</div>\r\n\r\n				<!-- 5 -->\r\n				<div class=\"col-12 col-sm-6 col-lg-4 mt-4\">\r\n				<a href=\"#\" class=\"topic-card\">\r\n					<div class=\"topic-media\">\r\n					<img src=\"assets/images/rentacar/chauffeur.jpg\" alt=\"Chauffeur Driven Car Rentals\">\r\n					<span class=\"topic-chip\">Chauffeur</span>\r\n					</div>\r\n					<div class=\"topic-body\">\r\n					<h6>Chauffeur Driven Car Rentals</h6>\r\n					<p>SR Rent A Car is best known for its top-notch personal chauffeur services in Sri Lanka. Perfect chauffeur-driven car for your occasion.</p>\r\n					<span class=\"topic-cta\">Explore →</span>\r\n					</div>\r\n				</a>\r\n				</div>\r\n\r\n				<!-- 6 -->\r\n				<div class=\"col-12 col-sm-6 col-lg-4 mt-4\">\r\n				<a href=\"#\" class=\"topic-card\">\r\n					<div class=\"topic-media\">\r\n					<img src=\"assets/images/rentacar/vip.jpg\" alt=\"Luxury Car Rentals\">\r\n					<span class=\"topic-chip\">Luxury</span>\r\n					</div>\r\n					<div class=\"topic-body\">\r\n					<h6>Luxury Car Rentals</h6>\r\n					<p>Here At SR Rent A Car we pride ourselves in offering a wide range of prestigious vehicles, from luxury saloons to sporty 4x4s.</p>\r\n					<span class=\"topic-cta\">Explore →</span>\r\n					</div>\r\n				</a>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n</section>\r\n      \r\n<section class=\"ftco-section why-choose\">\r\n  <div class=\"container\">\r\n    <div class=\"row mb-4 align-items-end\">\r\n      <div class=\"col-lg-9\">\r\n        <h2 class=\"why-title\">Why Choose SR Rent A Car?</h2>\r\n        <p class=\"why-intro\">\r\n          SR Rent A Car offers reliable, flexible and cheap car rental services in Sri Lanka. As a rent a car company, we take pride in our trustworthy services to all our esteemed clients. Our wide range of rental cars is available all through the year. Our rental car services stretch from short term rentals to long term rentals at very affordable prices. Whether you are looking for a saloon car, station wagon, minivans, coaster bus and SUVs, we got you covered with low prices and ultimate customer care service. Below are some of the reasons why you should choose us.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"row g-4\">\r\n      <!-- 1 -->\r\n      <div class=\"col-12 col-lg-6\">\r\n        <div class=\"why-item\">\r\n          <button class=\"why-head\" type=\"button\" aria-expanded=\"false\">\r\n            <span class=\"why-icon\">✓</span>\r\n            <span class=\"why-label\">Professional Services</span>\r\n            <span class=\"why-toggle\">+</span>\r\n          </button>\r\n          <div class=\"why-body\">\r\n            <p>\r\n              The happiness & satisfaction of our customer is the most valued components of our business.\r\n              You will be provided with a vehicle that will keep you relaxed, safe, calm and extremely comfortable.\r\n              We guarantee exceptional, first-class services that give 100% customer satisfaction.\r\n            </p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 2 -->\r\n      <div class=\"col-12 col-lg-6\">\r\n        <div class=\"why-item\">\r\n          <button class=\"why-head\" type=\"button\" aria-expanded=\"false\">\r\n            <span class=\"why-icon\">👥</span>\r\n            <span class=\"why-label\">Knowledgeable Staff</span>\r\n            <span class=\"why-toggle\">+</span>\r\n          </button>\r\n          <div class=\"why-body\">\r\n            <p>\r\n              Because our staff are local residents and have years of experience offering vehicle rentals from Sri Lanka,\r\n              you can be confident you’ll get answers to all of your questions and satisfactory solutions along the way.\r\n            </p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 3 -->\r\n      <div class=\"col-12 col-lg-6 mt-3\">\r\n        <div class=\"why-item\">\r\n          <button class=\"why-head\" type=\"button\" aria-expanded=\"false\">\r\n            <span class=\"why-icon\">🛬</span>\r\n            <span class=\"why-label\">Flexible Pick Up and Drop Off Service</span>\r\n            <span class=\"why-toggle\">+</span>\r\n          </button>\r\n          <div class=\"why-body\">\r\n            <p>\r\n              Our friendly staff pick you up from the terminal of your choice. From there you can enjoy your trip with the\r\n              seamless comforts of your own transportation. Once you are ready to hand back the keys, simply meet our team\r\n              at a prearranged time and we’ll drop you off at the airport with plenty of time to spare.\r\n            </p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 4 -->\r\n      <div class=\"col-12 col-lg-6 mt-3\">\r\n        <div class=\"why-item\">\r\n          <button class=\"why-head\" type=\"button\" aria-expanded=\"false\">\r\n            <span class=\"why-icon\">🚗</span>\r\n            <span class=\"why-label\">Diverse Fleet</span>\r\n            <span class=\"why-toggle\">+</span>\r\n          </button>\r\n          <div class=\"why-body\">\r\n            <p>\r\n              We can provide you with a wide range of different vehicles. Our diverse vehicle fleet includes Economy,\r\n              Compact, Family Sedan, Pickup 2x4, SUVs, Station Wagons, Seven-Seaters and many more.\r\n            </p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 5 -->\r\n      <div class=\"col-12 col-lg-6 mt-3\">\r\n        <div class=\"why-item\">\r\n          <button class=\"why-head\" type=\"button\" aria-expanded=\"false\">\r\n            <span class=\"why-icon\">💰</span>\r\n            <span class=\"why-label\">Affordable Rates Guaranteed</span>\r\n            <span class=\"why-toggle\">+</span>\r\n          </button>\r\n          <div class=\"why-body\">\r\n            <p>\r\n              Whether you\'re gearing up to take your family on a road trip or heading out on a business excursion,\r\n              you\'ll find our rates are personalized to you. Providing affordable car rental rates throughout the year\r\n              is one of the key aspects of SR Rent A Car.\r\n            </p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n	<div class=\"row mt-5\">\r\n		<div class=\"col-12 col-lg-6\">\r\n        <div class=\"why-cta\">\r\n          <h4>Need help choosing a vehicle?</h4>\r\n          <p>Tell us your dates and location — we’ll recommend the best option for your budget.</p>\r\n          <a href=\"[[~6]]\" class=\"why-btn\">Contact Us</a>\r\n        </div>\r\n      </div>\r\n	</div>\r\n  </div>\r\n</section>\r\n  \r\n  </div>\r\n    </div>\r\n  \r\n  <script>\r\ndocument.addEventListener(\"DOMContentLoaded\", function () {\r\n  document.querySelectorAll(\".why-item .why-head\").forEach((btn) => {\r\n    btn.addEventListener(\"click\", () => {\r\n      const item = btn.closest(\".why-item\");\r\n      const isOpen = item.classList.contains(\"is-open\");\r\n\r\n      // close others (optional - remove if you want multiple open)\r\n      document.querySelectorAll(\".why-item.is-open\").forEach((openItem) => {\r\n        openItem.classList.remove(\"is-open\");\r\n        openItem.querySelector(\".why-head\").setAttribute(\"aria-expanded\", \"false\");\r\n        openItem.querySelector(\".why-toggle\").textContent = \"+\";\r\n      });\r\n\r\n      // toggle current\r\n      if (!isOpen) {\r\n        item.classList.add(\"is-open\");\r\n        btn.setAttribute(\"aria-expanded\", \"true\");\r\n        item.querySelector(\".why-toggle\").textContent = \"–\";\r\n      } else {\r\n        item.classList.remove(\"is-open\");\r\n        btn.setAttribute(\"aria-expanded\", \"false\");\r\n        item.querySelector(\".why-toggle\").textContent = \"+\";\r\n      }\r\n    });\r\n  });\r\n});\r\n</script>', 1, 2, 7, 1, 1, 1, 1725434763, 1, 1772516946, 0, 0, 0, 1725434760, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'rent-a-car.html', 0, 0, 1, NULL, 1),
(10, 'document', 'faq', 'Congratulations!', '', 'faq', '', 1, 0, 0, 0, 0, '', '  \r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n        <div class=\"overlay\"></div>\r\n        <div class=\"container\">\r\n          <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n            <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n              <h1 class=\"mb-2 bread\">FAQ</h1>\r\n              <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span> FREQUENTLY ASKED QUESTIONS<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </section>\r\n <section class=\"faq-modern\">\r\n  <div class=\"container\">\r\n    <div class=\"row g-4\">\r\n\r\n      <!-- LEFT: Categories -->\r\n      <div class=\"col-lg-4\">\r\n        <div class=\"faq-side\">\r\n          <div class=\"faq-side-head\">\r\n            <h3>FAQ Categories</h3>\r\n            <p>Find answers quickly. Choose a category or search below.</p>\r\n          </div>\r\n\r\n\r\n          <!-- Tabs -->\r\n          <div class=\"nav flex-column faq-nav-modern\" id=\"faq-tabs\" role=\"tablist\" aria-orientation=\"vertical\">\r\n            <a href=\"#tab1\" class=\"faq-tab active\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab1\" aria-selected=\"true\">\r\n              <span class=\"faq-ico\">📄</span> Rental Requirements\r\n            </a>\r\n            <a href=\"#tab2\" class=\"faq-tab\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab2\" aria-selected=\"false\">\r\n              <span class=\"faq-ico\">📅</span> Reservations\r\n            </a>\r\n            <a href=\"#tab3\" class=\"faq-tab\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab3\" aria-selected=\"false\">\r\n              <span class=\"faq-ico\">🚗</span> During Rental Period\r\n            </a>\r\n            <a href=\"#tab4\" class=\"faq-tab\" data-toggle=\"pill\" role=\"tab\" aria-controls=\"tab4\" aria-selected=\"false\">\r\n              <span class=\"faq-ico\">✨</span> Miscellaneous\r\n            </a>\r\n          </div>\r\n\r\n          <div class=\"faq-side-cta\">\r\n            <div class=\"cta-title\">Still need help?</div>\r\n            <div class=\"cta-text pl-0\">Call us anytime for quick assistance.</div>\r\n<a class=\"cta-btn\" href=\"https://wa.me/94773207108\" target=\"_blank\">\r\n    WhatsApp (+94) 773 207 108\r\n</a>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- RIGHT: FAQ Content -->\r\n      <div class=\"col-lg-8\">\r\n        <div class=\"faq-content\">\r\n          <div class=\"tab-content\" id=\"faq-tab-content\">\r\n\r\n            <!-- TAB 1 -->\r\n            <div class=\"tab-pane show active\" id=\"tab1\" role=\"tabpanel\" aria-labelledby=\"tab1\">\r\n              <div class=\"faq-block-head\">\r\n                <h3>Rental Requirements</h3>\r\n                <p>Documents, eligibility and licenses needed to rent a car in Sri Lanka.</p>\r\n              </div>\r\n\r\n              <div class=\"accordion faq-acc\" id=\"accordion-tab-1\">\r\n                <!-- Q1 -->\r\n                <div class=\"faq-item\" data-faq>\r\n                  <button class=\"faq-q\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-1-content-1\">\r\n                    What do I need to rent a car?\r\n                    <span class=\"faq-plus\">+</span>\r\n                  </button>\r\n                  <div class=\"collapse\" id=\"accordion-tab-1-content-1\" data-parent=\"#accordion-tab-1\">\r\n                    <div class=\"faq-a\">\r\n                      <ul>\r\n                        <li>A valid passport</li>\r\n                        <li>A valid international driving licence</li>\r\n                        <li>A valid temporary local (Sri Lankan) driving licence</li>\r\n                        <li>Valid working credit card</li>\r\n                      </ul>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n\r\n                <!-- Q2 -->\r\n                <div class=\"faq-item\" data-faq>\r\n                  <button class=\"faq-q\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-1-content-2\">\r\n                    What type of driver\'s license do I need to drive in Sri Lanka?\r\n                    <span class=\"faq-plus\">+</span>\r\n                  </button>\r\n                  <div class=\"collapse\" id=\"accordion-tab-1-content-2\" data-parent=\"#accordion-tab-1\">\r\n                    <div class=\"faq-a\">\r\n                      <p>\r\n                        You’ll need a valid International Driving Permit (Geneva Convention 1949 format)\r\n                        and a Temporary Sri Lanka Driving Permit (TDL). Obtaining a TDL is compulsory for foreigners.\r\n                      </p>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n\r\n                <!-- Q3 -->\r\n                <div class=\"faq-item\" data-faq>\r\n                  <button class=\"faq-q\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-1-content-3\">\r\n                    How can I obtain a temporary driving license (TDL) in Sri Lanka?\r\n                    <span class=\"faq-plus\">+</span>\r\n                  </button>\r\n                  <div class=\"collapse\" id=\"accordion-tab-1-content-3\" data-parent=\"#accordion-tab-1\">\r\n                    <div class=\"faq-a\">\r\n                      <ul>\r\n                        <li>You can obtain it yourself in Sri Lanka at the Sri Lanka Motor Traffic Department.</li>\r\n                        <li>Or we can obtain it on your behalf (mention when requesting a quote).</li>\r\n                      </ul>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n\r\n                <!-- Q4 -->\r\n                <div class=\"faq-item\" data-faq>\r\n                  <button class=\"faq-q\" type=\"button\" data-toggle=\"collapse\" data-target=\"#accordion-tab-1-content-4\">\r\n                    Can elderly people also rent cars?\r\n                    <span class=\"faq-plus\">+</span>\r\n                  </button>\r\n                  <div class=\"collapse\" id=\"accordion-tab-1-content-4\" data-parent=\"#accordion-tab-1\">\r\n                    <div class=\"faq-a\">\r\n                      <p>Yes. No age restrictions are in place. Anyone with a valid driver’s license can rent a vehicle.</p>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n\r\n            <!-- TAB 2 (keep your existing questions; just wrap each in .faq-item like above) -->\r\n            <div class=\"tab-pane\" id=\"tab2\" role=\"tabpanel\" aria-labelledby=\"tab2\">\r\n              <div class=\"faq-block-head\">\r\n                <h3>Reservations</h3>\r\n                <p>Booking, cancellations, modifications and rental inclusions.</p>\r\n              </div>\r\n\r\n<div class=\"accordion faq-acc\" id=\"accordion-tab-2\">\r\n\r\n  <!-- Q1 -->\r\n  <div class=\"faq-item\" data-faq>\r\n    <button class=\"faq-q\" type=\"button\"\r\n            data-toggle=\"collapse\"\r\n            data-target=\"#accordion-tab-2-content-1\">\r\n      What is included in the rental price, and are there any additional fees?\r\n      <span class=\"faq-plus\">+</span>\r\n    </button>\r\n\r\n    <div class=\"collapse\"\r\n         id=\"accordion-tab-2-content-1\"\r\n         data-parent=\"#accordion-tab-2\">\r\n      <div class=\"faq-a\">\r\n        <p>The basic rental price typically covers the vehicle and standard insurance. Optional extras may include:</p>\r\n        <ul>\r\n          <li>Unlimited mileage or mileage restrictions</li>\r\n          <li>Additional driver fees</li>\r\n          <li>Baby seat rental</li>\r\n          <li>Navigation systems</li>\r\n          <li>Fuel charges</li>\r\n          <li>Optional insurance upgrades</li>\r\n        </ul>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Q2 -->\r\n  <div class=\"faq-item\" data-faq>\r\n    <button class=\"faq-q\" type=\"button\"\r\n            data-toggle=\"collapse\"\r\n            data-target=\"#accordion-tab-2-content-2\">\r\n      Can I drop off the car at a different location from where I picked it up?\r\n      <span class=\"faq-plus\">+</span>\r\n    </button>\r\n\r\n    <div class=\"collapse\"\r\n         id=\"accordion-tab-2-content-2\"\r\n         data-parent=\"#accordion-tab-2\">\r\n      <div class=\"faq-a\">\r\n        <p>\r\n          One-way rentals are possible but typically incur an additional fee.\r\n          Our rental staff will conduct a thorough vehicle inspection at the collection point\r\n          to ensure the vehicle’s condition before finalizing the rental agreement.\r\n        </p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Q3 -->\r\n  <div class=\"faq-item\" data-faq>\r\n    <button class=\"faq-q\" type=\"button\"\r\n            data-toggle=\"collapse\"\r\n            data-target=\"#accordion-tab-2-content-3\">\r\n      What happens if I need to cancel my reservation?\r\n      <span class=\"faq-plus\">+</span>\r\n    </button>\r\n\r\n    <div class=\"collapse\"\r\n         id=\"accordion-tab-2-content-3\"\r\n         data-parent=\"#accordion-tab-2\">\r\n      <div class=\"faq-a\">\r\n        <p>\r\n          Cancellation policies vary depending on the type of reservation\r\n          and how close it is to the pickup date.\r\n          Please contact our team for detailed cancellation terms.\r\n        </p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Q4 -->\r\n  <div class=\"faq-item\" data-faq>\r\n    <button class=\"faq-q\" type=\"button\"\r\n            data-toggle=\"collapse\"\r\n            data-target=\"#accordion-tab-2-content-4\">\r\n      Can I modify my existing reservation?\r\n      <span class=\"faq-plus\">+</span>\r\n    </button>\r\n\r\n    <div class=\"collapse\"\r\n         id=\"accordion-tab-2-content-4\"\r\n         data-parent=\"#accordion-tab-2\">\r\n      <div class=\"faq-a\">\r\n        <p>\r\n          Reservation modifications are possible, preferably with at least 24 hours\' notice.\r\n          Changes can even be made at the collection point, subject to vehicle availability.\r\n        </p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Q5 -->\r\n  <div class=\"faq-item\" data-faq>\r\n    <button class=\"faq-q\" type=\"button\"\r\n            data-toggle=\"collapse\"\r\n            data-target=\"#accordion-tab-2-content-5\">\r\n      How much will it cost to modify a reservation?\r\n      <span class=\"faq-plus\">+</span>\r\n    </button>\r\n\r\n    <div class=\"collapse\"\r\n         id=\"accordion-tab-2-content-5\"\r\n         data-parent=\"#accordion-tab-2\">\r\n      <div class=\"faq-a\">\r\n        <p>\r\n          Modification costs vary depending on the vehicle model selected.\r\n          We offer flexible charge policies for reservation changes to ensure\r\n          the most convenient rental experience possible.\r\n        </p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n</div>\r\n            </div>\r\n\r\n            <!-- Tabs 3-6: keep your content, just convert each Q/A into .faq-item -->\r\n<div class=\"tab-pane\" id=\"tab3\" role=\"tabpanel\" aria-labelledby=\"tab3\">\r\n\r\n  <div class=\"faq-block-head\">\r\n    <h3>During Rental Period</h3>\r\n    <p>Accidents, damage handling, mileage limits and rental rules.</p>\r\n  </div>\r\n\r\n  <div class=\"accordion faq-acc\" id=\"accordion-tab-3\">\r\n\r\n    <!-- Q1 -->\r\n    <div class=\"faq-item\" data-faq>\r\n      <button class=\"faq-q\" type=\"button\"\r\n              data-toggle=\"collapse\"\r\n              data-target=\"#accordion-tab-3-content-1\">\r\n        What should I do if I damage the car?\r\n        <span class=\"faq-plus\">+</span>\r\n      </button>\r\n\r\n      <div class=\"collapse\"\r\n           id=\"accordion-tab-3-content-1\"\r\n           data-parent=\"#accordion-tab-3\">\r\n        <div class=\"faq-a\">\r\n          <p>\r\n            If the vehicle is damaged during the rental period,\r\n            the customer will be required to pay the Non-Operation Charge (NOC).\r\n          </p>\r\n          <p>\r\n            This charge compensates for potential loss of earnings while the vehicle\r\n            is being repaired or cleaned, regardless of the severity of the damage\r\n            or repair duration.\r\n          </p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Q2 -->\r\n    <div class=\"faq-item\" data-faq>\r\n      <button class=\"faq-q\" type=\"button\"\r\n              data-toggle=\"collapse\"\r\n              data-target=\"#accordion-tab-3-content-2\">\r\n        What should I do in case of an accident or theft while renting a car?\r\n        <span class=\"faq-plus\">+</span>\r\n      </button>\r\n\r\n      <div class=\"collapse\"\r\n           id=\"accordion-tab-3-content-2\"\r\n           data-parent=\"#accordion-tab-3\">\r\n        <div class=\"faq-a\">\r\n          <p><strong>If you are involved in an accident:</strong></p>\r\n          <ul>\r\n            <li>Move the vehicle to a safe location.</li>\r\n            <li>Assist any injured parties.</li>\r\n            <li>Report the accident to the police immediately.</li>\r\n            <li>Collect details of the other party involved.</li>\r\n            <li>Contact our Customer Support Desk.</li>\r\n          </ul>\r\n\r\n          <p>\r\n            Do <strong>not</strong> negotiate private settlements on the spot.\r\n            This will invalidate insurance coverage and make you fully responsible for all costs.\r\n          </p>\r\n\r\n          <p>\r\n            In case of theft, report immediately to the police and inform our office.\r\n          </p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Q3 -->\r\n    <div class=\"faq-item\" data-faq>\r\n      <button class=\"faq-q\" type=\"button\"\r\n              data-toggle=\"collapse\"\r\n              data-target=\"#accordion-tab-3-content-3\">\r\n        Are there any restrictions on mileage when using a rental car?\r\n        <span class=\"faq-plus\">+</span>\r\n      </button>\r\n\r\n      <div class=\"collapse\"\r\n           id=\"accordion-tab-3-content-3\"\r\n           data-parent=\"#accordion-tab-3\">\r\n        <div class=\"faq-a\">\r\n          <p>\r\n            Yes. Mileage limits apply:\r\n          </p>\r\n          <ul>\r\n            <li>100 km per day for short-term rentals</li>\r\n            <li>3000 km per month for monthly rentals</li>\r\n          </ul>\r\n          <p>\r\n            Extra mileage will be charged based on the vehicle category.\r\n          </p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Q4 -->\r\n    <div class=\"faq-item\" data-faq>\r\n      <button class=\"faq-q\" type=\"button\"\r\n              data-toggle=\"collapse\"\r\n              data-target=\"#accordion-tab-3-content-4\">\r\n        Can my pet ride in the car?\r\n        <span class=\"faq-plus\">+</span>\r\n      </button>\r\n\r\n      <div class=\"collapse\"\r\n           id=\"accordion-tab-3-content-4\"\r\n           data-parent=\"#accordion-tab-3\">\r\n        <div class=\"faq-a\">\r\n          <p>\r\n            No. Pets are not permitted in rental vehicles to ensure\r\n            cleanliness and comfort for all customers.\r\n          </p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n</div>\r\n\r\n<div class=\"tab-pane\" id=\"tab4\" role=\"tabpanel\" aria-labelledby=\"tab4\">\r\n\r\n  <div class=\"faq-block-head\">\r\n    <h3>Miscellaneous</h3>\r\n    <p>Pickup requirements, changes at pickup, and airport delivery options.</p>\r\n  </div>\r\n\r\n  <div class=\"accordion faq-acc\" id=\"accordion-tab-4\">\r\n\r\n    <!-- Q1 -->\r\n    <div class=\"faq-item\" data-faq>\r\n      <button class=\"faq-q\" type=\"button\"\r\n              data-toggle=\"collapse\"\r\n              data-target=\"#accordion-tab-4-content-1\">\r\n        What do I need to bring when picking up the car?\r\n        <span class=\"faq-plus\">+</span>\r\n      </button>\r\n\r\n      <div class=\"collapse\"\r\n           id=\"accordion-tab-4-content-1\"\r\n           data-parent=\"#accordion-tab-4\">\r\n        <div class=\"faq-a\">\r\n          <ul>\r\n            <li>Your passport</li>\r\n            <li>Your International Driving Licence</li>\r\n            <li>Your Sri Lanka Temporary Driving Licence (TDL) — we can arrange this if you don’t have one</li>\r\n            <li>Your credit card</li>\r\n          </ul>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Q2 -->\r\n    <div class=\"faq-item\" data-faq>\r\n      <button class=\"faq-q\" type=\"button\"\r\n              data-toggle=\"collapse\"\r\n              data-target=\"#accordion-tab-4-content-2\">\r\n        Can I make changes to the reservation when I pick up the car?\r\n        <span class=\"faq-plus\">+</span>\r\n      </button>\r\n\r\n      <div class=\"collapse\"\r\n           id=\"accordion-tab-4-content-2\"\r\n           data-parent=\"#accordion-tab-4\">\r\n        <div class=\"faq-a\">\r\n          <p>\r\n            Yes, you can make changes at pickup (for example, extending or shortening the rental period).\r\n            However, your selected vehicle category and extras are subject to availability.\r\n          </p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Q3 -->\r\n    <div class=\"faq-item\" data-faq>\r\n      <button class=\"faq-q\" type=\"button\"\r\n              data-toggle=\"collapse\"\r\n              data-target=\"#accordion-tab-4-content-3\">\r\n        Can I arrange for the car to be delivered to the airport?\r\n        <span class=\"faq-plus\">+</span>\r\n      </button>\r\n\r\n      <div class=\"collapse\"\r\n           id=\"accordion-tab-4-content-3\"\r\n           data-parent=\"#accordion-tab-4\">\r\n        <div class=\"faq-a\">\r\n          <p>Yes, you can request airport pickup for your vehicle. Please inform us in advance when booking.</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n</div>\r\n\r\n\r\n\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n</section>', 1, 2, 8, 1, 1, 1, 1725602972, 1, 1773663484, 0, 0, 0, 1725602940, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'faq.html', 0, 0, 1, NULL, 1);
INSERT INTO `modx_site_content` (`id`, `type`, `pagetitle`, `longtitle`, `description`, `alias`, `link_attributes`, `published`, `pub_date`, `unpub_date`, `parent`, `isfolder`, `introtext`, `content`, `richtext`, `template`, `menuindex`, `searchable`, `cacheable`, `createdby`, `createdon`, `editedby`, `editedon`, `deleted`, `deletedon`, `deletedby`, `publishedon`, `publishedby`, `menutitle`, `donthit`, `privateweb`, `privatemgr`, `content_dispo`, `hidemenu`, `class_key`, `context_key`, `content_type`, `uri`, `uri_override`, `hide_children_in_tree`, `show_in_tree`, `properties`, `alias_visible`) VALUES
(11, 'document', 'wedding', 'Congratulations!', '', 'transfer', '', 1, 0, 0, 0, 0, '', '\r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n \r\n<section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/breadcrumb/sr_bc_rentacar.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n    <div class=\"overlay\"></div>\r\n    <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Transfer</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Transfer<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n    </div>\r\n</section>\r\n      \r\n<section class=\"about-section\">\r\n	<div class=\"container\">\r\n	<div class=\"row clearfix\">\r\n		\r\n	<!--Content Column-->\r\n	<div class=\"content-column col-md-6 col-sm-12 col-xs-12 align-items-center d-flex\">\r\n		<div class=\"inner-column\">\r\n			<div class=\"sec-title\">\r\n				<h2 style=\"font-size: 30px; color: #a40000; font-weight: bold;\">Enjoy a Smooth Journey</h2>\r\n			</div>\r\n			<div class=\"text\" style=\"text-align: justify;\">\r\n				Enhance your Sri Lankan experience with SR Rent A Car\'s premium chauffeur-driven airport and hotel transfers. Our fleet of luxurious vehicles, coupled with our professional and experienced chauffeurs, ensures a comfortable and stylish travel experience.\r\n			</div>\r\n			<div class=\"text\" style=\"text-align: justify;\">\r\n				From the moment you land at Colombo International Airport (CMB), our Meet and Greet service welcomes you with a warm and efficient reception. Our drivers will escort you to your chosen vehicle and assist you throughout your journey.\r\n			</div>\r\n			<div class=\"text\" style=\"text-align: justify;\">\r\n				Whether you\'re heading to your hotel or embarking on a sightseeing adventure, our reliable and punctual transfer services provide the freedom and convenience you need. Book your airport transfer with SR Rent A Car today and experience the difference.\r\n			</div>\r\n						\r\n	\r\n			<a href=\"https://srilankatransfer.lk/booking.html\" target = \"_blank\"class=\"theme-btn btn-style-three\">Book a Transfer</a>\r\n		</div>\r\n	</div>\r\n	<!--Image Column-->\r\n	<div class=\"image-column col-md-6 col-sm-12 col-xs-12\">\r\n		<div class=\"inner-column \" data-wow-delay=\"0ms\" data-wow-duration=\"1500ms\">\r\n			<div class=\"image\">\r\n				<img src=\"assets/images/wedding/transfer.jpg\" alt=\"\">\r\n				<div class=\"overlay-box\">\r\n				<div class=\"year-box\"><span class=\"number\">20</span>Years <br> industry  <br> Expertise</div>\r\n				</div>\r\n			</div>\r\n			</div>\r\n		</div>\r\n	\r\n		</div>\r\n	</div>\r\n</section>\r\n      \r\n<section class=\"transfer-section\">\r\n	<div class=\"container\">\r\n\r\n		<!-- Heading -->\r\n		<div class=\"transfer-heading text-center\">\r\n		<span class=\"transfer-subtitle\">Transfers</span>\r\n		<h2 class=\"transfer-title\">Our Transfer Services</h2>\r\n		<p class=\"transfer-lead\">\r\n			Chauffeur-driven Airport Transfers and Hotel Transfers across Sri Lanka — including Colombo International Airport (CMB) and all hotels islandwide.\r\n		</p>\r\n		</div>\r\n\r\n		<!-- Top highlight cards -->\r\n		<div class=\"row g-4 transfer-highlights\">\r\n		<div class=\"col-12 col-lg-6\">\r\n			<div class=\"transfer-highlight\">\r\n			<div class=\"th-icon\">✈</div>\r\n			<div class=\"th-content\">\r\n				<h4>Seamless Airport Transfers</h4>\r\n				<p>\r\n				Arrive in style and comfort with our 24/7 private airport transfer service.\r\n				Your chauffeur greets you at Bandaranaike International Airport (CMB) with a personalized sign\r\n				and escorts you directly to your destination.\r\n				</p>\r\n			</div>\r\n			</div>\r\n		</div>\r\n\r\n		<div class=\"col-12 col-lg-6\">\r\n			<div class=\"transfer-highlight\">\r\n			<div class=\"th-icon\">🏨</div>\r\n			<div class=\"th-content\">\r\n				<h4>Hassle-Free Hotel Transfers</h4>\r\n				<p>\r\n				Already in Sri Lanka? Book a hotel transfer and enjoy a smooth ride to your next destination.\r\n				Your chauffeur picks you up right from your hotel doorstep.\r\n				</p>\r\n			</div>\r\n			</div>\r\n		</div>\r\n		</div>\r\n\r\n		<!-- Info block -->\r\n		<div class=\"transfer-info\">\r\n		<h3 class=\"transfer-info-title\">Luxury Chauffeur Service, 24/7 Support</h3>\r\n		<p>\r\n			SR Rent A Car offers chauffeur-driven Airport Transfers and Hotel Transfers in Sri Lanka. We offer our service for\r\n			Colombo International Airport (CMB) & all hotels in Sri Lanka. Our helpful chauffeurs and luxury fleet ensure a professional\r\n			service. Our well-maintained vehicle categories let you choose the right option for your journey. You can contact our helpful\r\n			staff members 24/7 to clarify any information.\r\n		</p>\r\n		<p>\r\n			We provide efficient and reliable airport transfers in Sri Lanka and take pride in our Meet & Greet service at CMB.\r\n			On arrival, you will meet one of our professional and experienced chauffeurs. He’ll escort you to your car and assist you\r\n			throughout your journey.\r\n		</p>\r\n		<p>\r\n			SR Rent A Car provides a stylish and comfortable journey without relying on public transport and gives you flexibility to explore places\r\n			of your choice right from the airport. A single phone call or email will have your transfer vehicle ready. If you’re looking for reliable\r\n			chauffeur service in safety, comfort and style, book your airport car rental with SR Rent A Car today.\r\n		</p>\r\n		</div>\r\n\r\n		<!-- Main service cards -->\r\n		<div class=\"row g-4 mt-4\">\r\n		<div class=\"col-12 col-lg-6\">\r\n			<div class=\"transfer-card\">\r\n			<div class=\"transfer-card-head\">\r\n				<div class=\"tc-badge\">Airport</div>\r\n				<h3>Airport Transfers</h3>\r\n			</div>\r\n\r\n			<p>\r\n				SR Transfers can arrange airport transfers from Bandaranaike International Airport (Colombo Airport [CMB])\r\n				to many destinations in Sri Lanka. We provide a 24/7 private airport transfer service catering to all your requirements.\r\n				Your chauffeur will greet you at the arrival lobby with a paging board showing your name.\r\n			</p>\r\n\r\n			<div class=\"transfer-actions\">\r\n				<a class=\"transfer-btn\" href=\"tel:+94773207108\">Call (+94) 773 207 108</a>\r\n				<a class=\"transfer-link\" href=\"#\">Get a Quote →</a>\r\n			</div>\r\n			</div>\r\n		</div>\r\n\r\n		<div class=\"col-12 col-lg-6\">\r\n			<div class=\"transfer-card\">\r\n			<div class=\"transfer-card-head\">\r\n				<div class=\"tc-badge\">Hotel</div>\r\n				<h3>Hotel Transfers</h3>\r\n			</div>\r\n\r\n			<p>\r\n				If you are already in the country and need secure transportation to move among destinations, you can book a transfer\r\n				from SR Transfers. We’ll send a chauffeur-driven vehicle to your hotel doorstep to pick you up.\r\n			</p>\r\n\r\n			<div class=\"transfer-actions\">\r\n				<a class=\"transfer-btn\" href=\"tel:+94773207108\">Call (+94) 773 207 108</a>\r\n				<a class=\"transfer-link\" href=\"#\">Get a Quote →</a>\r\n			</div>\r\n			</div>\r\n		</div>\r\n		</div>\r\n\r\n	</div>\r\n</section>\r\n            \r\n<section class=\"transfer-features\">\r\n  <div class=\"container\">\r\n\r\n    <!-- Section Header -->\r\n    <div class=\"text-center mb-5\">\r\n      <span class=\"tf-sub\">Why Choose Us</span>\r\n      <h2 class=\"tf-title\">Premium Transfer Experience</h2>\r\n      <p class=\"tf-lead\">\r\n        We combine professionalism, safety, and reliability to deliver a seamless\r\n        chauffeur-driven experience across Sri Lanka.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"row g-4\">\r\n\r\n      <!-- 1 -->\r\n      <div class=\"col-12 col-sm-6 col-lg-4\">\r\n        <div class=\"tf-card\">\r\n          <div class=\"tf-icon\"><i class=\"fas fa-briefcase\"></i></div>\r\n          <h4>Highly Professional Services</h4>\r\n          <p>\r\n            We provide exceptional private transfer services for visitors arriving\r\n            or departing Sri Lanka. Fast, reliable, comfortable, and convenient.\r\n          </p>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 2 -->\r\n      <div class=\"col-12 col-sm-6 col-lg-4\">\r\n        <div class=\"tf-card\">\r\n          <div class=\"tf-icon\"><i class=\"fas fa-star\"></i></div>\r\n          <h4>Quality Customer Services</h4>\r\n          <p>\r\n            Customer satisfaction is our priority. We ensure a smooth,\r\n            comfortable and stress-free experience tailored to your needs.\r\n          </p>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 3 -->\r\n      <div class=\"col-12 col-sm-6 col-lg-4\">\r\n        <div class=\"tf-card\">\r\n          <div class=\"tf-icon\"><i class=\"fas fa-clock\"></i></div>\r\n          <h4>Reliable & Punctual</h4>\r\n          <p>\r\n            We monitor flight arrivals to ensure timely pickups. Our services\r\n            are prompt, punctual, and dependable.\r\n          </p>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 4 -->\r\n      <div class=\"col-12 col-sm-6 col-lg-4 mt-4\">\r\n        <div class=\"tf-card\">\r\n          <div class=\"tf-icon\"><i class=\"fas fa-users\"></i></div>\r\n          <h4>Well-Trained Team</h4>\r\n          <p>\r\n            Our professional drivers have extensive knowledge of Colombo and\r\n            major cities, ensuring a smooth and enjoyable journey.\r\n          </p>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 5 -->\r\n      <div class=\"col-12 col-sm-6 col-lg-4 mt-4\">\r\n        <div class=\"tf-card\">\r\n          <div class=\"tf-icon\"><i class=\"fas fa-shield-alt\"></i></div>\r\n          <h4>High Safety Standards</h4>\r\n          <p>\r\n            We maintain secure, well-serviced vehicles and experienced drivers\r\n            to guarantee maximum safety and comfort.\r\n          </p>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- 6 -->\r\n      <div class=\"col-12 col-sm-6 col-lg-4 mt-4\">\r\n        <div class=\"tf-card\">\r\n          <div class=\"tf-icon\"><i class=\"fas fa-headset\"></i></div>\r\n          <h4>24/7 Availability</h4>\r\n          <p>\r\n            Our transfer services operate around the clock — including weekends\r\n            and public holidays.\r\n          </p>\r\n        </div>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n</section>', 1, 2, 9, 1, 1, 1, 1725626063, 1, 1772517776, 0, 0, 0, 1725626040, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'transfer.html', 0, 0, 1, NULL, 1),
(12, 'document', 'Valid Driving Licenses To Rent A Car In Sri Lanka', 'Congratulations!', '', 'valid-driving-licenses-to-rent-a-car-in-sri-lanka', '', 1, 0, 0, 0, 0, '', '\r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n\r\n\r\n<section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n  <div class=\"overlay\"></div>\r\n  <div class=\"container\">\r\n    <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n      <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n        <h1 class=\"mb-2 bread\">Blog</h1>\r\n        <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\">\r\n          <span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span>\r\n          <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span>\r\n        </p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"blog-modern py-5\">\r\n  <div class=\"container\">\r\n    <div class=\"row\">\r\n\r\n      <!-- MAIN CONTENT -->\r\n      <div class=\"col-lg-8\">\r\n        <article class=\"blog-card\">\r\n\r\n          <!-- HEADER -->\r\n          <header class=\"blog-header\">\r\n            <div class=\"meta-row\">\r\n              <span><i class=\"far fa-calendar\"></i> Nov 01, 2021</span>\r\n              <span><i class=\"fas fa-id-card\"></i> Legal Requirements</span>\r\n              <span><i class=\"fas fa-car\"></i> Car Rental</span>\r\n            </div>\r\n\r\n            <h1>Valid Driving Licenses To Rent A Car In Sri Lanka</h1>\r\n\r\n            <img src=\"assets/images/blog/driving_license.jpg\"\r\n                 class=\"img-fluid blog-hero-img\"\r\n                 alt=\"Driving License Sri Lanka\">\r\n          </header>\r\n\r\n          <div class=\"blog-content\">\r\n\r\n            <p>\r\n              Planning to rent a car in Sri Lanka? Whether you\'re visiting for a short holiday\r\n              or staying long-term, having the correct driving license is legally required.\r\n            </p>\r\n\r\n            <div class=\"highlight-box\">\r\n              A valid driving license is mandatory to drive any motor vehicle in Sri Lanka.\r\n            </div>\r\n\r\n            <!-- LICENSE TYPES -->\r\n            <h2>Accepted Driving Licenses</h2>\r\n\r\n            <div class=\"license-grid\">\r\n\r\n              <div class=\"license-card\">\r\n                <h3>International Driving Permit (IDP)</h3>\r\n                <p>\r\n                  Must be endorsed locally before driving.\r\n                </p>\r\n              </div>\r\n\r\n              <div class=\"license-card\">\r\n                <h3>Temporary Sri Lankan Driving Licence (TSDL)</h3>\r\n                <p>\r\n                  Issued for short stays (1–6 months).\r\n                </p>\r\n              </div>\r\n\r\n              <div class=\"license-card\">\r\n                <h3>Regular Sri Lankan Driving Licence</h3>\r\n                <p>\r\n                  Available for Sri Lankan residents and long-term visa holders.\r\n                </p>\r\n              </div>\r\n\r\n            </div>\r\n\r\n            <div class=\"info-box\">\r\n              SR Rent A Car can arrange the entire process for you.\r\n              Send documents at least one week before arrival.\r\n            </div>\r\n\r\n            <!-- IDP SECTION -->\r\n            <h2 class=\"mt-5\">How to Get IDP Endorsed in Sri Lanka</h2>\r\n\r\n            <p>\r\n              Sri Lanka recognizes all IDP types (1926, 1949, 1968 conventions),\r\n              but requires endorsement from the Automobile Association (AA) of Ceylon.\r\n            </p>\r\n\r\n            <div class=\"checklist\">\r\n              <ul>\r\n                <li>Copy of IDP (front + photo page)</li>\r\n                <li>Passport copy</li>\r\n                <li>Passport-size photograph</li>\r\n              </ul>\r\n            </div>\r\n\r\n            <div class=\"warning-box\">\r\n              IDP alone is NOT valid without local endorsement.\r\n            </div>\r\n\r\n            <!-- TSDL SECTION -->\r\n            <h2 class=\"mt-5\">Temporary Sri Lankan Driving Licence (TSDL)</h2>\r\n\r\n            <p>\r\n              Issued by the Department of Motor Vehicles (DMV) in Werahara.\r\n              Valid for light vehicle categories only.\r\n            </p>\r\n\r\n            <div class=\"checklist\">\r\n              <ul>\r\n                <li>Copy of country license (front & back)</li>\r\n                <li>Passport copy</li>\r\n                <li>Passport-size photograph</li>\r\n              </ul>\r\n            </div>\r\n\r\n            <!-- REGULAR LICENSE -->\r\n            <h2 class=\"mt-5\">Regular Sri Lankan Driving Licence</h2>\r\n\r\n            <p>\r\n              Available to residents and long-term visa holders.\r\n              Application must be made through the DMV.\r\n            </p>\r\n\r\n            <div class=\"highlight-box\">\r\n              Non-English licenses must be translated by an embassy or certified translator.\r\n            </div>\r\n\r\n            <!-- CTA -->\r\n            <div class=\"cta-box-modern\">\r\n              <h2 class=\"text-white\">Need Help With License Processing?</h2>\r\n              <p class=\"text-white\">We can arrange endorsements or temporary licenses before your arrival.</p>\r\n              <a href=\"[[~9]]\" class=\"cta-btn-main\">\r\n                <i class=\"fas fa-phone\"></i> Contact Us\r\n              </a>\r\n            </div>\r\n\r\n          </div>\r\n        </article>\r\n      </div>\r\n\r\n      <!-- SIDEBAR -->\r\n      <div class=\"col-lg-4\">\r\n        <aside class=\"sidebar-modern\">\r\n\r\n          <h5>Previous Blogs</h5>\r\n\r\n          <a href=\"[[~8]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\"\r\n                 style=\"background-image:url(assets/images/blog/hidden_gems.jpg)\"></div>\r\n            <div>\r\n              <span>Hidden Gems near Kandy</span>\r\n              <small>Sep 20, 2023</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~13]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\"\r\n                 style=\"background-image:url(assets/images/blog/road_sign.jpg)\"></div>\r\n            <div>\r\n              <span>Traffic Rules Guide</span>\r\n              <small>Oct 27, 2021</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~14]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\"\r\n                 style=\"background-image:url(assets/images/blog/drive_road.jpg)\"></div>\r\n            <div>\r\n              <span>Travel at Your Own Pace</span>\r\n              <small>Apr 19, 2024</small>\r\n            </div>\r\n          </a>\r\n\r\n        </aside>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n</section>\r\n', 1, 2, 10, 1, 1, 1, 1725744932, 1, 1772530032, 0, 0, 0, 1725744900, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'valid-driving-licenses-to-rent-a-car-in-sri-lanka.html', 0, 0, 1, NULL, 1),
(13, 'document', 'traffic_guide', 'Congratulations!', '', 'traffic-guide', '', 1, 0, 0, 0, 0, '', '  \r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n      <div class=\"overlay\"></div>\r\n      <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Blog</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n        \r\n  <section class=\"blog-modern py-5\">\r\n  <div class=\"container\">\r\n    <div class=\"row\">\r\n\r\n      <!-- MAIN CONTENT -->\r\n      <div class=\"col-lg-9\">\r\n        <article class=\"blog-card\">\r\n\r\n          <!-- HERO -->\r\n          <header class=\"blog-header\">\r\n            <div class=\"meta-row\">\r\n              <span><i class=\"far fa-calendar\"></i> Oct 27, 2021</span>\r\n              <span><i class=\"fas fa-user\"></i> Sri Lanka Travel Guide</span>\r\n              <span><i class=\"fas fa-road\"></i> Driving Rules</span>\r\n            </div>\r\n\r\n            <h1>Essential Guide to Sri Lanka’s Traffic Rules for Drivers</h1>\r\n\r\n            <img src=\"assets/images/blog/road_sign.jpg\" class=\"img-fluid blog-hero-img\" alt=\"\">\r\n          </header>\r\n\r\n          <!-- INTRO -->\r\n          <div class=\"blog-content\">\r\n            <p>\r\n              If you’re planning a trip to Sri Lanka and want to explore the country at your own pace,\r\n              renting a car is one of the best options. However, understanding local traffic laws is essential\r\n              for a safe and stress-free journey.\r\n            </p>\r\n\r\n            <div class=\"highlight-box\">\r\n              <strong>Important:</strong>\r\n              Sri Lanka drives on the <b>left-hand side</b> of the road.\r\n            </div>\r\n\r\n            <h2>Traffic Rules Every Driver Must Know</h2>\r\n\r\n            <!-- RULE BLOCK -->\r\n            <div class=\"rule-block\">\r\n              <h3>01. Speed Limits</h3>\r\n              <ul>\r\n                <li><strong>Urban Areas:</strong> 0–50 km/h</li>\r\n                <li><strong>Rural Areas:</strong> 0–70 km/h</li>\r\n                <li><strong>Highways:</strong> 80–100 km/h</li>\r\n              </ul>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>02. No Driving Under Influence</h3>\r\n              <ul>\r\n                <li>Driving under alcohol or drugs is illegal.</li>\r\n                <li>Violations lead to severe penalties.</li>\r\n                <li>Use a designated driver if needed.</li>\r\n              </ul>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>03. Avoid Using Mobile Phones</h3>\r\n              <ul>\r\n                <li>Mobile use while driving is illegal.</li>\r\n                <li>Pull over safely before making calls.</li>\r\n              </ul>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>04. Obey Road Signs</h3>\r\n              <p>Always follow road signs carefully. Ignoring them may result in fines or accidents.</p>\r\n            </div>\r\n\r\n            <!-- ROAD SIGN GALLERY -->\r\n            <h2 class=\"mt-5\">Common Road Signs</h2>\r\n\r\n            <div class=\"road-sign-grid\">\r\n              <img src=\"assets/images/blog/news/road_sign/1.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/2.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/3.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/4.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/5.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/6.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/7.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/8.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/9.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/10.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/11.jpg\">\r\n              <img src=\"assets/images/blog/news/road_sign/12.jpg\">\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>05. Traffic Lights</h3>\r\n              <ul>\r\n                <li><strong>Red:</strong> Stop</li>\r\n                <li><strong>Yellow:</strong> Slow down</li>\r\n                <li><strong>Green:</strong> Go</li>\r\n                <li><strong>Green Arrow:</strong> Turn only as indicated</li>\r\n              </ul>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>06. Keep Left</h3>\r\n              <p>Always drive on the left side of the road.</p>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>07. Use Indicators</h3>\r\n              <p>Signal clearly when turning or changing lanes.</p>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>08. Maintain Safe Distance</h3>\r\n              <p>Keep at least 2 seconds distance from the vehicle ahead.</p>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>09. Give Way to Pedestrians</h3>\r\n              <p>Pedestrians always have priority at zebra crossings.</p>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>10. Emergency Vehicles</h3>\r\n              <p>Move aside immediately when you hear sirens.</p>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>11. Lane Discipline</h3>\r\n              <p>Keep left unless overtaking. Avoid zig-zag driving.</p>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>12. Watch for Animals</h3>\r\n              <p>Especially in rural areas.</p>\r\n            </div>\r\n\r\n            <div class=\"rule-block\">\r\n              <h3>13. Valid Driving License</h3>\r\n              <p>Foreign drivers must hold a valid international permit or Sri Lanka temporary license.</p>\r\n            </div>\r\n\r\n            <div class=\"blog-conclusion\">\r\n              <h2>Final Thoughts</h2>\r\n              <p>\r\n                Following these traffic rules ensures safety, avoids fines, and makes your journey\r\n                across Sri Lanka smooth and enjoyable.\r\n              </p>\r\n            </div>\r\n\r\n          </div>\r\n        </article>\r\n      </div>\r\n\r\n      <!-- SIDEBAR -->\r\n      <div class=\"col-lg-3\">\r\n        <div class=\"sidebar-modern\">\r\n          <h5>Previous Blogs</h5>\r\n\r\n          <a href=\"[[~7]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/hidden_gems.jpg)\"></div>\r\n            <div>\r\n              <span>Hidden Gems near Kandy</span>\r\n              <small>Sep 20, 2023</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~12]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/driving_license.jpg)\"></div>\r\n            <div>\r\n              <span>Valid Driving Licenses</span>\r\n              <small>Nov 01, 2021</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~14]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/drive_road.jpg)\"></div>\r\n            <div>\r\n              <span>Travel at Your Own Pace</span>\r\n              <small>Apr 19, 2024</small>\r\n            </div>\r\n          </a>\r\n\r\n        </div>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n</section>\r\n    ', 1, 2, 11, 1, 1, 1, 1726211301, 1, 1772528641, 0, 0, 0, 1726211280, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'traffic-guide.html', 0, 0, 1, NULL, 1),
(14, 'document', 'How to travel in Sri Lanka at your own pace', 'Congratulations!', '', 'how-to-travel-in-sri-lanka-at-your-own-pace', '', 1, 0, 0, 0, 0, '', '  \r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n      <div class=\"overlay\"></div>\r\n      <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Blog</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n        \r\n  <section class=\"blog-modern py-5\">\r\n  <div class=\"container\">\r\n    <div class=\"row\">\r\n\r\n      <!-- MAIN CONTENT -->\r\n      <div class=\"col-lg-9\">\r\n        <article class=\"blog-card\">\r\n\r\n          <!-- HEADER -->\r\n          <header class=\"blog-header\">\r\n            <div class=\"meta-row\">\r\n              <span><i class=\"far fa-calendar\"></i> April 19, 2024</span>\r\n              <span><i class=\"fas fa-map-marked-alt\"></i> Travel Guide</span>\r\n              <span><i class=\"fas fa-car\"></i> Transportation</span>\r\n            </div>\r\n\r\n            <h1>How to Travel in Sri Lanka at Your Own Pace?</h1>\r\n\r\n            <img src=\"assets/images/blog/drive_road.jpg\" class=\"img-fluid blog-hero-img\" alt=\"\">\r\n          </header>\r\n\r\n          <div class=\"blog-content\">\r\n\r\n            <p>\r\n              If you’re planning to explore Sri Lanka freely and without restrictions,\r\n              choosing the right transportation method is crucial.\r\n              Let’s compare your main options.\r\n            </p>\r\n\r\n            <div class=\"highlight-box\">\r\n              Want flexibility, comfort, and freedom? Your choice of transport makes all the difference.\r\n            </div>\r\n\r\n            <!-- OPTION 1 -->\r\n            <div class=\"transport-card\">\r\n              <div class=\"transport-icon\">🚌</div>\r\n              <div>\r\n                <h3>01. Public Transportation (Buses & Trains)</h3>\r\n                <p>Cheapest way to travel across Sri Lanka.</p>\r\n                <ul>\r\n                  <li>Low cost</li>\r\n                  <li>Authentic local experience</li>\r\n                  <li>Limited flexibility</li>\r\n                  <li>Can be crowded & time-consuming</li>\r\n                </ul>\r\n              </div>\r\n            </div>\r\n\r\n            <!-- OPTION 2 -->\r\n            <div class=\"transport-card\">\r\n              <div class=\"transport-icon\">🚕</div>\r\n              <div>\r\n                <h3>02. Third-Party Taxi Services (Uber / PickMe)</h3>\r\n                <p>Convenient for city travel.</p>\r\n                <ul>\r\n                  <li>Available in major cities</li>\r\n                  <li>Affordable for short distances</li>\r\n                  <li>Limited availability outside cities</li>\r\n                  <li>Occasional ride cancellations</li>\r\n                </ul>\r\n              </div>\r\n            </div>\r\n\r\n            <!-- OPTION 3 -->\r\n            <div class=\"transport-card\">\r\n              <div class=\"transport-icon\">🛺</div>\r\n              <div>\r\n                <h3>03. Private Tuk-Tuk</h3>\r\n                <p>Very common and easily accessible.</p>\r\n                <ul>\r\n                  <li>High availability</li>\r\n                  <li>Great for short trips</li>\r\n                  <li>Limited comfort</li>\r\n                  <li>Not ideal for long distances or luggage</li>\r\n                </ul>\r\n              </div>\r\n            </div>\r\n\r\n            <!-- BEST OPTION -->\r\n            <div class=\"best-option\">\r\n              <h2 class=\"text-white\">04. Rent a Car – The Most Flexible Option</h2>\r\n\r\n              <p class=\"text-white\">\r\n                Renting a vehicle gives you complete freedom to explore Sri Lanka at your own pace.\r\n                Unlike other options, you are not restricted by schedules or driver availability.\r\n              </p>\r\n\r\n              <ul>\r\n                <li>Drive yourself or hire a chauffeur</li>\r\n                <li>Choose from a wide range of vehicles</li>\r\n                <li>Daily & monthly rental options</li>\r\n                <li>Book before arriving in Sri Lanka</li>\r\n                <li>Ideal for families & long-distance travel</li>\r\n              </ul>\r\n\r\n              <div class=\"cta-box text-white\">\r\n                <h4 class=\"text-white\">Explore Sri Lanka Your Way</h4>\r\n                <p class=\"text-white\">Book your rental vehicle today and travel stress-free.</p>\r\n                <a href=\"[[~9]]\" class=\"cta-btn-main\">\r\n                  <i class=\"fas fa-car\"></i> View Rental Options\r\n                </a>\r\n              </div>\r\n            </div>\r\n\r\n            <div class=\"blog-conclusion mt-3\">\r\n              <h2>Final Recommendation</h2>\r\n              <p>\r\n                While public transportation is budget-friendly,\r\n                renting a vehicle offers unmatched flexibility, comfort,\r\n                and control over your travel experience.\r\n              </p>\r\n            </div>\r\n\r\n          </div>\r\n        </article>\r\n      </div>\r\n\r\n      <!-- SIDEBAR -->\r\n      <div class=\"col-lg-3\">\r\n        <aside class=\"sidebar-modern\">\r\n          <h5>Previous Blogs</h5>\r\n\r\n          <a href=\"[[~7]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/hidden_gems.jpg)\"></div>\r\n            <div>\r\n              <span>Hidden Gems near Kandy</span>\r\n              <small>Sep 20, 2023</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~12]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/driving_license.jpg)\"></div>\r\n            <div>\r\n              <span>Valid Driving Licenses</span>\r\n              <small>Nov 01, 2021</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~13]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/road_sign.jpg)\"></div>\r\n            <div>\r\n              <span>Traffic Rules Guide</span>\r\n              <small>Oct 27, 2021</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~15]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/short_term.jpg)\"></div>\r\n            <div>\r\n              <span>How to Rent a Car</span>\r\n              <small>Jun 21, 2021</small>\r\n            </div>\r\n          </a>\r\n\r\n        </aside>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n</section>', 1, 2, 12, 1, 1, 1, 1726214455, 1, 1772528997, 0, 0, 0, 1726214400, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'how-to-travel-in-sri-lanka-at-your-own-pace.html', 0, 0, 1, NULL, 1),
(15, 'document', 'How to Rent a Car in Sri Lanka', 'Congratulations!', '', 'how-to-rent-a-car-in-sri-lanka', '', 1, 0, 0, 0, 0, '', '  \r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/home/breadcrumb.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n      <div class=\"overlay\"></div>\r\n      <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n          <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n            <h1 class=\"mb-2 bread\">Blog</h1>\r\n            <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span><a href=\"[[~5]]\">Blog</a> <i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n        \r\n <section class=\"blog-modern py-5\">\r\n  <div class=\"container\">\r\n    <div class=\"row\">\r\n\r\n      <!-- MAIN CONTENT -->\r\n      <div class=\"col-lg-9\">\r\n        <article class=\"blog-card\">\r\n\r\n          <!-- HEADER -->\r\n          <header class=\"blog-header\">\r\n            <div class=\"meta-row\">\r\n              <span><i class=\"far fa-calendar\"></i> June 21, 2021</span>\r\n              <span><i class=\"fas fa-car\"></i> Car Rental Guide</span>\r\n              <span><i class=\"fas fa-map\"></i> Sri Lanka</span>\r\n            </div>\r\n\r\n            <h1>How to Rent a Car in Sri Lanka: Step-by-Step Process</h1>\r\n\r\n            <img src=\"assets/images/blog/short_term.jpg\" class=\"img-fluid blog-hero-img\" alt=\"\">\r\n          </header>\r\n\r\n          <div class=\"blog-content\">\r\n\r\n            <p>\r\n              Thinking about renting a car in Sri Lanka? Here’s everything you need\r\n              to know to ensure a smooth and stress-free rental experience.\r\n            </p>\r\n\r\n            <!-- PROCESS STEPS -->\r\n            <div class=\"process-wrapper\">\r\n\r\n              <div class=\"process-step\">\r\n                <div class=\"step-number\">01</div>\r\n                <div>\r\n                  <h3>Have a Valid Driving License</h3>\r\n                  <p>\r\n                    Foreign drivers must carry:\r\n                  </p>\r\n                  <ul>\r\n                    <li>International Driving Permit (IDP)</li>\r\n                    <li>Sri Lanka Temporary Driving Permit (issued locally)</li>\r\n                  </ul>\r\n\r\n                  <div class=\"highlight-box\">\r\n                    International license alone is NOT sufficient under Sri Lankan law.\r\n                  </div>\r\n\r\n                  <img src=\"assets/images/blog/driving_license.jpg\" class=\"img-fluid rounded mt-3\">\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"process-step\">\r\n                <div class=\"step-number\">02</div>\r\n                <div>\r\n                  <h3>Submit Passport Copy</h3>\r\n                  <p>\r\n                    A valid passport is required as proof of identity while driving in Sri Lanka.\r\n                  </p>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"process-step\">\r\n                <div class=\"step-number\">03</div>\r\n                <div>\r\n                  <h3>Age Verification</h3>\r\n                  <ul>\r\n                    <li>Minimum driving age: 18 years</li>\r\n                    <li>Minimum rental age: 21 years</li>\r\n                  </ul>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"process-step\">\r\n                <div class=\"step-number\">04</div>\r\n                <div>\r\n                  <h3>Select Your Vehicle</h3>\r\n                  <p>\r\n                    Choose based on budget, number of passengers, luggage, and travel distance.\r\n                  </p>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"process-step\">\r\n                <div class=\"step-number\">05</div>\r\n                <div>\r\n                  <h3>Submit Payment & Deposit</h3>\r\n                  <ul>\r\n                    <li>Credit card required</li>\r\n                    <li>Refundable security deposit applies</li>\r\n                  </ul>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"process-step\">\r\n                <div class=\"step-number\">06</div>\r\n                <div>\r\n                  <h3>Inspect Vehicle at Pickup</h3>\r\n                  <p>\r\n                    Check the vehicle thoroughly and sign inspection documents.\r\n                  </p>\r\n                </div>\r\n              </div>\r\n\r\n              <div class=\"process-step\">\r\n                <div class=\"step-number\">07</div>\r\n                <div>\r\n                  <h3>Return Vehicle on Time</h3>\r\n                  <p>\r\n                    SR Rent A Car operates 24/7. Late returns may incur additional charges.\r\n                  </p>\r\n                </div>\r\n              </div>\r\n\r\n            </div>\r\n\r\n            <!-- CTA -->\r\n            <div class=\"cta-box-modern\">\r\n              <h2>Ready to Book Your Vehicle?</h2>\r\n              <p>Explore our fleet and reserve your car before arriving in Sri Lanka.</p>\r\n              <a href=\"[[~4]]\" class=\"cta-btn-main\">\r\n                <i class=\"fas fa-car\"></i> Browse Vehicles\r\n              </a>\r\n            </div>\r\n\r\n          </div>\r\n        </article>\r\n      </div>\r\n\r\n      <!-- SIDEBAR -->\r\n      <div class=\"col-lg-3\">\r\n        <aside class=\"sidebar-modern\">\r\n          <h5>Previous Blogs</h5>\r\n\r\n          <a href=\"[[~7]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/hidden_gems.jpg)\"></div>\r\n            <div>\r\n              <span>Hidden Gems near Kandy</span>\r\n              <small>Sep 20, 2023</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~12]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/driving_license.jpg)\"></div>\r\n            <div>\r\n              <span>Driving License Requirements</span>\r\n              <small>Nov 01, 2021</small>\r\n            </div>\r\n          </a>\r\n\r\n          <a href=\"[[~13]]\" class=\"side-item\">\r\n            <div class=\"side-thumb\" style=\"background-image:url(assets/images/blog/road_sign.jpg)\"></div>\r\n            <div>\r\n              <span>Traffic Rules Guide</span>\r\n              <small>Oct 27, 2021</small>\r\n            </div>\r\n          </a>\r\n\r\n        </aside>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n</section>\r\n        \r\n    ', 1, 2, 13, 1, 1, 1, 1726215527, 1, 1772529494, 0, 0, 0, 1726215480, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'how-to-rent-a-car-in-sri-lanka.html', 0, 0, 1, NULL, 1);
