(16, 'document', 'registration', 'Congratulations!', '', 'index', '', 1, 0, 0, 0, 0, '', '  \r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/breadcrumb/sr_bc_fleet.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n		<div class=\"overlay\"></div>\r\n		<div class=\"container\">\r\n		  <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n			<div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n			  <h1 class=\"mb-2 bread\">Reserve A Car</h1>\r\n			  <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Reserve A Car<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n			</div>\r\n		  </div>\r\n		</div>\r\n	  </section>\r\n\r\n	  <section class=\"ftco-section ftco-no-pt ftco-no-pb\">\r\n		<div class=\"container-fluid px-0\">\r\n           \r\n		  <div class=\"row d-flex no-gutters\">\r\n			<div class=\"col-md-12 order-md-last ftco-animate makereservation p-4 p-md-5 pt-5\">\r\n				<h3 id=\"carName\" class=\"text-center\"><P>You Selected</P></h3>\r\n			  <div class=\"py-md-5\">\r\n				<form action=\"#\">\r\n				  <div class=\"row\">\r\n					<div class=\"col-md-6\">\r\n					  <div class=\"form-group\">\r\n						<label for=\"\">Your Name</label>\r\n						<input type=\"text\" class=\"form-control\" placeholder=\"Your Name\">\r\n					  </div>\r\n					</div>\r\n					<div class=\"col-md-6\">\r\n					  <div class=\"form-group\">\r\n						<label for=\"\">Your email address</label>\r\n						<input type=\"text\" class=\"form-control\" placeholder=\"Your Email\">\r\n					  </div>\r\n					</div>\r\n					<div class=\"col-md-6\">\r\n						\r\n						<div class=\"form-group\">\r\n						  <label for=\"country-code\">Your contact number</label>\r\n						  <div class=\"input-group\">\r\n							<select id=\"country-code\" class=\"form-control\">\r\n								<option value=\"+1\">USA (+1)</option>\r\n							