value=\"\">SR  Rent A Car Office Seeduwa</option>\r\n							<option value=\"\">Colombo Hotel</option>\r\n							<option value=\"\">Negombo Hotel</option>\r\n							<option value=\"\">Beruwala Hotel</option>\r\n							<option value=\"\">Benthota Hotel</option>\r\n							<option value=\"\">Galle Hotel</option>\r\n							<option value=\"\">Kandy Hotel</option>\r\n							<option value=\"\">Nuwara Eliya Hotel</option>\r\n							<option value=\"\">Jaffna Hotel</option>\r\n							<option value=\"\">Other Locations</option>\r\n						  </select>\r\n						</div>\r\n					  </div>\r\n					  </div>\r\n					 \r\n\r\n					  <div class=\"col-md-6\">\r\n				 <div class=\"form-group\">\r\n						<label for=\"\">Vehicle Drop Off Location </label>\r\n						<div class=\"select-wrap one-third\">\r\n						  <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n						  <select id=\"supportType\" class=\"form-control\">\r\n							<option value=\"\"selected >SR  Rent A Car Office Seeduwa</option>\r\n							<option value=\"\" >Colombo International Airport (CMB)</option>\r\n							<option value=\"\">Colombo Hotel</option>\r\n							<option value=\"\">Negombo Hotel</option>\r\n							<option value=\"\">Beruwala Hotel</option>\r\n							<option value=\"\">Benthota Hotel</option>\r\n							<option value=\"\">Galle Hotel</option>\r\n							<option value=\"\">Kandy Hotel</option>\r\n							<option value=\"\">Nuwara Eliya Hotel</option>\r\n							<option value=\"\">Jaffna Hotel</option>\r\n							<option value=\"\">Other Locations</option>\r\n							\r\n						  </select>\r\n						</div>\r\n					  </div>\r\n					  </div>\r\n\r\n\r\n				   </div>\r\n				   </div>\r\n\r\n				\r\n<div class=\"col-md-12\">\r\n    <div class=\"row\">\r\n        <div class=\"col-md-6\">\r\n            <div class=\"form-group\">\r\n                <label for=\"vehicleType\">Preferred Vehicle Type</label>\r\n                <div class=\"select-wrap one-third\">\r\n                    <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n                    <select id=\"vehicleType\" class=\"form-control\" onchange=\"updateBrands()\">\r\n                        <option value=\"mini\">Mini Cars</option>\r\n                        <option value=\"economy\">Economy Cars</option>\r\n                        <option value=\"standard\">Standard Cars</option>\r\n                        <option value=\"semi-executive\">Semi Executive Cars</option>\r\n                        <option value=\"executive\">Executive Cars</option>\r\n                        <option value=\"luxury\">Luxury Cars</option>\r\n                        <option value=\"mini-suv\">Mini SUVs (4 X 4)</option>\r\n                        <option value=\"large-suv\">Large SUVs (4 X 4)</option>\r\n                        <option value=\"mini-van\">Mini Van</option>\r\n						<option value=\"van\">Van</option>\r\n                        <option value=\"bus\">Luxury Coach</option>\r\n						<option value=\"long_bus\">Super Luxury Coach</option>\r\n                    </select>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n        <div class=\"col-md-6\">\r\n            <div class=\"form-group\">\r\n                <label for=\"vehicleBrand\">Preferred Vehicle Brand</label>\r\n                <div class=\"select-wrap one-third\">\r\n                    <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n                    <select id=\"vehicleBrand\" class=\"form-control\">\r\n                        <option value=\"\">Select a vehicle type first</option>\r\n                    </select>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>\r\n				 \r\n\r\n\r\n             <div class=\"col-md-12\">\r\n					 <div class=\"row\">\r\n					  <div class=\"col-md-6\">\r\n    <div class=\"form-group\">\r\n        <label for=\"pickupdate\">Pickup Date & Time</label>\r\n        <input type=\"datetime-local\" class=\"form-control\" id=\"pickupdate\" placeholder=\"Pickup Date & Time\">\r\n    </div>\r\n</div>\r\n\r\n <div class=\"col-md-6\">\r\n    <div class=\"form-group\">\r\n        <label for=\"dropoffdate\">Dropoff Date & Time</label>\r\n        <input type=\"datetime-local\" class=\"form-control\" id=\"dropoffdate\" placeholder=\"Dropoff Date & Time\">\r\n    </div>\r\n</div>\r\n\r\n\r\n				   </div>\r\n				   </div>\r\n             </div>\r\n				   </div>\r\n\r\n				   					<div class=\"col-md-12\">\r\n						<div class=\"row\">\r\n							<div class=\"col-md-6\">\r\n					  <div class=\"form-group\">\r\n						<label for=\"\">I need a Sri Lanka Driver\'s License</label>\r\n						<div class=\"select-wrap one-third\">\r\n						  <div class=\"icon\"><span class=\"ion-ios-arrow-down\"></span></div>\r\n						  <select id=\"supportType\" class=\"form-control\" onchange=\"updateLabels()\">\r\n							<option value=\"\" selected>Please Choose an Option</option>\r\n							<option value=\"license\">Yes</option>\r\n							<option value=\"\">No</option>\r\n						  </select>\r\n						</div>\r\n					  </div>\r\n					</div>\r\n					</div>\r\n				</div>\r\n\r\n<div class=\"col-md-12\">\r\n	<label>Extras (subject to additional charges)</label><br>\r\n<div class=\"row\">\r\n\r\n  \r\n   </div>\r\n</div>\r\n				`;\r\n				break;\r\n			  case \'airport-hotel-transfer\':\r\n				labels = `\r\n				  <div class=\"col-md-6\">\r\n					<div class=\"form-group\">\r\n					  <label for=\"\">Flight Number</label>\r\n					  <input type=\"text\" class=\"form-control\" placeholder=\"Flight Number\">\r\n					</div>\r\n				  </div>\r\n				  <div class=\"col-md-6\">\r\n					<div class=\"form-group\">\r\n					  <label for=\"\">Arrival Time</label>\r\n					  <input type=\"text\" class=\"form-control\" placeholder=\"Arrival Time\">\r\n					</div>\r\n				  </div>\r\n				`;\r\n				break;\r\n			  case \'wedding-car-rentals\':\r\n				labels = `\r\n				  <div class=\"col-md-6\">\r\n					<div class=\"form-group\">\r\n					  <label for=\"\">Wedding Date</label>\r\n					  <input type=\"date\" class=\"form-control\" placeholder=\"Wedding Date\">\r\n					</div>\r\n				  </div>\r\n				  <div class=\"col-md-6\">\r\n					<div class=\"form-group\">\r\n					  <label for=\"\">Venue Address</label>\r\n					  <input type=\"text\" class=\"form-control\" placeholder=\"Venue Address\">\r\n					</div>\r\n				  </div>\r\n				`;\r\n				break;\r\n			  default:\r\n				labels = \'\';\r\n				break;\r\n			}\r\n		  \r\n			dynamicLabels.innerHTML = labels;\r\n		  }\r\n		  \r\n		  </script>\r\n\r\n<!--script>\r\n	const brandsByType = {\r\n    mini: [\'Suzuki Alto (Japan)\', \'Perodua Axia\', \'Suzuki Alto (Indian)\'],\r\n    economy: [\'Toyota Aqua\', \'Suzuki Swift\', \'Suzuki Hustler\', \'Suzuki Wagon R\'],\r\n    standard: [\'Perudua Bezza\', \'Honda Insight\', \'Nissan Sunny\', \'Kia Rio\',],\r\n    \'semi-executive\': [\'Toyota Corolla 121\', \'Toyota Belta\', \'Toyota Prius\', \'Honda Grace\'],\r\n    executive: [\'Toyota Corolla Axio\', \'Toyota Allion\'],\r\n    luxury: [\'Mercedes Benz S Class\', \'BMW 520d\', \'Jaguar XF\'],\r\n    \'mini-suv\': [\'Kia Sorento\', \'Hyundai Tucson\', \'Nissan X-Trail\'],\r\n    \'large-suv\': [\'Toyota Land Cruiser Prado V8\', \'Mitsubishi Montero\', \'Toyota Land Cruiser Prado V150\'],\r\n    \'mini-van\': [\'Nissan Vanette\', \'Nissan Caravan\'],\r\n	\'van\': [\'Toyota Hiace KDH\', \'Micro Tourer\'],\r\n    bus: [\'Toyota Coaster\'],\r\n	long_bus: [\'Scania\'],\r\n};\r\n\r\nfunction updateBrands() {\r\n    const vehicleType = document.getElementById(\'vehicleType\').value;\r\n    const vehicleBrandSelect = document.getElementById(\'vehicleBrand\');\r\n\r\n    // Clear the current options\r\n    vehicleBrandSelect.innerHTML = \'\';\r\n\r\n    // Add a default option\r\n    if (vehicleType === \'\') {\r\n        vehicleBrandSelect.innerHTML = \'<option value=\"\">Select a vehicle type first</option>\';\r\n        return;\r\n    }\r\n\r\n    // Populate brand options based on selected vehicle type\r\n    const brands = brandsByType[vehicleType];\r\n    brands.forEach(brand => {\r\n        const option = document.createElement(\'option\');\r\n        option.value = brand;\r\n        option.textContent = brand;\r\n        vehicleBrandSelect.appendChild(option);\r\n    });\r\n}\r\n\r\n</script>\r\n\r\n\r\n<script>\r\n  \r\n   document.addEventListener(\'DOMContentLoaded\', function() {\r\n    const selected = document.querySelector(\'.selected\');\r\n    const optionsContainer = document.querySelector(\'.options\');\r\n    const selectedFlag = document.getElementById(\'selected-country-flag\');\r\n    let selectedCarCode = localStorage.getItem(\'selected_car\');\r\n    let selectedCarName = localStorage.getItem(\'selected_car_name\');\r\n    $(\'#carName\').text(selectedCarName);\r\n\r\n    selected.addEventListener(\'click\', () => {\r\n        optionsContainer.style.display = optionsContainer.style.display === \'block\' ? \'none\' : \'block\';\r\n    });\r\n\r\n    optionsContainer.addEventListener(\'click\', (event) => {\r\n        if (event.target && event.target.matches(\'div\')) {\r\n            selectedFlag.src = event.target.getAttribute(\'data-flag\');\r\n            selected.querySelector(\'span\').textContent = event.target.textContent;\r\n            selected.setAttribute(\'data-value\', event.target.getAttribute(\'data-value\'));\r\n            optionsContainer.style.display = \'none\';\r\n        }\r\n    });\r\n\r\n    document.addEventListener(\'click\', (event) => {\r\n        if (!selected.contains(event.target)) {\r\n            optionsContainer.style.display = \'none\';\r\n        }\r\n    });\r\n});\r\n\r\n\r\n</script>\r\n\r\n\r\n\r\n\r\n\r\n\r\n', 1, 2, 14, 1, 1, 1, 1726587393, 1, 1728905585, 1, 1728966131, 1, 1726587360, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'index.html', 0, 0, 1, NULL, 1);
INSERT INTO `modx_site_content` (`id`, `type`, `pagetitle`, `longtitle`, `description`, `alias`, `link_attributes`, `published`, `pub_date`, `unpub_date`, `parent`, `isfolder`, `introtext`, `content`, `richtext`, `template`, `menuindex`, `searchable`, `cacheable`, `createdby`, `createdon`, `editedby`, `editedon`, `deleted`, `deletedon`, `deletedby`, `publishedon`, `publishedby`, `menutitle`, `donthit`, `privateweb`, `privatemgr`, `content_dispo`, `hidemenu`, `class_key`, `context_key`, `content_type`, `uri`, `uri_override`, `hide_children_in_tree`, `show_in_tree`, `properties`, `alias_visible`) VALUES
(17, 'document', 'mini_cars', 'Congratulations!', '', 'mini-cars', '', 1, 0, 0, 0, 0, '', '\r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n<section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/breadcrumb/sr_bc_rentacar.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n    <div class=\"overlay\"></div>\r\n    <div class=\"container\">\r\n        <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n            <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n                <h1 class=\"mb-2 bread\">Mini Cars</h1>\r\n                <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\">\r\n                    <span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span>\r\n                    <span class=\"mr-2\"><a href=\"[[~4]]\">Fleet <i class=\"ion-ios-arrow-forward\"></i></a></span>\r\n                    <span>Mini Cars<i class=\"ion-ios-arrow-forward\"></i></span>\r\n                </p>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</section>\r\n  \r\n  <!-- Topic Cards -->\r\n  <div id=\"cards_landscape_wrap-2\"  style=\"padding-bottom: 50px;\">\r\n    <div class=\"container\">\r\n        <h5 class=\"text-fleet\" style=\"font-size: 25px; text-align: left;\">Which vehicle would you like to Drive?</h5>\r\n        <div class=\"row\">\r\n  \r\n          <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-6\">\r\n              <div class=\"card-flyer\" style=\"height: auto; overflow: hidden;\">\r\n                  <div class=\"text-box\" style=\"height: 100%;\">\r\n                      <!-- Exclusive Label -->\r\n                      <div class=\"exclusive-label\" style=\"position: absolute; top: 50px; right: 15px; background-color: #06b609; color: rgb(255, 255, 255); padding: 5px 10px; font-weight: bold; border-radius: 5px;\">\r\n                          Exclusive\r\n                      </div>\r\n                      <div class=\"image-box\" style=\"position: relative; display: inline-block;\">\r\n                          <img src=\"assets/images/car_booking/econ/hustler_b.jpg\" alt=\"\" style=\"display: block; width: 100%; height: 200px;\" />\r\n                          <div class=\"overlay-text\" style=\"position: absolute; top: 10%; left: 54%; color: #fff7f7; font-size: 22px; text-align: center;\">\r\n                               <div class=\"icon-text\">\r\n                                    <div class=\"icon-contain\">\r\n                                        [[!ratesModalSnippet]]\r\n\r\n                                    </div>\r\n                                </div> \r\n                              \r\n                             \r\n                          </div>\r\n                          <div class=\"overlay-text\" style=\"position: absolute; top: 25%; left: 0%; color: white; font-size: 16px; text-align: center;\">\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-snowflake iconic\"></i>\r\n                                  <span>Front AC</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-users iconic\"></i>\r\n                                  <span>04 Max</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-suitcase iconic\"></i>\r\n                                  <span>04 Max</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-gas-pump iconic\"></i>\r\n                                  <span>Full to Full</span>\r\n                              </div>\r\n                              <div class=\"icon-text\">\r\n                                  <i class=\"fas fa-tachometer iconic\"></i>\r\n                                  <span>Unlimited KM per Day</span>\r\n                              </div>\r\n\r\n\r\n                          </div>\r\n\r\n\r\n                      </div>\r\n          \r\n                      <div class=\"text-container\">\r\n                          <h6 style=\"font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; font-size: 18px;\">Suzuki Hustler</h6>\r\n                          <p style=\"font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; font-size: 14px; color: green;\">( Economy Cars )</p>\r\n                          <div class=\"alert alert-info alert-dismissible\" role=\"alert\" style=\"background-color: #28a74609; color: rgb(132, 12, 12);\">\r\n                              <strong>Info:</strong> Flexible cancellation with every booking.\r\n                          </div>\r\n                      </div>\r\n          \r\n                      <div class=\"container\">\r\n                          <!-- Bootstrap Tabs -->\r\n                          <ul class=\"nav nav-tabs\" id=\"vehicleTab\" role=\"tablist\">\r\n                              <li class=\"nav-item\">\r\n                                  <a class=\"nav-link active\" id=\"details-tab\" data-toggle=\"tab\" href=\"#details3\" role=\"tab\" aria-controls=\"details\" aria-selected=\"true\">Basic Info</a>\r\n                              </li>\r\n                              <!-- <li class=\"nav-item\">\r\n                                  <a class=\"nav-link\" id=\"rates-tab\" data-toggle=\"tab\" href=\"#rates3\" role=\"tab\" aria-controls=\"rates\" aria-selected=\"false\">Rates</a>\r\n                              </li> -->\r\n                              <li class=\"nav-item\">\r\n                                  <a class=\"nav-link\" id=\"terms-tab\" data-toggle=\"tab\" href=\"#terms3\" role=\"tab\" aria-controls=\"terms\" aria-selected=\"false\">Terms & Conditions</a>\r\n                              </li>\r\n                          </ul>\r\n                          <div class=\"tab-content\" id=\"vehicleTabContent\">\r\n                              <div class=\"tab-pane fade show\" id=\"details3\" role=\"tabpanel\" aria-labelledby=\"details-tab\" style=\"padding: 15px;\">\r\n                                  <div class=\"bordered-text\" style=\"font-size: 14px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">\r\n                                      At the car pickup, it is compulsory to hold a temporary Sri Lankan driver permit for self-driving.\r\n                                    \r\n                                    </div>\r\n                                  <!-- Content for Basic Info -->\r\n                                  <h4>Driver & license requirements</h4>\r\n                                  <div style=\"text-align: left;\">\r\n                                      <p style=\"font-weight: 900;\">When you pick the car up, you\'ll need:</p>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Passport or national ID card<br>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Driving license<br>\r\n                                      <i class=\"fas fa-check-circle icon\"></i> Credit card\r\n                                  </div>\r\n                                  <hr>\r\n                                  <h4>Security deposit</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      At pick-up, the main driver will leave a refundable security deposit of € 700 on their credit card. Cash and debit cards are not accepted. The counter staff will confirm how much this will be.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Accepted cards</h4>\r\n                                  <div style=\"text-align: center;\">\r\n                                      <figure style=\"display: inline-block; margin: 10px;\">\r\n                                          <img src=\"assets/images/car_booking/master_card.png\" alt=\"Card Type 1\" style=\"width: 100px; height: auto;\">\r\n                                          <figcaption>Master Card</figcaption>\r\n                                      </figure>\r\n                                      <figure style=\"display: inline-block; margin: 10px;\">\r\n                                          <img src=\"assets/images/car_booking/visa_card.png\" alt=\"Card Type 2\" style=\"width: 100px; height: auto;\">\r\n                                          <figcaption>Visa Card</figcaption>\r\n                                      </figure>\r\n                                  </div>\r\n                                  <hr>\r\n                                  <h4>Damage Excess</h4>\r\n\r\n                                  <p style=\"text-align: justify;\">\r\n                                      If the car\'s bodywork gets damaged, the most you\'ll pay towards repairs covered by the Collision Damage Waiver is the damage excess  (€ 1000). This cover is only valid if you stick to the terms of the rental agreement.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Mileage (Unlimited)</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      Your rental includes unlimited free kilometres.\r\n                                  </p>\r\n                                  <hr>\r\n                                  <h4>Fuel policy (Full to Full)</h4>\r\n                                  <p style=\"text-align: justify;\">\r\n                                      Your vehicle will be supplied with a full tank of fuel. To avoid incurring fuel charges, you will need to return it with the same amount of fuel as it had when you collected it.\r\n                                  </p>\r\n                                  <hr>\r\n                              </div>\r\n                              <div class=\"tab-pane fade\" id=\"rates3\" role=\"tabpanel\" aria-labelledby=\"rates-tab\">\r\n                                  <table class=\"table table-striped table-hover\">\r\n                                      <thead class=\"thead-light\">\r\n                                          <tr style=\"text-align: left;\">\r\n                                              <th>Duration</th>\r\n                                              <th>Rate</th>\r\n                                          </tr>\r\n                                      </thead>\r\n                                      <tbody style=\"text-align: left;\">\r\n                                          <tr class=\"table-primary\">\r\n                                              <td>01  - 03 Days</td>\r\n                                              <td>52 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-secondary\">\r\n                                              <td>04  - 06 Days</td>\r\n                                              <td>47 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-success\">\r\n                                              <td>07 Days</td>\r\n                                              <td>44 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-primary\">\r\n                                              <td>08  - 13 Days</td>\r\n                                              <td>42 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-secondary\">\r\n                                              <td>14 Days</td>\r\n                                              <td>37 Euro</td>\r\n                                          </tr>\r\n                                          <tr class=\"table-success\">\r\n                                              <td>15 & More Days</td>\r\n                                              <td>32 Euro</td>\r\n                                          </tr>\r\n                                      </tbody>\r\n                                  </table>\r\n                              </div>\r\n                              <div class=\"tab-pane fade\" id=\"terms3\" role=\"tabpanel\" aria-labelledby=\"terms-tab\">\r\n                <div style=\"text-align: left; padding: 15px;\">\r\n                                                                             \r\n                                     \r\n                  <i class=\"fas fa-check-circle icon\"></i>Digital driving licences will not be accepted.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The main driver or booking holder  must be in possession of a Credit Card in their own name when picking up the car.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The driver must be within the age range of 21-65 years to be eligible to self drive.\r\n                  <hr>\r\n                  <i class=\"fas fa-check-circle icon\"></i>The renter must be physically present at the car pick up and on return of the vehicle.\r\n              </div>\r\n                              </div>\r\n                          </div>\r\n                      </div>\r\n          \r\n                    <div style=\"margin-bottom: 20px;\">\r\n                          <a href=\"[[~30]]\" class=\"theme-btn btn-style-three btn-selection\" data-carcode=\"car_007\"  data-carname=\"Suzuki Hustler\" data-carimage=\"assets/images/reg/car_007.png\">Select</a>\r\n                        </div>\r\n                      \r\n                  </div>\r\n              </div>\r\n          </div>\r\n  \r\n  \r\n            <div class=\"col-xs-12 col-sm-6 col-md-6 col-lg-6\">\r\n                <div class=\"card-flyer\" style=\"height: auto; overflow: hidden;\">\r\n                    <div class=\"text-box\" style=\"height: 100%;\">\r\n                        <!-- Exclusive Label -->\r\n                        <div class=\"exclusive-label\" style=\"position: absolute; top: 50px; right: 15px; background-color: #06b609; color: rgb(255, 255, 255); padding: 5px 10px; font-weight: bold; border-radius: 5px;\">\r\n                            Exclusive\r\n                        </div>\r\n                        <div class=\"image-box\" style=\"position: relative; display: inline-block;\">\r\n  \r\n                            <img src=\"assets/images/car_booking/mini_car/jalto.jpg\" alt=\"\" style=\"display: block; width: 100%; height: 200px;\" />\r\n  \r\n                            <div class=\"overlay-text\" style=\"position: absolute; top: 10%; left: 54%; color: #fff7f7; font-size: 22px; text-align: center;\">\r\n                                <div class=\"icon-text\">\r\n                                    <div class=\"icon-contain\">\r\n                                        [[!ratesModalSnippet]]\r\n\r\n                                    </div>\r\n                                </div> \r\n                                \r\n                               \r\n                            </div>\r\n                            <div class=\"overlay-text\" style=\"position: absolute; top: 25%; left: 0%; color: white; font-size: 16px; text-align: center;\">\r\n                                <div class=\"icon-text\">\r\n                                    <i class=\"fas fa-snowflake iconic\"></i>\r\n                                    <span>Front AC</span>\r\n                                </div>\r\n                                <div class=\"icon-text\">\r\n                                    <i class=\"fas fa-users iconic\"></i>\r\n                                    <span>04 Max</span>\r\n                                </div>\r\n                                <div class=\"icon-text\">\r\n                                    <i class=\"fas fa-suitcase iconic\"></i>\r\n                                    <span>04 Max</span>\r\n                                </div>\r\n                                <div class=\"icon-text\">\r\n                                    <i class=\"fas fa-gas-pump iconic\"></i>\r\n                                    <span>Full to Full</span>\r\n                                </div>\r\n                                <div class=\"icon-text\">\r\n                                    <i class=\"fas fa-tachometer iconic\"></i>\r\n                                    <span>Unlimited KM per Day</span>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n  \r\n  \r\n                        <div class=\"text-container\">\r\n                            <h6 style=\"font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; font-size: 18px;\">Suzuki Alto (Japan)</h6>\r\n                            <p style=\"font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; font-size: 14px; color: green;\">( Mini Cars )</p>\r\n                            <div class=\"alert alert-info alert-dismissible\" role=\"alert\" style=\"background-color: #28a74609; color: rgb(132, 12, 12);\">\r\n                                <strong>Info:</strong> Flexible cancellation with every booking.\r\n                            </div>\r\n                        </div>\r\n  \r\n                        <div class=\"container\">\r\n                            <!-- Bootstrap Tabs -->\r\n                            <ul class=\"nav nav-tabs\" id=\"vehicleTab\" role=\"tablist\">\r\n                                <li class=\"nav-item\">\r\n                                    <a class=\"nav-link active\" id=\"details-tab\" data-toggle=\"tab\" href=\"#details1\" role=\"tab\" aria-controls=\"details\" aria-selected=\"true\">Basic Info</a>\r\n                                </li>\r\n                                <!-- <li class=\"nav-item\">\r\n                                    <a class=\"nav-link\" id=\"rates-tab\" data-toggle=\"tab\" href=\"#rates1\" role=\"tab\" aria-controls=\"rates\" aria-selected=\"false\">Rates</a>\r\n                                </li> -->\r\n                                <li class=\"nav-item\">\r\n                                    <a class=\"nav-link\" id=\"terms-tab\" data-toggle=\"tab\" href=\"#terms1\" role=\"tab\" aria-controls=\"terms\" aria-selected=\"false\">Terms & Conditions</a>\r\n                                </li>\r\n                            </ul>\r\n                            <div class=\"tab-content\" id=\"vehicleTabContent\">\r\n                                <div class=\"tab-pane fade show\" id=\"details1\" role=\"tabpanel\" aria-labelledby=\"details-tab\" style=\"padding: 15px;\">\r\n                                    <div class=\"bordered-text\" style=\"font-size: 14px;font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\">\r\n                                        At the car pickup, it is compulsory to hold a temporary Sri Lankan driver permit for self-driving.\r\n                                      \r\n                                      </div>\r\n                                    <!-- Content for Basic Info -->\r\n                                    <h4>Driver & license requirements</h4>\r\n                                    <div style=\"text-align: left;\">\r\n                                        <p style=\"font-weight: 900;\">When you pick the car up, you\'ll need:</p>\r\n                                        <i class=\"fas fa-check-circle icon\"></i> Passport or national ID card<br>\r\n                                        <i class=\"fas fa-check-circle icon\"></i> Driving license<br>\r\n                                        <i class=\"fas fa-check-circle icon\"></i> Credit card\r\n                                    </div>\r\n                                    <hr>\r\n                                    <h4>Security deposit</h4>\r\n                                    <p style=\"text-align: justify;\">\r\n                                        At pick-up, the main driver will leave a refundable security deposit of € 700.00 on their credit card. Cash and debit cards are not accepted. The counter staff will confirm how much this will be.\r\n                                    </p>\r\n                                    <hr>\r\n                                    <h4>Accepted cards</h4>\r\n                                    <div style=\"text-align: center;\">\r\n                                        <figure style=\"display: inline-block; margin: 10px;\">\r\n                                            <img src=\"assets/images/car_booking/master_card.png\" alt=\"Card Type 1\" style=\"width: 100px; height: auto;\">\r\n                                            <figcaption>Master Card</figcaption>\r\n                                        </figure>\r\n                                        <figure style=\"display: inline-block; margin: 10px;\">\r\n                                            <img src=\"assets/images/car_booking/visa_card.png\" alt=\"Card Type 2\" style=\"width: 100px; height: auto;\">\r\n                                            <figcaption>Visa Card</figcaption>\r\n                                        </figure>\r\n                                    </div>\r\n                                    <hr>\r\n                                    <h4>Damage Excess (€ 1000)</h4>\r\n                                    <p style=\"text-align: justify;\">\r\n                                        If the car\'s bodywork gets damaged, the most you\'ll pay towards repairs covered by the Collision Damage Waiver is the damage excess  (€ 1000). This cover is only valid if you stick to the terms of the rental agreement.\r\n                                    </p>\r\n                                    <hr>\r\n                                    <h4>Mileage </h4>\r\n                                    <p style=\"text-align: justify;\">\r\n                                        Your rental includes 150 kilometres.\r\n                                    </p>\r\n                                    <hr>\r\n                                    <h4>Fuel policy (Full to Full)</h4>\r\n                                    <p style=\"text-align: justify;\">\r\n                                        Your vehicle will be supplied with a full tank of fuel. To avoid incurring fuel charges, you will need to return it with the same amount of fuel as it had when you collected it.\r\n                                    </p>\r\n                                    <hr>\r\n                                </div>\r\n                                <div class=\"tab-pane fade\" id=\"rates1\" role=\"tabpanel\" aria-labelledby=\"rates-tab\">\r\n                                    <table class=\"table table-striped table-hover\">\r\n                                        <thead class=\"thead-light\">\r\n                                            <tr style=\"text-align: left;\">\r\n                                                <th>Duration</th>\r\n                                                <th>Rate</th>\r\n                                            </tr>\r\n                                        </thead>\r\n                                        <tbody style=\"text-align: left;\">\r\n                                            <tr class=\"table-primary\">\r\n                                                <td>01  - 03 Days</td>\r\n                                                <td>50 Euro</td>\r\n                                            </tr>\r\n                                            <tr class=\"table-secondary\">\r\n                                                <td>04  - 06 Days</td>\r\n                                                <td>45 Euro</td>\r\n                                            </tr>\r\n                                            <tr class=\"table-success\">\r\n                                                <td>07 Days</td>\r\n                                                <td>42 Euro</td>\r\n                                            </tr>\r\n                                            <tr class=\"table-primary\">\r\n                                                <td>08  - 13 Days</td>\r\n                                                <td>40 Euro</td>\r\n                                            </tr>\r\n                                            <tr class=\"table-secondary\">\r\n                                                <td>14 Days</td>\r\n                                                <td>35 Euro</td>\r\n                                            </tr>\r\n                                            <tr class=\"table-success\">\r\n                                                <td>15 & More Days</td>\r\n                                                <td>30 Euro</td>\r\n                                            </tr>\r\n                                        </tbody>\r\n                                    </table>\r\n                                </div>\r\n                                <div class=\"tab-pane fade\" id=\"terms1\" role=\"tabpanel\" aria-labelledby=\"terms-tab\">\r\n                  <div style=\"text-align: left; padding: 15px;\">\r\n                                                                               \