(33, 'document', 'rates', 'Congratulations!', '', 'rates', '', 1, 0, 0, 0, 0, '', '<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n    <title>Login - SR Rent A Car</title>\r\n    <link rel=\"icon\" href=\"favicon.ico\" type=\"image/x-icon\">\r\n    <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n    <style>\r\n        body {\r\n            background-color: #f8f9fa;\r\n        }\r\n        h1 {\r\n            font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\r\n            color: #09273b;\r\n            font-size: 30px;\r\n        }\r\n        .logo-bar img {\r\n            max-width: 60px;\r\n        }\r\n        h1 {\r\n  font-family: \'cambria bold\', ;\r\n  font-size: 2 rem;\r\n  color:rgb(81, 0, 83);\r\n  text-align: center;\r\n  margin-top: 10px;\r\n  margin-bottom: 20px;\r\n  letter-spacing: 1px;\r\n  position: relative;\r\n}\r\n\r\nh1::after {\r\n  content: \'\';\r\n  display: block;\r\n  width: 80px;\r\n  height: 4px;\r\n  background-color: #0074c1;\r\n  margin: 10px auto 0;\r\n  border-radius: 2px;\r\n}\r\n\r\n    </style>\r\n</head>\r\n\r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n<body>\r\n    <div class=\"container py-5\">\r\n    <div class=\"text-center mb-4\">\r\n            <img src=\"assets/images/logo.png\" alt=\"Logo\" class=\"mb-3\" style=\"max-width: 150px;\">\r\n            <h1>Car Rates Updates</h1>\r\n        </div>\r\n        <div class=\"row justify-content-center\">\r\n            <div class=\"col-md-5\">\r\n                <div class=\"card shadow-lg\">\r\n                    <div class=\"card-body\">\r\n                        <!-- <h1 class=\"text-center mb-4\">Login</h1> -->\r\n                        <form action=\"home.php\" method=\"POST\">\r\n                            <div class=\"mb-3\">\r\n                                <label for=\"email\" class=\"form-label\">E Mail</label>\r\n                                <input type=\"email\" class=\"form-control\" id=\"email\" name=\"email\" required>\r\n                            </div>\r\n                            <div class=\"mb-4\">\r\n                                <label for=\"password\" class=\"form-label\">Password</label>\r\n                                <input type=\"password\" class=\"form-control\" id=\"password\" name=\"password\" required>\r\n                            </div>\r\n                            <div class=\"d-grid\">\r\n                                <button type=\"submit\" class=\"btn\" style=\"background-color: #09273b; color: white;\">Login</button>\r\n                            </div>\r\n                        </form>\r\n                        <!-- <div class=\"text-center mt-3\">\r\n                            <small>Forgot your password? <a href=\"#\">Click here</a></small>\r\n                        </div> -->\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n\r\n    <script>\r\n    document.addEventListener(\"DOMContentLoaded\", function () {\r\n        const form = document.querySelector(\"form\");\r\n        form.addEventListener(\"submit\", function (e) {\r\n            e.preventDefault(); // prevent default submission\r\n\r\n            const username = document.getElementById(\"email\").value;\r\n            const password = document.getElementById(\"password\").value;\r\n\r\n            // Example hardcoded credentials\r\n            const validUsername = \"login@explorevacations.lk\";\r\n            const validPassword = \"KavSan2000\";\r\n\r\n            if (username === validUsername && password === validPassword) {\r\n                // alert(\"Login successful!\");\r\n                // Redirect or allow form submission\r\n                window.location.href = \"dashboard.php\";\r\n            } else {\r\n                // alert(\"Invalid username or password!\");\r\n            }\r\n        });\r\n    });\r\n</script>\r\n\r\n    <!-- Bootstrap JS -->\r\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\r\n\r\n    <script>\r\n        document.addEventListener(\"DOMContentLoaded\", function () {\r\n            const form = document.querySelector(\"form\");\r\n            form.addEventListener(\"submit\", function (e) {\r\n                e.preventDefault(); // prevent default submission\r\n\r\n                const username = document.getElementById(\"email\").value;\r\n                const password = document.getElementById(\"password\").value;\r\n\r\n                const validUsername = \"login@explorevacations.lk\";\r\n                const validPassword = \"KavSan2000\";\r\n\r\n                if (username === validUsername && password === validPassword) {\r\n                    // alert(\"Login successful!\");\r\n                    window.location.href = \"dashboard.php\";\r\n                } else {\r\n                    // alert(\"Invalid username or password!\");\r\n                }\r\n            });\r\n        });\r\n    </script>\r\n</body>\r\n\r\n    <!-- Bootstrap JS -->\r\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\r\n</body>\r\n</html>\r\n', 1, 0, 31, 1, 1, 1, 1745930659, 1, 1748927432, 0, 0, 0, 1745930640, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'rates.html', 0, 0, 1, NULL, 1),
(34, 'document', 'dashboard.php', 'Congratulations!', '', 'dashboard', '', 1, 0, 0, 0, 0, '', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n    <title>Car Rental Records</title>\r\n    <link rel=\"stylesheet\" href=\"https://maxcdn.bootstrapcdn.com/bootstrap/3.3.7/css/bootstrap.min.css\">\r\n</head>\r\n\r\n<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-5861K2TN4V\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-5861K2TN4V\');\r\n</script>\r\n\r\n<body>\r\n<div class=\"container\">\r\n    <h2 class=\"text-center\" style=\"margin-top:20px;\">All Car Rental Records</h2>\r\n    <hr>\r\n\r\n    <?php\r\n    // MySQLi Procedural Connection\r\n    $conn = mysqli_connect(\"localhost\", \"slrcar_srimal87\", \"Srimal@456\", \"slrcar_sr\");\r\n    if (!$conn) {\r\n        die(\"Connection failed: \" . mysqli_connect_error());\r\n    }\r\n\r\n    // Fetch records\r\n    $query = mysqli_query($conn, \"SELECT * FROM car_rental\");\r\n\r\n    if (!$query) {\r\n        die(\"Query failed: \" . mysqli_error($conn));\r\n    }\r\n\r\n    if (mysqli_num_rows($query) > 0) {\r\n        echo \'<table class=\"table table-bordered table-striped\">\';\r\n        echo \'<thead><tr>\r\n                <th>ID</th>\r\n                <th>Car Code</th>\r\n                <th>Car Model</th>\r\n                <th>Car Category</th>\r\n                <th>Duration</th>\r\n                <th>Rate</th>\r\n                <th>Start Date</th>\r\n                <th>End Date</th>\r\n              </tr></thead><tbody>\';\r\n        while ($row = mysqli_fetch_assoc($query)) {\r\n            echo \'<tr>\';\r\n            echo \'<td>\' . $row[\'id\'] . \'</td>\';\r\n            echo \'<td>\' . htmlspecialchars($row[\'car_code\']) . \'</td>\';\r\n            echo \'<td>\' . htmlspecialchars($row[\'car_model\']) . \'</td>\';\r\n            echo \'<td>\' . htmlspecialchars($row[\'car_category\']) . \'</td>\';\r\n            echo \'<td>\' . htmlspecialchars($row[\'duration\']) . \'</td>\';\r\n            echo \'<td>\' . htmlspecialchars($row[\'rate\']) . \'</td>\';\r\n            echo \'<td>\' . htmlspecialchars($row[\'start_date\']) . \'</td>\';\r\n            echo \'<td>\' . htmlspecialchars($row[\'end_date\']) . \'</td>\';\r\n            echo \'</tr>\';\r\n        }\r\n        echo \'</tbody></table>\';\r\n    } else {\r\n        echo \'<div class=\"alert alert-warning\">No records found in car_rental table.</div>\';\r\n    }\r\n\r\n    mysqli_close($conn);\r\n    ?>\r\n</div>\r\n</body>\r\n</html>\r\n', 1, 0, 32, 1, 1, 1, 1745986005, 1, 1750243352, 1, 1750243366, 1, 1745985960, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'dashboard.html', 0, 0, 1, NULL, 1),
