n\r\n            if (username === validUsername && password === validPassword) {\r\n                // alert(\"Login successful!\");\r\n                // Redirect or allow form submission\r\n                window.location.href = \"inquiry.php\";\r\n            } else {\r\n                // alert(\"Invalid username or password!\");\r\n            }\r\n        });\r\n    });\r\n</script>\r\n\r\n    <!-- Bootstrap JS -->\r\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\r\n\r\n    <script>\r\n        document.addEventListener(\"DOMContentLoaded\", function () {\r\n            const form = document.querySelector(\"form\");\r\n            form.addEventListener(\"submit\", function (e) {\r\n                e.preventDefault(); // prevent default submission\r\n\r\n                const username = document.getElementById(\"email\").value;\r\n                const password = document.getElementById(\"password\").value;\r\n\r\n                const validUsername = \"login@explorevacations.lk\";\r\n                const validPassword = \"sr@2000\";\r\n\r\n                if (username === validUsername && password === validPassword) {\r\n                    // alert(\"Login successful!\");\r\n                    window.location.href = \"inquiry.php\";\r\n                } else {\r\n                    // alert(\"Invalid username or password!\");\r\n                }\r\n            });\r\n        });\r\n    </script>\r\n</body>\r\n\r\n    <!-- Bootstrap JS -->\r\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\r\n</body>\r\n</html>\r\n', 1, 0, 33, 1, 1, 1, 1746183110, 1, 1748927681, 0, 0, 0, 1746183060, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'inquiry.html', 0, 0, 1, NULL, 1);
