bel>\r\n                                <input type=\"email\" class=\"form-control\" id=\"email\" name=\"email\" required>\r\n                            </div>\r\n                            <div class=\"mb-4\">\r\n                                <label for=\"password\" class=\"form-label\">Password</label>\r\n                                <input type=\"password\" class=\"form-control\" id=\"password\" name=\"password\" required>\r\n                            </div>\r\n                            <div class=\"d-grid\">\r\n                                <button type=\"submit\" class=\"btn\" style=\"background-color: #09273b; color: white;\">Login</button>\r\n                            </div>\r\n                        </form>\r\n                        <!-- <div class=\"text-center mt-3\">\r\n                            <small>Forgot your password? <a href=\"#\">Click here</a></small>\r\n                        </div> -->\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n\r\n    <script>\r\n    document.addEventListener(\"DOMContentLoaded\", function () {\r\n        const form = document.querySelector(\"form\");\r\n        form.addEventListener(\"submit\", function (e) {\r\n            e.preventDefault(); // prevent default submission\r\n\r\n            const username = document.getElementById(\"email\").value;\r\n            const password = document.getElementById(\"password\").value;\r\n\r\n            // Example hardcoded credentials\r\n            const validUsername = \"login@explorevacations.lk\";\r\n            const validPassword = \"JkQ6rT5m09\";\r\n\r\n            if (username === validUsername && password === validPassword) {\r\n                // alert(\"Login successful!\");\r\n                // Redirect or allow form submission\r\n                window.location.href = \"home.php\";\r\n            } else {\r\n                // alert(\"Invalid username or password!\");\r\n            }\r\n        });\r\n    });\r\n</script>\r\n\r\n    <!-- Bootstrap JS -->\r\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\r\n\r\n    <script>\r\n        document.addEventListener(\"DOMContentLoaded\", function () {\r\n            const form = document.querySelector(\"form\");\r\n            form.addEventListener(\"submit\", function (e) {\r\n                e.preventDefault(); // prevent default submission\r\n\r\n                const username = document.getElementById(\"email\").value;\r\n                const password = document.getElementById(\"password\").value;\r\n\r\n                const validUsername = \"login@explorevacations.lk\";\r\n                const validPassword = \"JkQ6rT5m09\";\r\n\r\n                if (username === validUsername && password === validPassword) {\r\n                    // alert(\"Login successful!\");\r\n                    window.location.href = \"home.php\";\r\n                } else {\r\n                    // alert(\"Invalid username or password!\");\r\n                }\r\n            });\r\n        });\r\n    </script>\r\n</body>\r\n\r\n    <!-- Bootstrap JS -->\r\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js\"></script>\r\n</body>\r\n</html>\r\n', 1, 0, 34, 1, 1, 1, 1763016153, 1, 1763020670, 0, 0, 0, 1763016120, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'eval.html', 0, 0, 1, NULL, 1),
(37, 'document', 'selection', 'Congratulations!', '', 'selection', '', 1, 0, 0, 0, 0, '', '<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n  <meta charset=\"UTF-8\" />\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"/>\r\n  <title>Paging Board Generator</title>\r\n\r\n  <link rel=\"icon\" href=\"favicon.ico\" type=\"image/x-icon\" />\r\n  <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\" />\r\n  <script src=\"https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js\"></script>\r\n  <script src=\"https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.4.0/jspdf.umd.min.js\"></script>\r\n\r\n  <style>\r\n    h1 {\r\n      font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\r\n      font-size: 28px;\r\n      color: blueviolet;\r\n      text-align: center;\r\n      margin-top: 20px;\r\n    }\r\n\r\n    .card-body {\r\n      height: 250px;\r\n      display: flex;\r\n      flex-direction: column;\r\n      justify-content: space-between;\r\n      overflow: hidden;\r\n      transition: box-shadow 0.3s ease;\r\n    }\r\n\r\n    .card-body:hover {\r\n      box-shadow: 0 0 15px rgba(8, 0, 36, 0.7);\r\n    }\r\n\r\n    .card-title {\r\n      font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\r\n      font-size: 22px;\r\n      color: rgb(75, 0, 0);\r\n    }\r\n\r\n    .card img {\r\n      max-width: 60%;\r\n      height: auto;\r\n      display: block;\r\n      margin-left: auto;\r\n      margin-right: auto;\r\n    }\r\n\r\n    .card-body img {\r\n      margin-bottom: 10px;\r\n    }\r\n\r\n    .text-center img {\r\n      margin: 0 auto;\r\n    }\r\n\r\n    .card {\r\n      transition: box-shadow 0.3s ease-in-out, transform 0.3s ease-in-out;\r\n    }\r\n\r\n    .card:hover {\r\n      box-shadow: 0 0 25px rgba(0, 0, 255, 0.7);\r\n      transform: translateY(-5px);\r\n    }\r\n\r\n    /* Logout button styling */\r\n    .logout-btn {\r\n      position: fixed;\r\n      top: 15px;\r\n      right: 15px;\r\n      z-index: 1050;\r\n    }\r\n  </style>\r\n</head>\r\n\r\n<body class=\"bg-light\">\r\n  <!-- Logout Button -->\r\n  <div class=\"logout-btn\">\r\n    <a href=\"eval.php\" class=\"btn btn-primary\">Logout</a>\r\n  </div>\r\n\r\n  <div class=\"container py-5\">\r\n    <div class=\"text-center mb-4\">\r\n      <img src=\"assets/images/eval/sr.png\" alt=\"Logo\" class=\"mb-3\" style=\"max-width: 150px;\" />\r\n      <h1>Staff Evaluation Console</h1>\r\n    </div>\r\n\r\n    <div class=\"row\">\r\n      <!-- Card 1 -->\r\n      <div class=\"col-md-4\">\r\n        <div class=\"card shadow-lg mb-4\">\r\n          <div class=\"card-body\">\r\n       <div class=\"row\">\r\n  <img src=\"assets/images/eval/arrival.png\" alt=\"Image\" class=\"img-fluid rounded\" style=\"max-width: 30%;\" />\r\n</div>\r\n\r\n            <h5 class=\"card-title text-center\">Arrival</h5>\r\n            <div class=\"d-grid gap-2\">\r\n              <a href=\"#\" onclick=\"openPinModal(\'pdf.php\')\" class=\"btn\" style=\"background-color: #09273b; color: white;\">\r\n                Log in to Evaluate\r\n              </a>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Card 2 -->\r\n      <div class=\"col-md-4\">\r\n        <div class=\"card shadow-lg mb-4\">\r\n          <div class=\"card-body text-center\">\r\n            <img src=\"assets/images/eval/departure.png\" alt=\"SR Transfers\" class=\"img-fluid rounded\" style=\"max-width: 45;\" />\r\n             <h5 class=\"card-title text-center\">Departure</h5>\r\n            <div class=\"d-grid gap-2\">\r\n              <a href=\"#\" onclick=\"openPinModal(\'transfer.php\')\" class=\"btn\" style=\"background-color: #09273b; color: white;\">\r\n                Log in to Evaluate\r\n              </a>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Card 3 -->\r\n      <div class=\"col-md-4\">\r\n        <div class=\"card shadow-lg mb-4\">\r\n          <div class=\"card-body text-center\">\r\n            <img src=\"assets/images/eval/examine.png\" alt=\"54 Travellers\" class=\"img-fluid rounded\" style=\"max-width: 45%;\" />\r\n             <h5 class=\"card-title text-center\">Dashbaord</h5>\r\n            <div class=\"d-grid gap-2\">\r\n              <a href=\"#\" onclick=\"openPinModal(\'54.php\')\" class=\"btn\" style=\"background-color: #09273b; color: white;\">\r\n                Log in to Examine\r\n              </a>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- PIN Modal -->\r\n  <div class=\"modal fade\" id=\"pinModal\" tabindex=\"-1\" aria-labelledby=\"pinModalLabel\" aria-hidden=\"true\">\r\n    <div class=\"modal-dialog modal-dialog-centered\">\r\n      <div class=\"modal-content\">\r\n        <div class=\"modal-header\">\r\n          <h5 class=\"modal-title\" id=\"pinModalLabel\">Enter PIN</h5>\r\n          <button type=\"button\" class=\"btn-close\" data-bs-dismiss=\"modal\" aria-label=\"Close\"></button>\r\n        </div>\r\n        <div class=\"modal-body\">\r\n          <input type=\"password\" class=\"form-control\" id=\"pinInput\" placeholder=\"Enter your PIN\" />\r\n          <div class=\"text-danger mt-2 d-none\" id=\"pinError\">Incorrect PIN. Please try again.</div>\r\n        </div>\r\n        <div class=\"modal-footer\">\r\n          <button type=\"button\" class=\"btn btn-secondary\" data-bs-dismiss=\"modal\">Cancel</button>\r\n          <button type=\"button\" class=\"btn btn-primary\" onclick=\"verifyPin()\">Submit</button>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Scripts -->\r\n  <script src=\"https://cdn.jsdelivr.net/npm/@popperjs/core@2.11.6/dist/umd/popper.min.js\"></script>\r\n  <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.min.js\"></script>\r\n\r\n  <script>\r\n  let targetLink = \'\';\r\n  let expectedPin = \'\';\r\n\r\n  function openPinModal(link) {\r\n    targetLink = link;\r\n\r\n    // Set expected PIN based on the link\r\n    switch (link) {\r\n      case \'https://srilankarentacar.com/eval.html\':\r\n        expectedPin = \'1234\';\r\n        break;\r\n      case \'transfer.php\':\r\n        expectedPin = \'5678\';\r\n        break;\r\n      case \'54.php\':\r\n        expectedPin = \'199705\';\r\n        break;\r\n      default:\r\n        expectedPin = \'\';\r\n    }\r\n\r\n    document.getElementById(\'pinInput\').value = \'\';\r\n    document.getElementById(\'pinError\').classList.add(\'d-none\');\r\n    new bootstrap.Modal(document.getElementById(\'pinModal\')).show();\r\n  }\r\n\r\n  function verifyPin() {\r\n    const enteredPin = document.getElementById(\'pinInput\').value;\r\n    if (enteredPin === expectedPin) {\r\n      window.location.href = targetLink;\r\n    } else {\r\n      document.getElementById(\'pinError\').classList.remove(\'d-none\');\r\n    }\r\n  }\r\n  </script>\r\n</body>\r\n</html>\r\n', 1, 0, 35, 1, 1, 1, 1763017289, 1, 1763020907, 0, 0, 0, 1763017260, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'selection.html', 0, 0, 1, NULL, 1),
(38, 'document', 'arrivals', 'Congratulations!', '', 'arrivals', '', 1, 0, 0, 0, 0, '', '<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Staff Evaluation - Arrival</title>\r\n  <link rel=\"icon\" href=\"favicon.ico\" type=\"image/x-icon\">\r\n  <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\r\n  <style>\r\n    h1 {\r\n      font-family: Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\r\n      font-size: 28px;\r\n      color: blueviolet;\r\n      text-align: center;\r\n      margin-top: 20px;\r\n    }\r\n    .logout-btn {\r\n      position: fixed;\r\n      top: 15px;\r\n      right: 15px;\r\n      z-index: 1050;\r\n    }\r\n    .row.align-items-center {\r\n      margin-bottom: 0.75rem;\r\n    }\r\n  </style>\r\n</head>\r\n<body class=\"bg-light\">\r\n\r\n  <div class=\"logout-btn\">\r\n    <a href=\"index.php\" class=\"btn btn-primary\">Logout</a>\r\n  </div>\r\n\r\n  <div class=\"container py-5\">\r\n    <div class=\"text-center mb-4\">\r\n      <div class=\"d-flex justify-content-center mb-3\">\r\n        <img src=\"assets/images/eval/sr.png\" alt=\"Logo 1\" class=\"mx-2\" style=\"max-width: 100px;\">\r\n      </div>\r\n      <h1>Staff Evaluation on the Arrival</h1>\r\n    </div>\r\n\r\n    <nav aria-label=\"breadcrumb\">\r\n      <ol class=\"breadcrumb\">\r\n        <li class=\"breadcrumb-item\"><a href=\"home.php\">Home</a></li>\r\n        <li class=\"breadcrumb-item active\" aria-current=\"page\">Staff Evaluation - Arrival</li>\r\n      </ol>\r\n    </nav>\r\n\r\n    <div class=\"card shadow-sm mb-5\">\r\n      <div class=\"card-body\">\r\n        <h4 class=\"card-title mb-3\">Arrivals / Checkout Checklist</h4>\r\n        <form id=\"checkoutForm\" class=\"needs-validation\" novalidate method=\"POST\" action=\"save_evaluation.php\">\r\n\r\n          <!-- Employee Details -->\r\n          <div class=\"row align-items-center\">\r\n            <div class=\"col-md-6 mb-2\">\r\n              <label class=\"form-label fw-semibold\">Employee Name</label>\r\n              <select name=\"employee_name\" class=\"form-select\" required>\r\n                <option value=\"\" disabled selected>Select Employee</option>\r\n                <?php\r\n                  for ($i = 1; $i <= 15; $i++) {\r\n                      echo \"<option value=\'Staff $i\'>Staff $i</option>\";\r\n                  }\r\n                ?>\r\n              </select>\r\n            </div>\r\n            <div class=\"col-md-6 mb-2\">\r\n              <label class=\"form-label fw-semibold\">Station</label>\r\n              <select name=\"station\" class=\"form-select\" required>\r\n                <option value=\"\" disabled selected>Select Station</option>\r\n                <option value=\"SR Rent Station\">SR Rent Station</option>\r\n                <option value=\"Europcar Station\">Europcar Station</option>\r\n                <option value=\"Greenmotion Station\">Greenmotion Station</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"row align-items-center mb-3\">\r\n            <div class=\"col-md-6\">\r\n              <label class=\"form-label fw-semibold\">Booking Number</label>\r\n              <input type=\"text\" name=\"booking_number\" class=\"form-control\" required>\r\n            </div>\r\n          </div>\r\n\r\n          <!-- Evaluation Checklist -->\r\n          <div class=\"row align-items-center\">\r\n            <div class=\"col-md-9\">\r\n              <label class=\"form-label fw-semibold\">1. Greeting (Polite & Helpful Way)</label>\r\n            </div>\r\n            <div class=\"col-md-3\">\r\n              <select name=\"greeting\" class=\"form-select\" required>\r\n                <option value=\"\" disabled selected>Select Your Rate</option>\r\n                <option>1</option><option>2</option><option>3</option><option>4</option><option>5</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"row align-items-center\">\r\n            <div class=\"col-md-9\">\r\n              <label class=\"form-label fw-semibold\">2. Accurate Documentation & Payment</label>\r\n            </div>\r\n            <div class=\"col-md-3\">\r\n              <select name=\"documentation\" class=\"form-select\" required>\r\n                <option value=\"\" disabled selected>Select Your Rate</option>\r\n                <option>1</option><option>2</option><option>3</option><option>4</option><option>5</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"row align-items-center\">\r\n            <div class=\"col-md-9\">\r\n              <label class=\"form-label fw-semibold\">3. Provide Value Added Information</label>\r\n            </div>\r\n            <div class=\"col-md-3\">\r\n              <select name=\"value_info\" class=\"form-select\" required>\r\n                <option value=\"\" disabled selected>Select Your Rate</option>\r\n                <option>1</option><option>2</option><option>3</option><option>4</option><option>5</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"row align-items-center\">\r\n            <div class=\"col-md-9\">\r\n              <label class=\"form-label fw-semibold\">4. Carried Out Proper Inspection (Vehicle)</label>\r\n            </div>\r\n            <div class=\"col-md-3\">\r\n              <select name=\"vehicle_inspection\" class=\"form-select\" required>\r\n                <option value=\"\" disabled selected>Select Your Rate</option>\r\n                <option>1</option><option>2</option><option>3</option><option>4</option><option>5</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"row align-items-center\">\r\n            <div class=\"col-md-9\">\r\n              <label class=\"form-label fw-semibold\">5. Provided Vehicle Controls Info + Photos at Key Handover</label>\r\n            </div>\r\n            <div class=\"col-md-3\">\r\n              <select name=\"controls_photos\" class=\"form-select\" required>\r\n                <option value=\"\" disabled selected>Select Your Rate</option>\r\n                <option>1</option><option>2</option><option>3</option><option>4</option><option>5</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"row align-items-center\">\r\n            <div class=\"col-md-9\">\r\n              <label class=\"form-label fw-semibold\">6. Total Checkout Time (Should Be 15 Min)</label>\r\n            </div>\r\n            <div class=\"col-md-3\">\r\n              <select name=\"checkout_time\" class=\"form-select\" required>\r\n                <option value=\"\" disabled selected>Select Your Rate</option>\r\n                <option>1</option><option>2</option><option>3</option><option>4</option><option>5</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"text-end mt-3\">\r\n            <button type=\"submit\" class=\"btn btn-success\">Submit Checklist</button>\r\n          </div>\r\n        </form>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <script src=\"https://cdn.jsdelivr.net/npm/@popperjs/core@2.11.6/dist/umd/popper.min.js\"></script>\r\n  <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.min.js\"></script>\r\n\r\n  <script>\r\n    // Bootstrap validation\r\n    (function () {\r\n      \'use strict\'\r\n      var forms = document.querySelectorAll(\'.needs-validation\')\r\n      Array.prototype.slice.call(forms)\r\n        .forEach(function (form) {\r\n          form.addEventListener(\'submit\', function (event) {\r\n            if (!form.checkValidity()) {\r\n              event.preventDefault()\r\n              event.stopPropagation()\r\n            }\r\n            form.classList.add(\'was-validated\')\r\n          }, false)\r\n        })\r\n    })()\r\n  </script>\r\n</body>\r\n</html>\r\n', 1, 0, 36, 1, 1, 1, 1763018725, 1, 1763023538, 0, 0, 0, 1763018700, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, 'arrivals.html', 0, 0, 1, NULL, 1),
(39, 'document', 'book-vehicle', '', '', 'book-vehicle', '', 1, 0, 0, 0, 0, '', '<section class=\"hero-wrap hero-wrap-2\" \r\n    style=\"background-image: url(\'assets/images/booking-bg.jpg\'); height: 36rem;\" \r\n    data-stellar-background-ratio=\"0.5\">\r\n    <div class=\"overlay\"></div>\r\n    <div class=\"container\">\r\n      <div class=\"row no-gutters slider-text align-items-end justify-content-center\" style=\"height: 36rem;\">\r\n        <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n          <h1 class=\"mb-2 bread\">Manage Booking</h1>\r\n          <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Manage Booking<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n</section>\r\n\r\n<section id=\"rentResults\" class=\"rentResults py-5 bg-whitee\">\r\n  <div class=\"container\">\r\n    <div class=\"row\">\r\n      <div class=\"col-lg-12\">\r\n        [[!VehiclesCategoryList? &table=`vehicles`]]\r\n      </div>\r\n    </div>\r\n    <div class=\"row mt-5\">\r\n      <div class=\"col-lg-4\">\r\n        [[!RentSearchSummary? &searchPageId=`1`]]\r\n      </div>\r\n      <div class=\"col-lg-8\">\r\n        <div class=\"d-flex justify-content-between align-items-center mb-3\">\r\n          <h2 id=\"vehiclesHeading\" class=\"mb-0\">All vehicles</h2>\r\n\r\n          <div class=\"stepIndicator\" role=\"button\" tabindex=\"0\" aria-label=\"Step 1: Select vehicle\">\r\n            <span class=\"stepIndicator__label\">Step</span>\r\n            <span class=\"stepIndicator__number\">1</span>\r\n            <span class=\"stepIndicator__text\">Select vehicle</span>\r\n          </div>\r\n        </div>\r\n\r\n        [[!VehiclesCategoryList? &table=`vehicles` &mode=`list` &tplItem=`VehicleListItemTpl`]]\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<script>\r\n  document.addEventListener(\'DOMContentLoaded\', () => {\r\n    const stepIndicator = document.querySelector(\'.stepIndicator\');\r\n    const categoryCards = document.querySelectorAll(\'.vehicleScroller [data-category]\');\r\n    const vehicleItems = document.querySelectorAll(\'#vehicleGroups .vehicleItem\');\r\n\r\n    if (!stepIndicator) return;\r\n\r\n    const activateStep = () => {\r\n      stepIndicator.classList.add(\'is-active\');\r\n      const text = stepIndicator.querySelector(\'.stepIndicator__text\');\r\n      if (text) text.textContent = \'Vehicle selected\';\r\n    };\r\n\r\n    categoryCards.forEach(card => {\r\n      card.addEventListener(\'click\', activateStep);\r\n    });\r\n\r\n    vehicleItems.forEach(item => {\r\n      item.addEventListener(\'click\', activateStep);\r\n    });\r\n\r\n    stepIndicator.addEventListener(\'click\', () => {\r\n      const listSection = document.getElementById(\'rentResults\');\r\n      if (listSection) {\r\n        listSection.scrollIntoView({ behavior: \'smooth\', block: \'start\' });\r\n      }\r\n    });\r\n  });\r\n</script>\r\n\r\n<script>\r\n  document.addEventListener(\'DOMContentLoaded\', () => {\r\n    document.querySelectorAll(\'.rentWidgetForm\').forEach((form) => {\r\n      const same = form.querySelector(\'.js-sameLocation\');\r\n      const dropRow = form.querySelector(\'.js-dropoffRow\');\r\n      const dropInput = form.querySelector(\'input[name=\"dropoff_location\"]\');\r\n\r\n      const sync = () => {\r\n        const checked = same && same.checked;\r\n        if (dropRow) dropRow.style.display = checked ? \'none\' : \'\';\r\n        if (checked && dropInput) dropInput.value = \'\';\r\n      };\r\n\r\n      if (same) same.addEventListener(\'change\', sync);\r\n      sync();\r\n\r\n      form.querySelectorAll(\'.rentWidget__clear\').forEach((btn) => {\r\n        btn.addEventListener(\'click\', () => {\r\n          const input = btn.parentElement.querySelector(\'input\');\r\n          if (input) input.value = \'\';\r\n          if (input) input.focus();\r\n        });\r\n      });\r\n    });\r\n  });\r\n</script>\r\n\r\n<script>\r\n  document.addEventListener(\'DOMContentLoaded\', () => {\r\n    if (!window.flatpickr) return;\r\n\r\n    const now = new Date();\r\n\r\n    document.querySelectorAll(\'.rentWidgetForm\').forEach((form) => {\r\n      const pickupInput = form.querySelector(\'input[name=\"pickup_datetime\"]\');\r\n      const dropoffInput = form.querySelector(\'input[name=\"dropoff_datetime\"]\');\r\n\r\n      if (!pickupInput || !dropoffInput) return;\r\n\r\n      let dropoffPicker;\r\n\r\n      const pickupPicker = flatpickr(pickupInput, {\r\n        enableTime: true,\r\n        dateFormat: \"Y-m-d H:i\",\r\n        time_24hr: true,\r\n        minDate: now,\r\n        disableMobile: true,\r\n        onChange: function(selectedDates) {\r\n          if (selectedDates.length && dropoffPicker) {\r\n            dropoffPicker.set(\'minDate\', selectedDates[0]);\r\n\r\n            const currentDrop = dropoffPicker.selectedDates[0];\r\n            if (currentDrop && currentDrop <= selectedDates[0]) {\r\n              dropoffPicker.clear();\r\n            }\r\n          }\r\n        }\r\n      });\r\n\r\n      dropoffPicker = flatpickr(dropoffInput, {\r\n        enableTime: true,\r\n        dateFormat: \"Y-m-d H:i\",\r\n        time_24hr: true,\r\n        minDate: pickupInput.value ? pickupInput.value : now,\r\n        disableMobile: true\r\n      });\r\n    });\r\n  });\r\n</script>\r\n\r\n<script>\r\n  function initAutocomplete() {\r\n    document.querySelectorAll(\'.js-places\').forEach((input) => {\r\n      const ac = new google.maps.places.Autocomplete(input, {\r\n        fields: [\"formatted_address\", \"geometry\", \"name\"],\r\n        componentRestrictions: { country: \"lk\" }\r\n      });\r\n\r\n      ac.addListener(\"place_changed\", () => {\r\n        const place = ac.getPlace();\r\n        if (place && place.formatted_address) {\r\n          input.value = place.formatted_address;\r\n        }\r\n      });\r\n    });\r\n  }\r\n</script>\r\n\r\n<script src=\"https://maps.googleapis.com/maps/api/js?key=AIzaSyAHmbwBrk0OKY0Nhp9FrR_zn8HKLGZ54OU&libraries=places&callback=initAutocomplete\" async defer></script>\r\n\r\n<script>\r\n  document.addEventListener(\'DOMContentLoaded\', () => {\r\n    document.querySelectorAll(\'.vehicleScroller\').forEach(scroller => {\r\n      const rowId = scroller.getAttribute(\'data-scroller\');\r\n      const row = document.getElementById(rowId);\r\n      if (!row) return;\r\n\r\n      const scrollByCards = (dir) => {\r\n        const card = row.querySelector(\'.vehicleCard\');\r\n        const cardW = card ? (card.getBoundingClientRect().width + 12) : 200;\r\n        row.scrollBy({ left: dir * (cardW * 3), behavior: \'smooth\' }); \r\n      };\r\n\r\n      scroller.querySelectorAll(\'.vehicleScroller__btn\').forEach(btn => {\r\n        btn.addEventListener(\'click\', () => {\r\n          const dir = parseInt(btn.getAttribute(\'data-dir\'), 10) || 1;\r\n          scrollByCards(dir);\r\n        });\r\n      });\r\n    });\r\n  });\r\n</script>\r\n\r\n<script>\r\ndocument.addEventListener(\'DOMContentLoaded\', () => {\r\n  const heading = document.getElementById(\'vehiclesHeading\');\r\n  const groups = document.querySelectorAll(\'#vehicleGroups .vehicleGroup\');\r\n  const categoryCards = document.querySelectorAll(\'.vehicleScroller [data-category]\');\r\n\r\n  if (!groups.length || !categoryCards.length) return;\r\n\r\n  const normalize = (str) => (str || \'\').trim().toLowerCase();\r\n\r\n  const showDefaultView = () => {\r\n    if (heading) heading.textContent = \'All vehicles\';\r\n\r\n    groups.forEach(group => {\r\n      const items = group.querySelectorAll(\'.vehicleItem\');\r\n      items.forEach((item, index) => {\r\n        item.style.display = index === 0 ? \'\' : \'none\';\r\n      });\r\n      group.style.display = \'\';\r\n    });\r\n\r\n    categoryCards.forEach(card => card.classList.remove(\'is-active\'));\r\n  };\r\n\r\n  const showCategory = (category) => {\r\n    const selected = normalize(category);\r\n    if (!selected) {\r\n      showDefaultView();\r\n      return;\r\n    }\r\n\r\n    if (heading) heading.textContent = category.toUpperCase();\r\n\r\n    groups.forEach(group => {\r\n      const groupCat = normalize(group.getAttribute(\'data-category\'));\r\n      const items = group.querySelectorAll(\'.vehicleItem\');\r\n\r\n      if (groupCat === selected) {\r\n        group.style.display = \'\';\r\n        items.forEach(item => item.style.display = \'\');\r\n      } else {\r\n        group.style.display = \'none\';\r\n      }\r\n    });\r\n\r\n    categoryCards.forEach(card => {\r\n      const cardCat = normalize(card.getAttribute(\'data-category\'));\r\n      card.classList.toggle(\'is-active\', cardCat === selected);\r\n    });\r\n  };\r\n\r\n  categoryCards.forEach(card => {\r\n    card.addEventListener(\'click\', (e) => {\r\n      e.preventDefault();\r\n      const cat = card.getAttribute(\'data-category\');\r\n      showCategory(cat);\r\n    });\r\n  });\r\n\r\n  showDefaultView();\r\n});\r\n</script>', 1, 2, 37, 1, 1, 1, 1772606037, 1, 1773989618, 0, 0, 0, 1772606100, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1);
INSERT INTO `modx_site_content` (`id`, `type`, `pagetitle`, `longtitle`, `description`, `alias`, `link_attributes`, `published`, `pub_date`, `unpub_date`, `parent`, `isfolder`, `introtext`, `content`, `richtext`, `template`, `menuindex`, `searchable`, `cacheable`, `createdby`, `createdon`, `editedby`, `editedon`, `deleted`, `deletedon`, `deletedby`, `publishedon`, `publishedby`, `menutitle`, `donthit`, `privateweb`, `privatemgr`, `content_dispo`, `hidemenu`, `class_key`, `context_key`, `content_type`, `uri`, `uri_override`, `hide_children_in_tree`, `show_in_tree`, `properties`, `alias_visible`) VALUES
(40, 'document', 'indian', '', '', 'indian', '', 1, 0, 0, 0, 0, '', '\r\n  <style>\r\n    :root{\r\n      --navy:#0b1f3a;\r\n      --navy-2:#132d52;\r\n      --navy-3:#1d3f6f;\r\n      --white:#ffffff;\r\n      --off:#f6f8fc;\r\n      --soft:#edf2f9;\r\n      --text:#5c6a7d;\r\n      --gold:#c79a63;\r\n      --gold-soft:#f1e3d3;\r\n      --border:#dfe6f0;\r\n      --shadow:0 18px 50px rgba(11,31,58,.10);\r\n      --radius-xl:34px;\r\n      --radius-lg:26px;\r\n      --radius-md:20px;\r\n      --container:1200px;\r\n    }\r\n\r\n    .tag{\r\n      display:inline-flex;\r\n      align-items:center;\r\n      gap:8px;\r\n      padding:8px 16px;\r\n      border-radius:999px;\r\n      font-size:14px;\r\n      font-weight:800;\r\n      letter-spacing:.08em;\r\n      text-transform:uppercase;\r\n      background:#fff;\r\n      border:1px solid rgba(255,255,255,.14);\r\n      color:black;\r\n    }\r\n\r\n    .tag--light{\r\n      background:rgba(11,31,58,.06);\r\n      border:1px solid rgba(11,31,58,.08);\r\n      color:var(--navy);\r\n    }\r\n\r\n    .btn{\r\n      display:inline-flex;\r\n      align-items:center;\r\n      justify-content:center;\r\n      gap:10px;\r\n      padding:2px 24px;\r\n      border-radius:999px;\r\n      font-weight:800;\r\n      transition:.3s ease;\r\n      border:none;\r\n      cursor:pointer;\r\n    }\r\n\r\n    /* .btn-primary{\r\n      background:var(--white);\r\n      color:var(--navy);\r\n      box-shadow:0 12px 30px rgba(0,0,0,.10);\r\n    } */\r\n\r\n    /* .btn-primary:hover{\r\n      transform:translateY(-2px);\r\n    } */\r\n\r\n    .btn-dark{\r\n      background:var(--navy);\r\n      color:var(--white);\r\n      box-shadow:var(--shadow);\r\n    }\r\n\r\n    /* .btn-dark:hover{\r\n      background:var(--navy-2);\r\n      transform:translateY(-2px);\r\n    } */\r\n\r\n    .btn-outline{\r\n    background: transparent;\r\n    color: var(--navy);\r\n    border: 1px solid rgba(11,31,58,.18);\r\n    }\r\n\r\n    .btn-outline:hover{\r\n    background: rgba(11,31,58,.05);\r\n    transform: translateY(-2px);\r\n    color:black;\r\n    }\r\n\r\n    .section-head{\r\n      max-width:760px;\r\n      margin:0 auto 40px;\r\n      text-align:center;\r\n    }\r\n\r\n    .section-head h2{\r\n      font-size:clamp(2rem, 3.5vw, 3rem);\r\n      line-height:1.15;\r\n      margin:16px 0 12px;\r\n      font-weight:800;\r\n      color:var(--navy);\r\n    }\r\n\r\n    .section-head p{\r\n      color:var(--text);\r\n      font-size:1.02rem;\r\n    }\r\n\r\n    /* Header */\r\n    .site-header{\r\n      position:sticky;\r\n      top:0;\r\n      z-index:1000;\r\n      background:rgba(255,255,255,.92);\r\n      backdrop-filter:blur(10px);\r\n      border-bottom:1px solid rgba(11,31,58,.07);\r\n    }\r\n\r\n    .nav-wrap{\r\n      min-height:78px;\r\n      display:flex;\r\n      align-items:center;\r\n      justify-content:space-between;\r\n      gap:20px;\r\n    }\r\n\r\n    .logo{\r\n      font-size:1.35rem;\r\n      font-weight:800;\r\n      color:var(--navy);\r\n      letter-spacing:.02em;\r\n    }\r\n\r\n    .logo span{\r\n      color:var(--gold);\r\n    }\r\n\r\n    .nav{\r\n      display:flex;\r\n      align-items:center;\r\n      gap:26px;\r\n      flex-wrap:wrap;\r\n    }\r\n\r\n    .nav a{\r\n      color:var(--navy);\r\n      font-weight:700;\r\n      font-size:.95rem;\r\n    }\r\n\r\n    .nav a:hover{\r\n      color:var(--navy-3);\r\n    }\r\n\r\n    /* Hero */\r\n        .hero{\r\n        position: relative;\r\n        overflow: hidden;\r\n        background:\r\n            radial-gradient(circle at top left, rgba(199,154,99,.10), transparent 24%),\r\n            radial-gradient(circle at bottom right, rgba(11,31,58,.05), transparent 28%),\r\n            linear-gradient(180deg, #ffffff 0%, #f7faff 100%);\r\n        color: var(--navy);\r\n        padding: 40px 0;\r\n        }\r\n\r\n        .hero::before,\r\n        .hero::after{\r\n        content: \"\";\r\n        position: absolute;\r\n        border-radius: 50%;\r\n        z-index: 0;\r\n        }\r\n\r\n        .hero::before{\r\n        width: 260px;\r\n        height: 260px;\r\n        top: -80px;\r\n        right: 8%;\r\n        background: rgba(199,154,99,.10);\r\n        filter: blur(10px);\r\n        }\r\n\r\n        .hero::after{\r\n        width: 180px;\r\n        height: 180px;\r\n        bottom: 20px;\r\n        left: -40px;\r\n        background: rgba(11,31,58,.05);\r\n        filter: blur(8px);\r\n        }\r\n\r\n        .hero-grid{\r\n        display: grid;\r\n        grid-template-columns: 1.06fr .94fr;\r\n        gap: 40px;\r\n        align-items: center;\r\n        position: relative;\r\n        z-index: 1;\r\n        }\r\n\r\n        .hero-content h1{\r\n        font-size: clamp(2.4rem, 5vw, 4.6rem);\r\n        line-height: 1.02;\r\n        margin: 18px 0 18px;\r\n        font-weight: 800;\r\n        max-width: 720px;\r\n        color: var(--navy);\r\n        }\r\n\r\n        .hero-content p{\r\n        color: var(--text);\r\n        max-width: 680px;\r\n        font-size: 14px;\r\n        margin-bottom: 28px;\r\n        }\r\n\r\n        .hero-actions{\r\n        display: flex;\r\n        flex-wrap: wrap;\r\n        gap: 14px;\r\n        margin-bottom: 28px;\r\n        }\r\n\r\n        .hero-points{\r\n        display: grid;\r\n        grid-template-columns: repeat(3,1fr);\r\n        gap: 16px;\r\n        max-width: 760px;\r\n        }\r\n\r\n        .hero-point{\r\n        background: #ffffff;\r\n        border: 1px solid rgba(11,31,58,.08);\r\n        border-radius: 20px;\r\n        padding: 18px;\r\n        box-shadow: 0 14px 35px rgba(11,31,58,.08);\r\n        }\r\n\r\n        .hero-point i{\r\n        color: var(--gold);\r\n        font-size:20px;\r\n        margin-bottom: 10px;\r\n        display: block;\r\n        }\r\n\r\n        .hero-point strong{\r\n        display: block;\r\n        font-size: 14px;\r\n        margin-bottom: 4px;\r\n        color: var(--navy);\r\n        }\r\n\r\n        .hero-point span{\r\n        display: block;\r\n        color: var(--text);\r\n        font-size: 14px;\r\n        line-height: 1.5;\r\n        }\r\n\r\n        .hero-visual{\r\n        position: relative;\r\n        }\r\n\r\n        .hero-main-card{\r\n        background: #ffffff;\r\n        border: 1px solid rgba(11,31,58,.08);\r\n        border-radius: 36px;\r\n        padding: 16px;\r\n        box-shadow: 0 24px 60px rgba(11,31,58,.10);\r\n        }\r\n\r\n        .hero-main-card img{\r\n        width: 100%;\r\n        height: 620px;\r\n        object-fit: cover;\r\n        border-radius: 28px;\r\n        }\r\n\r\n        .floating-card{\r\n        position: absolute;\r\n        background: var(--white);\r\n        color: var(--navy);\r\n        border-radius: 24px;\r\n        padding: 10px 20px;\r\n        box-shadow: 0 18px 40px rgba(11,31,58,.12);\r\n        max-width: 260px;\r\n        border: 1px solid rgba(11,31,58,.06);\r\n        }\r\n\r\n        .floating-card small{\r\n        display: block;\r\n        color: var(--gold);\r\n        font-weight: 800;\r\n        text-transform: uppercase;\r\n        letter-spacing: .08em;\r\n        font-size: 14px;\r\n        }\r\n\r\n        .floating-card strong{\r\n        display: block;\r\n        font-size: 14px;\r\n        margin-bottom: 6px;\r\n        line-height: 1.35;\r\n        color: var(--navy);\r\n        }\r\n\r\n        .floating-card p{\r\n        color: var(--text);\r\n        font-size: 14px;\r\n        line-height: 1.55;\r\n        }\r\n\r\n        .floating-card--top{\r\n        top: -18px;\r\n        right: -12px;\r\n        }\r\n\r\n        .floating-card--bottom{\r\n        left: -18px;\r\n        bottom: 30px;\r\n        }\r\n\r\n      .section-space{\r\n        padding:40px 0;\r\n        background-color:white;\r\n      }\r\n\r\n    /* About / direct booking */\r\n        .editorial-grid{\r\n        display:flex;\r\n        align-items:center;\r\n        }\r\n\r\n    .panel{\r\n      border-radius:var(--radius-xl);\r\n      overflow:hidden;\r\n    }\r\n\r\n    .panel-dark{\r\n      background:var(--navy);\r\n      color:var(--white);\r\n      padding:28px;\r\n    }\r\n\r\n    .panel-dark h2,\r\n    .panel-dark h3{\r\n      color:var(--white);\r\n    }\r\n\r\n    .panel-dark p{\r\n      color:rgba(255,255,255,.82);\r\n    }\r\n\r\n    .panel-image img{\r\n      width:100%;\r\n      height:100%;\r\n      min-height:430px;\r\n      object-fit:cover;\r\n    }\r\n\r\n    .panel-content{\r\n      padding:38px;\r\n    }\r\n\r\n    .panel-content h2,\r\n    .panel-content h3,\r\n    .panel-dark h2,\r\n    .panel-dark h3{\r\n      font-size:clamp(1.7rem, 2.4vw, 2.4rem);\r\n      line-height:1.18;\r\n      margin:16px 0 14px;\r\n      font-weight:800;\r\n    }\r\n\r\n    .panel-content p{\r\n      color:var(--text);\r\n      margin-bottom:14px;\r\n    }\r\n\r\n    .shape-list{\r\n      display:grid;\r\n      gap:14px;\r\n      margin-top:20px;\r\n    }\r\n\r\n    .shape-list li{\r\n      display:flex;\r\n      align-items:flex-start;\r\n      gap:14px;\r\n      padding:14px 16px;\r\n      border-radius:18px;\r\n      background:var(--soft);\r\n      color:var(--navy);\r\n      font-weight:700;\r\n      line-height:1.55;\r\n    }\r\n\r\n    .shape-list li i{\r\n      color:var(--gold);\r\n      margin-top:4px;\r\n      flex-shrink:0;\r\n    }\r\n\r\n    .panel-dark .shape-list li{\r\n      background:rgba(255,255,255,.08);\r\n      color:var(--white);\r\n    }\r\n\r\n    /* Highlight cards */\r\n    .highlight-grid{\r\n      display:grid;\r\n      grid-template-columns:repeat(3,1fr);\r\n      gap:24px;\r\n    }\r\n\r\n    .highlight-card{\r\n      background:var(--white);\r\n      border-radius:28px;\r\n      overflow:hidden;\r\n      box-shadow:var(--shadow);\r\n      transition:.35s ease;\r\n    }\r\n\r\n    .highlight-card:hover{\r\n      transform:translateY(-8px);\r\n    }\r\n\r\n    .highlight-card img{\r\n      width:100%;\r\n      height:240px;\r\n      object-fit:cover;\r\n    }\r\n\r\n    .highlight-card__body{\r\n      padding:26px;\r\n    }\r\n\r\n    .highlight-card__body h3{\r\n      font-size:1.35rem;\r\n      margin-bottom:10px;\r\n      line-height:1.25;\r\n    }\r\n\r\n    .highlight-card__body p{\r\n      color:var(--text);\r\n      margin-bottom:16px;\r\n    }\r\n\r\n    /* Permit strip */\r\n    .permit-strip{\r\n    position: relative;\r\n    overflow: hidden;\r\n    color: var(--white);\r\n    border-radius: 40px;\r\n    padding: 48px;\r\n    box-shadow: var(--shadow);\r\n    background-image: url(\"assets/images/indian-page/permit-bg.jpg\");\r\n    background-size: cover;\r\n    background-position: center;\r\n    background-repeat: no-repeat;\r\n    }\r\n\r\n    .permit-strip::before{\r\n    content: \"\";\r\n    position: absolute;\r\n    inset: 0;\r\n    background: rgb(0 0 0 / 84%);\r\n    z-index: 0;\r\n    }\r\n\r\n    .permit-strip > *{\r\n    position: relative;\r\n    z-index: 1;\r\n    }\r\n\r\n    .permit-grid{\r\n      display:grid;\r\n      grid-template-columns:1.05fr .95fr;\r\n      gap:34px;\r\n      align-items:center;\r\n    }\r\n    .permit-strip .tag{\r\n    background: rgba(255,255,255,.12);\r\n    border: 1px solid rgba(255,255,255,.16);\r\n    color: #fff;\r\n    }\r\n\r\n    .permit-strip h2,\r\n    .permit-strip h3,\r\n    .permit-strip strong{\r\n    color: #fff;\r\n    }\r\n\r\n    .permit-strip p{\r\n    color: rgba(255,255,255,.85);\r\n    }\r\n\r\n    .permit-reqs{\r\n      display:grid;\r\n      grid-template-columns:repeat(3,1fr);\r\n      gap:14px;\r\n      margin-top:20px;\r\n    }\r\n\r\n    .permit-req{\r\n      background:rgba(255,255,255,.08);\r\n      border:1px solid rgba(255,255,255,.10);\r\n      border-radius:20px;\r\n      padding:18px;\r\n      text-align:center;\r\n    }\r\n\r\n    .permit-req i{\r\n      font-size:20px;\r\n      color:#ffd7a8;\r\n      margin-bottom:10px;\r\n    }\r\n\r\n    .permit-req strong{\r\n      display:block;\r\n      font-size:.96rem;\r\n      line-height:1.35;\r\n    }\r\n\r\n    .permit-box{\r\n      background:rgba(255,255,255,.09);\r\n      border:1px solid rgba(255,255,255,.10);\r\n      border-radius:28px;\r\n      padding:21px;\r\n    }\r\n\r\n    .permit-box h3{\r\n      margin-bottom:12px;\r\n      font-size:1.45rem;\r\n    }\r\n\r\n    .permit-box ul{\r\n      display:grid;\r\n      gap:12px;\r\n      margin-top:18px;\r\n    }\r\n\r\n    .permit-box li{\r\n      display:flex;\r\n      gap:12px;\r\n      align-items:flex-start;\r\n      color:rgba(255,255,255,.86);\r\n    }\r\n\r\n    .permit-box li i{\r\n      color:#ffd7a8;\r\n      margin-top:4px;\r\n    }\r\n\r\n    /* Two column info blocks */\r\n    .info-grid{\r\n      display:grid;\r\n      grid-template-columns:1fr 1fr;\r\n      gap:28px;\r\n    }\r\n\r\n    .info-card{\r\n      background:var(--white);\r\n      border-radius:32px;\r\n      padding:34px;\r\n      box-shadow:var(--shadow);\r\n    }\r\n\r\n    .info-card h3{\r\n      font-size:1.8rem;\r\n      line-height:1.2;\r\n      margin:16px 0 14px;\r\n    }\r\n\r\n    .info-card p{\r\n      color:var(--text);\r\n      margin-bottom:14px;\r\n    }\r\n\r\n    /* FAQ */\r\n    .faq-wrap{\r\n      display:grid;\r\n      grid-template-columns:1fr 1fr;\r\n      gap:18px;\r\n    }\r\n\r\n    details.faq-item{\r\n      background:var(--white);\r\n      border-radius:22px;\r\n      padding:20px 22px;\r\n      box-shadow:var(--shadow);\r\n    }\r\n\r\n    details.faq-item summary{\r\n      cursor:pointer;\r\n      font-weight:800;\r\n      color:var(--navy);\r\n      list-style:none;\r\n      position:relative;\r\n      padding-right:26px;\r\n    }\r\n\r\n    details.faq-item summary::-webkit-details-marker{\r\n      display:none;\r\n    }\r\n\r\n    details.faq-item summary::after{\r\n      content:\"+\";\r\n      position:absolute;\r\n      right:0;\r\n      top:0;\r\n      font-size:1.25rem;\r\n      color:var(--gold);\r\n      font-weight:800;\r\n    }\r\n\r\n    details[open].faq-item summary::after{\r\n      content:\"–\";\r\n    }\r\n\r\n    details.faq-item p{\r\n      color:var(--text);\r\n      margin-top:12px;\r\n      padding-top:12px;\r\n      border-top:1px solid var(--border);\r\n    }\r\n\r\n    /* CTA */\r\n    .cta-box{\r\n    position:relative;\r\n    overflow:hidden;\r\n    background:rgba(255,255,255,.65);\r\n    backdrop-filter:blur(12px);\r\n    -webkit-backdrop-filter:blur(12px);\r\n    border:3px solid rgb(0 24 57);\r\n    border-radius:40px;\r\n    padding:30px;\r\n    box-shadow:var(--shadow);\r\n    text-align:center;\r\n\r\n    }\r\n\r\n    /* heading */\r\n    .cta-box h2{\r\n    font-size:clamp(2rem, 3.5vw, 3.2rem);\r\n    line-height:1.1;\r\n    margin:16px auto 14px;\r\n    max-width:820px;\r\n    color:var(--navy);\r\n    }\r\n\r\n    /* text */\r\n    .cta-box p{\r\n    max-width:840px;\r\n    margin:0 auto 14px;\r\n    color:var(--text);\r\n    }\r\n\r\n    /* contact pills */\r\n    .contact-pills{\r\n    display:flex;\r\n    flex-wrap:wrap;\r\n    justify-content:center;\r\n    gap:14px;\r\n    margin:26px 0 30px;\r\n    }\r\n\r\n    .contact-pill{\r\n    background:#ffffff;\r\n    border:1px solid rgb(11 31 58);\r\n    color:var(--navy);\r\n    padding:14px 18px;\r\n    border-radius:999px;\r\n    font-weight:700;\r\n    box-shadow:0 8px 20px rgba(0,0,0,.06);\r\n    }\r\n\r\n    .contact-pill i{\r\n    color:var(--gold);\r\n    margin-right:8px;\r\n    }\r\n\r\n        .btn-primary{\r\n    background:var(--navy);\r\n    color:#fff;\r\n    }\r\n\r\n    .btn-primary-directly {\r\n        background:#fff;\r\n        color:#000;\r\n    }\r\n    .btn-primary-directly:hover {\r\n        background:#fff;\r\n        color:#000;\r\n    }\r\n\r\n    .btn-primary:hover{\r\n    background:#16345d;\r\n    }\r\n\r\n    .btn-outline{\r\n    background:transparent;\r\n    border:1px solid rgba(11,31,58,.20);\r\n    color:var(--navy);\r\n    }\r\n\r\n    .btn-outline:hover{\r\n    background:rgba(17, 46, 85, 0.05);\r\n    }\r\n\r\n    .cta-box::before{\r\n    content:\"\";\r\n    position:absolute;\r\n    inset:0;\r\n    background:\r\n    radial-gradient(circle at top right, rgba(199,154,99,.12), transparent 35%),\r\n    radial-gradient(circle at bottom left, rgba(11,31,58,.08), transparent 35%);\r\n    z-index:-1;\r\n    }\r\n\r\n    /* Responsive */\r\n    @media (max-width: 1100px){\r\n      .hero-grid,\r\n      .editorial-grid,\r\n      .permit-grid,\r\n      .info-grid{\r\n        grid-template-columns:1fr;\r\n      }\r\n\r\n      .highlight-grid{\r\n        grid-template-columns:1fr 1fr;\r\n      }\r\n\r\n      .hero-main-card img{\r\n        height:520px;\r\n      }\r\n\r\n      .floating-card--top{\r\n        right:12px;\r\n      }\r\n\r\n      .floating-card--bottom{\r\n        left:12px;\r\n      }\r\n    }\r\n\r\n    @media (max-width: 900px){\r\n      .nav{\r\n        display:none;\r\n      }\r\n\r\n      .hero-points,\r\n      .permit-reqs,\r\n      .faq-wrap{\r\n        grid-template-columns:1fr;\r\n      }\r\n\r\n      .highlight-grid{\r\n        grid-template-columns:1fr;\r\n      }\r\n\r\n      .cta-box,\r\n      .permit-strip,\r\n      .panel-content,\r\n      .panel-dark,\r\n      .info-card{\r\n        padding:28px;\r\n      }\r\n\r\n      .hero{\r\n        padding-top:70px;\r\n      }\r\n\r\n      .hero-main-card img{\r\n        height:420px;\r\n      }\r\n\r\n      .floating-card{\r\n        position:static;\r\n        max-width:none;\r\n        margin-top:16px;\r\n      }\r\n    }\r\n\r\n    @media (max-width: 600px){\r\n      .section-space{\r\n        padding:72px 0;\r\n      }\r\n\r\n      .nav-wrap{\r\n        min-height:70px;\r\n      }\r\n\r\n      .hero-content h1{\r\n        font-size:2.2rem;\r\n      }\r\n\r\n      .hero-actions{\r\n        flex-direction:column;\r\n        align-items:stretch;\r\n      }\r\n\r\n      .btn{\r\n        width:100%;\r\n      }\r\n\r\n      .panel-image img{\r\n        min-height:300px;\r\n      }\r\n\r\n      .highlight-card img{\r\n        height:210px;\r\n      }\r\n\r\n      .cta-box{\r\n        padding:28px 22px;\r\n      }\r\n    }\r\n  </style>\r\n<body>\r\n    <section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/indian-page/indian-bg.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n        <div class=\"overlay\"></div>\r\n        <div class=\"container\">\r\n            <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n            <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n                <h1 class=\"mb-2 bread\">Indian Travellers</h1>\r\n                <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Indian Travellers<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n            </div>\r\n            </div>\r\n        </div>\r\n    </section>\r\n\r\n    <section class=\"hero\">\r\n    <div class=\"container\">\r\n        <div class=\"hero-grid\">\r\n        <div class=\"hero-content\">\r\n            <span class=\"tag\"><i class=\"fas fa-car-side\"></i> Special Page for Indian Travelers</span>\r\n            <h1>Self Drive Car Rental in Sri Lanka for Indian Travelers</h1>\r\n            <p>\r\n            SR Rent A Car proudly welcomes Indian travelers visiting Sri Lanka with reliable self drive vehicles,\r\n            exclusive offers, permit assistance arranged in advance, and dedicated travel support designed to make\r\n            every journey smooth, flexible, and cost effective.\r\n            </p>\r\n\r\n            <div class=\"hero-actions\">\r\n            <a href=\"[[~39]]\" class=\"btn btn-primary\">Book Your Self Drive Car</a>\r\n            <a href=\"[[~1]]\" class=\"btn btn-outline\">View Special Offers</a>\r\n            </div>\r\n\r\n            <div class=\"hero-points\">\r\n            <div class=\"hero-point\">\r\n                <i class=\"fas fa-percent\"></i>\r\n                <strong>Exclusive Offers</strong>\r\n                <span>Special packages created especially for Indian tourists.</span>\r\n            </div>\r\n            <div class=\"hero-point\">\r\n                <i class=\"fas fa-id-card\"></i>\r\n                <strong>Permit Assistance</strong>\r\n                <span>Advance help with temporary Sri Lanka driving permits.</span>\r\n            </div>\r\n            <div class=\"hero-point\">\r\n                <i class=\"fas fa-headset\"></i>\r\n                <strong>Priority Support</strong>\r\n                <span>Fast guidance before arrival and throughout your journey.</span>\r\n            </div>\r\n            </div>\r\n        </div>\r\n\r\n        <div class=\"hero-visual\">\r\n            <div class=\"hero-main-card\">\r\n            <img src=\"assets/images/indian-page/hero.jpg\" alt=\"Indian travelers with rental vehicle in Sri Lanka\">\r\n            </div>\r\n\r\n            <div class=\"floating-card floating-card--top\">\r\n            <small>Direct Booking Benefit</small>\r\n            <strong>Better pricing without third-party commissions</strong>\r\n            <p>Book directly with SR Rent A Car for more value and personalized support.</p>\r\n            </div>\r\n\r\n            <div class=\"floating-card floating-card--bottom\">\r\n            <small>Travel Freedom</small>\r\n            <strong>Explore Sri Lanka your way</strong>\r\n            <p>Travel with privacy, flexibility, and full control of your own schedule.</p>\r\n            </div>\r\n        </div>\r\n        </div>\r\n    </div>\r\n    </section>\r\n\r\n    <section class=\"section-space\">\r\n      <div class=\"container\">\r\n          <div class=\"row editorial-grid\">\r\n          <div class=\"col-md-6 panel panel-image\">\r\n              <img src=\"assets/images/indian-page/about-direct-booking.jpg\" alt=\"Self drive rental experience in Sri Lanka\">\r\n          </div>\r\n\r\n          <div class=\"col-md-6 panel panel-dark\">\r\n              <span class=\"tag\"><i class=\"fas fa-star\"></i> Why Book Directly</span>\r\n              <h2>Why Book Directly with SR Rent A Car</h2>\r\n              <p>\r\n              Booking directly with SR Rent A Car offers clear advantages for travelers who want better value,\r\n              direct communication, and a more reliable travel experience in Sri Lanka.\r\n              </p>\r\n\r\n              <ul class=\"shape-list\">\r\n              <li><i class=\"fas fa-check-circle\"></i> Competitive pricing without third-party commissions</li>\r\n              <li><i class=\"fas fa-check-circle\"></i> Direct communication with the rental provider</li>\r\n              <li><i class=\"fas fa-check-circle\"></i> Flexible travel plans and customized itineraries</li>\r\n              <li><i class=\"fas fa-check-circle\"></i> Reliable self-drive vehicles maintained by professionals</li>\r\n              </ul>\r\n\r\n              <div style=\"margin-top:24px;\">\r\n                <a href=\"https://wa.me/94777780729?text=Hello%20I%20would%20like%20to%20reserve%20a%20car.%20Please%20assist%20me%20with%20availability.\"\r\n                  class=\"btn btn-primary-directly\"\r\n                  target=\"_blank\">\r\n                  Reserve Directly Today\r\n                </a>              \r\n              </div>\r\n          </div>\r\n          </div>\r\n      </div>\r\n    </section>\r\n\r\n    <section class=\"section-space\" id=\"offers\" style=\"padding-top:0;\">\r\n    <div class=\"container\">\r\n        <div class=\"section-head\">\r\n        <span class=\"tag tag--light\"><i class=\"fas fa-gift\"></i> Exclusive Benefits</span>\r\n        <h2>Special Offers for Indian Travelers</h2>\r\n        <p>\r\n            At SR Rent A Car, we consider Indian travelers our valued neighbors. We provide tailored packages,\r\n            special offers, and practical support to make visiting Sri Lanka more convenient, enjoyable, and cost effective.\r\n        </p>\r\n        </div>\r\n\r\n        <div class=\"highlight-grid\">\r\n        <div class=\"highlight-card\">\r\n            <img src=\"assets/images/indian-page/offers.jpg\" alt=\"Special offers for Indian travelers\">\r\n            <div class=\"highlight-card__body\">\r\n            <h3>Tailored Packages for India</h3>\r\n            <p>\r\n                Enjoy special offers created specifically for Indian tourists with flexible rental plans and personalized support.\r\n            </p>\r\n            <a href=\"[[~1]]\" class=\"btn btn-dark\">Get My Offer</a>\r\n            </div>\r\n        </div>\r\n\r\n        <div class=\"highlight-card\">\r\n            <img src=\"assets/images/indian-page/permit-assistance.jpg\" alt=\"Driving permit assistance\">\r\n            <div class=\"highlight-card__body\">\r\n            <h3>Advance Driving Permit Help</h3>\r\n            <p>\r\n                We arrange assistance for temporary driving permits in advance so your self drive trip can start with less hassle.\r\n            </p>\r\n            <a href=\"[[~6]]\" class=\"btn btn-dark\">Learn About Permit Help</a>\r\n            </div>\r\n        </div>\r\n\r\n        <div class=\"highlight-card\">\r\n            <img src=\"assets/images/indian-page/family-freedom.jpg\" alt=\"Family travel in Sri Lanka\">\r\n            <div class=\"highlight-card__body\">\r\n            <h3>Comfort, Freedom, and Support</h3>\r\n            <p>\r\n                Our goal is to help every Indian traveler enjoy Sri Lanka with confidence, flexibility, and fully personalized service.\r\n            </p>\r\n            <a href=\"[[~6]]\" class=\"btn btn-dark\">Explore Services</a>\r\n            </div>\r\n        </div>\r\n        </div>\r\n    </div>\r\n    </section>\r\n\r\n    <section class=\"section-space\" id=\"self-drive\">\r\n    <div class=\"container\">\r\n        <div class=\"row align-items-center\">\r\n        <div class=\"col-md-6 col-lg-7\">\r\n            <span class=\"tag tag--light\"><i class=\"fas fa-road\"></i> Travel Freedom</span>\r\n            <h2>Why Indian Travelers Choose Self Drive Travel</h2>\r\n            <p>\r\n            Self drive travel allows Indian visitors to explore Sri Lanka with flexibility, privacy, and complete control over their plans.\r\n            </p>\r\n\r\n            <ul class=\"shape-list\">\r\n            <li><i class=\"fas fa-location-dot\"></i> Full freedom to plan your day</li>\r\n            <li><i class=\"fas fa-users\"></i> Travel privately with family, friends, or as a couple</li>\r\n            <li><i class=\"fas fa-camera\"></i> Stop anywhere to explore or capture scenic moments</li>\r\n            <li><i class=\"fas fa-bus\"></i> Avoid crowded buses or shared tours</li>\r\n            <li><i class=\"fas fa-face-smile\"></i> Enjoy a comfortable and stress free journey</li>\r\n            </ul>\r\n\r\n            <p style=\"margin-top:20px;\">\r\n            With our services, Indian travelers receive customized travel support that matches their preferences and ensures a safe, smooth driving experience.\r\n            </p>\r\n        </div>\r\n\r\n        <div class=\"col-md-6 col-lg-5\">\r\n            <img src=\"assets/images/indian-page/self-drive.jpg\" alt=\"Indian tourists enjoying self drive travel in Sri Lanka\" class=\"img-fluid\">\r\n        </div>\r\n        </div>\r\n    </div>\r\n    </section>\r\n\r\n    <section class=\"section-space\" id=\"services\">\r\n    <div class=\"container\">\r\n        <div class=\"section-head\">\r\n        <span class=\"tag tag--light\"><i class=\"fas fa-briefcase\"></i> Tailor Made Support</span>\r\n        <h2>Tailor Made Services for Indian Travelers</h2>\r\n        <p>\r\n            SR Rent A Car provides practical, flexible, and personalized services focused on helping Indian tourists enjoy a hassle free self drive holiday in Sri Lanka.\r\n        </p>\r\n        </div>\r\n\r\n        <div class=\"info-grid\">\r\n        <div class=\"info-card\">\r\n            <span class=\"tag tag--light\"><i class=\"fas fa-car\"></i> What We Provide</span>\r\n            <h3>Services Designed Around Your Travel Needs</h3>\r\n\r\n            <ul class=\"shape-list\">\r\n            <li><i class=\"fas fa-check-circle\"></i> Self drive vehicle rental with special offers for Indian travelers</li>\r\n            <li><i class=\"fas fa-check-circle\"></i> Assistance with temporary Sri Lanka driving permits arranged in advance</li>\r\n            <li><i class=\"fas fa-check-circle\"></i> Flexible rental durations from 1 day to several weeks</li>\r\n            <li><i class=\"fas fa-check-circle\"></i> Guidance on safe driving practices, road rules, and travel tips</li>\r\n            <li><i class=\"fas fa-check-circle\"></i> Priority support for Indian customers planning their trips</li>\r\n            </ul>\r\n        </div>\r\n\r\n        <div class=\"info-card\">\r\n            <span class=\"tag tag--light\"><i class=\"fas fa-heart\"></i> Our Focus</span>\r\n            <h3>Indian Travelers Are a Priority for Us</h3>\r\n            <p>\r\n            We focus on Indian travelers to ensure your self drive experience is fully supported from the moment you plan your trip until the day you return the vehicle.\r\n            </p>\r\n            <p>\r\n            Whether you are traveling as a couple, with children, with friends, or on a longer holiday route, we help you choose a suitable vehicle and guide you through everything you need before driving in Sri Lanka.\r\n            </p>\r\n            <p>\r\n            Our service is designed to be simple, responsive, cost effective, and comfortable, so you can enjoy the island with confidence.\r\n            </p>\r\n\r\n            <div style=\"margin-top:20px;\">\r\n            <a href=\"[[~6]]\" class=\"btn btn-dark\">Talk to Our Team</a>\r\n            </div>\r\n        </div>\r\n        </div>\r\n    </div>\r\n    </section>\r\n\r\n    <section class=\"section-space\" id=\"permit\">\r\n    <div class=\"container\">\r\n        <div class=\"permit-strip\">\r\n        <div class=\"permit-grid\">\r\n            <div>\r\n            <span class=\"tag\"><i class=\"fas fa-id-card-clip\"></i> Driving Permit Assistance</span>\r\n            <h2>Driving Permit Assistance for Indian Tourists</h2>\r\n            <p>\r\n                Indian tourists can legally drive in Sri Lanka with a temporary driving permit. SR Rent A Car provides complete assistance with the process in advance so you can begin your journey with confidence after arrival.\r\n            </p>\r\n\r\n            <div class=\"permit-reqs\">\r\n                <div class=\"permit-req\">\r\n                <i class=\"fas fa-id-card\"></i>\r\n                <strong>Valid Indian Driving License</strong>\r\n                </div>\r\n                <div class=\"permit-req\">\r\n                <i class=\"fas fa-passport\"></i>\r\n                <strong>Passport Copy</strong>\r\n                </div>\r\n                <div class=\"permit-req\">\r\n                <i class=\"fas fa-plane\"></i>\r\n                <strong>Tourist Visa</strong>\r\n                </div>\r\n            </div>\r\n            </div>\r\n\r\n            <div class=\"permit-box\">\r\n            <h3>How We Help</h3>\r\n            <p>\r\n                Our team assists with the documentation and advance coordination needed so your permit process is easier and more convenient.\r\n            </p>\r\n\r\n            <ul>\r\n                <li><i class=\"fas fa-check-circle\"></i> Guidance on required documents before arrival</li>\r\n                <li><i class=\"fas fa-check-circle\"></i> Advance support to avoid last minute confusion</li>\r\n                <li><i class=\"fas fa-check-circle\"></i> Faster start to your self drive travel experience</li>\r\n                <li><i class=\"fas fa-check-circle\"></i> Friendly assistance from our team whenever needed</li>\r\n            </ul>\r\n\r\n            <div style=\"margin-top:22px;\">\r\n                <a href=\"[[~6]]\" class=\"btn btn-primary\">Get Permit Help</a>\r\n            </div>\r\n            </div>\r\n        </div>\r\n        </div>\r\n    </div>\r\n    </section>\r\n\r\n    <section class=\"section-space\" style=\"padding-top:0;\">\r\n    <div class=\"container\">\r\n        <div class=\"info-grid\">\r\n        <div class=\"info-card\">\r\n            <span class=\"tag tag--light\"><i class=\"fas fa-handshake\"></i> Booking Benefits</span>\r\n            <h3>Advantages of Booking Directly with SR Rent A Car</h3>\r\n\r\n            <ul class=\"shape-list\">\r\n            <li><i class=\"fas fa-star\"></i> Exclusive offers and packages for Indian visitors</li>\r\n            <li><i class=\"fas fa-star\"></i> Competitive pricing without third party commissions</li>\r\n            <li><i class=\"fas fa-star\"></i> Direct communication for personalized travel planning</li>\r\n            <li><i class=\"fas fa-star\"></i> Reliable support for a safe and smooth self drive experience</li>\r\n            <li><i class=\"fas fa-star\"></i> Guidance tailored to Indian travelers’ needs</li>\r\n            </ul>\r\n\r\n            <p style=\"margin-top:18px;\">\r\n            We prioritize Indian travelers and aim to make your trip comfortable, safe, and memorable.\r\n            </p>\r\n        </div>\r\n\r\n        <div class=\"info-card\">\r\n            <span class=\"tag tag--light\"><i class=\"fas fa-route\"></i> Driving Tips</span>\r\n            <h3>Self Drive Travel Tips for Indian Tourists</h3>\r\n\r\n            <ul class=\"shape-list\">\r\n            <li><i class=\"fas fa-wallet\"></i> Carry your driving permit and identification while driving</li>\r\n            <li><i class=\"fas fa-gauge-high\"></i> Follow local traffic rules and speed limits</li>\r\n            <li><i class=\"fas fa-map-location-dot\"></i> Use GPS or navigation apps for safe and efficient travel</li>\r\n            <li><i class=\"fas fa-gas-pump\"></i> Plan fuel stops and vehicle support for longer trips</li>\r\n            <li><i class=\"fas fa-phone-volume\"></i> Keep emergency contacts and SR Rent A Car support ready</li>\r\n            </ul>\r\n\r\n            <p style=\"margin-top:18px;\">\r\n            Our team provides dedicated tips and advice for Indian travelers to ensure a stress free experience throughout Sri Lanka.\r\n            </p>\r\n        </div>\r\n        </div>\r\n    </div>\r\n    </section>\r\n\r\n    <section class=\"section-space\" id=\"faq\">\r\n    <div class=\"container\">\r\n        <div class=\"section-head\">\r\n        <span class=\"tag tag--light\"><i class=\"fas fa-circle-question\"></i> Frequently Asked Questions</span>\r\n        <h2>FAQs for Indian Travelers</h2>\r\n        <p>\r\n            Answers to the most common questions about self drive car rental in Sri Lanka for Indian tourists.\r\n        </p>\r\n        </div>\r\n\r\n        <div class=\"faq-wrap\">\r\n        <details class=\"faq-item\">\r\n            <summary>Can Indian tourists drive in Sri Lanka?</summary>\r\n            <p>Yes. Indian tourists can drive with a temporary driving permit issued locally. SR Rent A Car assists you in obtaining it quickly and easily.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>What documents are required for renting a self drive car in Sri Lanka?</summary>\r\n            <p>You need a valid Indian driving license, passport copy, and a tourist visa. Our team guides you through the process for a hassle free experience.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>Do you offer any special discounts for Indian travelers?</summary>\r\n            <p>Yes. We provide exclusive offers, packages, and tailor made services specifically for Indian tourists.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>Are the vehicles insured?</summary>\r\n            <p>All vehicles are fully insured and regularly maintained to ensure your safety and peace of mind.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>Can I rent a car for just a few days?</summary>\r\n            <p>Yes. Rental durations are flexible, ranging from one day to several weeks depending on your travel plans.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>What types of vehicles are available for Indian travelers?</summary>\r\n            <p>We provide options suitable for couples, families, and groups including sedans, SUVs, and premium vehicles.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>Do you provide support for planning travel routes?</summary>\r\n            <p>Yes. We offer guidance on safe and scenic driving routes, local road rules, and travel tips for Indian visitors.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>Is driving in Sri Lanka safe for Indian tourists?</summary>\r\n            <p>Yes. Sri Lanka is safe for tourists and our team provides driving tips, road safety advice, and local traffic guidance to ensure a secure journey.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>Can I extend my rental while I am in Sri Lanka?</summary>\r\n            <p>Yes. Rental extensions are possible. Simply contact our team in advance and we will adjust your booking accordingly.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>Are there additional charges for Indian traveler support?</summary>\r\n            <p>No. Indian travelers enjoy priority guidance and dedicated support included in all services.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>How do I apply for a temporary driving permit?</summary>\r\n            <p>SR Rent A Car provides full assistance with paperwork guidance and advance arrangements to help you get your permit more easily.</p>\r\n        </details>\r\n\r\n        <details class=\"faq-item\">\r\n            <summary>How can I book a car and secure my special offer?</summary>\r\n            <p>You can contact us via WhatsApp, email, or our website. Our team will help you choose a vehicle, apply your exclusive Indian traveler offers, and complete your booking quickly.</p>\r\n        </details>\r\n        </div>\r\n    </div>\r\n    </section>\r\n\r\n    <section class=\"section-space\" id=\"book\">\r\n    <div class=\"container\">\r\n        <div class=\"cta-box\">\r\n        <span class=\"tag\"><i class=\"fas fa-phone-volume\"></i> Book Your Self Drive Car Today</span>\r\n        <h2>Indian Travelers Are Our Priority</h2>\r\n        <p>\r\n            We are dedicated to making your Sri Lanka trip unforgettable, comfortable, and cost effective.\r\n            Our team will assist you in choosing the right vehicle, handling permit support in advance, and\r\n            providing personalized travel advice so you can focus on enjoying your journey.\r\n        </p>\r\n\r\n        <div class=\"contact-pills\">\r\n            <a href=\"https://wa.me/94777780729\" class=\"contact-pill\" target=\"_blank\">\r\n            <i class=\"fab fa-whatsapp\"></i> WhatsApp: +94 77 778 0729\r\n            </a>\r\n            <a href=\"mailto:info@srilankarentacar.com\" class=\"contact-pill\">\r\n            <i class=\"fas fa-envelope\"></i> info@srilankarentacar.com\r\n            </a>\r\n        </div>\r\n        </div>\r\n    </div>\r\n    </section>\r\n\r\n\r\n\r\n<script>\r\nfunction scrollToPromo() {\r\n  setTimeout(() => {\r\n    const el = document.querySelector(\'.promo50-section\');\r\n    if (el) {\r\n      el.scrollIntoView({ behavior: \'smooth\' });\r\n    }\r\n  }, 300);\r\n}\r\n</script>\r\n</body>\r\n', 1, 2, 38, 1, 1, 1, 1773397977, 1, 1774188149, 0, 0, 0, 1773397980, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1),
(41, 'document', 'vehicle-booking', '', '', 'vehicle-booking', '', 1, 0, 0, 0, 0, '', '\r\n\r\n<section class=\"hero-wrap hero-wrap-2\" \r\n    style=\"background-image: url(\'assets/images/booking-bg.jpg\'); height: 36rem;\" \r\n    data-stellar-background-ratio=\"0.5\">\r\n		<div class=\"overlay\"></div>\r\n		<div class=\"container\">\r\n		  <div class=\"row no-gutters slider-text align-items-end justify-content-center\" style=\"height: 36rem;\">\r\n			<div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n			  <h1 class=\"mb-2 bread\">Manage Booking</h1>\r\n			  <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>Manage Booking<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n			</div>\r\n		  </div>\r\n		</div>\r\n</section>\r\n\r\n<section class=\"bookingStepPage py-5\">\r\n  <div class=\"container\">\r\n\r\n    <div class=\"bookingSteps mb-4\">\r\n      <div class=\"bookingSteps__item bookingSteps__item--done\">\r\n        <span class=\"bookingSteps__num\">1</span>\r\n        <span class=\"bookingSteps__text\">Select vehicle</span>\r\n      </div>\r\n\r\n      <div class=\"bookingSteps__line bookingSteps__line--active\"></div>\r\n\r\n      <div class=\"bookingSteps__item bookingSteps__item--active\">\r\n        <span class=\"bookingSteps__num\">2</span>\r\n        <span class=\"bookingSteps__text\">Your deal</span>\r\n      </div>\r\n\r\n      <div class=\"bookingSteps__line\"></div>\r\n\r\n      <div class=\"bookingSteps__item\">\r\n        <span class=\"bookingSteps__num\">3</span>\r\n        <span class=\"bookingSteps__text\">Coverage</span>\r\n      </div>\r\n\r\n      <div class=\"bookingSteps__line\"></div>\r\n\r\n      <div class=\"bookingSteps__item\">\r\n        <span class=\"bookingSteps__num\">4</span>\r\n        <span class=\"bookingSteps__text\">Driver details</span>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"bookingStepTopbar mb-4\">\r\n<a href=\"[[~39]]\" class=\"bookingStepTopbar__back\">← Back to results</a>\r\n      <div class=\"bookingStepTopbar__next\">\r\n        Next: Coverage\r\n      </div>\r\n    </div>\r\n\r\n    [[!VehicleDealStep2]]\r\n\r\n  </div>\r\n</section>', 1, 2, 39, 1, 1, 1, 1773638237, 1, 1773903933, 0, 0, 0, 1773638220, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1);
