(42, 'document', 'international-travellers', '', '', 'international-travellers', '', 1, 0, 0, 0, 0, '', '<section class=\"hero-wrap hero-wrap-2\" style=\"background-image: url(\'assets/images/indian-page/indian-bg.jpg\');\" data-stellar-background-ratio=\"0.5\">\r\n  <div class=\"overlay\"></div>\r\n  <div class=\"container\">\r\n      <div class=\"row no-gutters slider-text align-items-end justify-content-center\">\r\n      <div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n          <h1 class=\"mb-2 bread\">International Travellers</h1>\r\n          <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\"><span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span> <span>International Travellers<i class=\"ion-ios-arrow-forward\"></i></span></p>\r\n      </div>\r\n      </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"section-padding premium-section\">\r\n  <div class=\"container\">\r\n    <div class=\"row align-items-center g-5\">\r\n      <div class=\"col-lg-6\">\r\n        <span class=\"section-eyebrow\">A warm welcome to global explorers</span>\r\n        <h2 class=\"section-title premium-heading\">Welcome Travelers from All Regions</h2>\r\n\r\n        <p class=\"premium-text\">\r\n          SR Rent A Car proudly welcomes tourists from\r\n          <strong>Asia, Europe, North America, South America, Africa, and Oceania.</strong>\r\n        </p>\r\n\r\n        <p class=\"premium-text\">\r\n          Our self drive car rental services offer the privacy, flexibility, and confidence you need to explore\r\n          Sri Lanka’s breathtaking landscapes, golden beaches, and cultural wonders at your own pace.\r\n        </p>\r\n\r\n        <p class=\"premium-text\">\r\n          Every journey is designed to feel smooth, secure, and effortless — wherever you are traveling from.\r\n        </p>\r\n\r\n        <div class=\"mt-4 d-flex flex-wrap gap-3\">\r\n          <a href=\"[[~39]]\" class=\"btn btn-premium-luxury\">Explore Vehicles</a>\r\n          <a href=\"https://wa.me/94777780729\" class=\"btn btn-outline-premium\" target=\"_blank\">Talk on WhatsApp</a>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-lg-6 text-center\">\r\n        <div class=\"premium-image-wrap\">\r\n          <img src=\"assets/images/international/self-drive.jpg\" class=\"img-fluid premium-img\" alt=\"Premium self drive experience\">\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"premium-dark-section py-5\">\r\n  <div class=\"container\">\r\n    <div class=\"text-center mb-5\">\r\n      <span class=\"section-eyebrow text-gold\">Why choose self drive</span>\r\n      <h2 class=\"premium-heading text-white\">Why Self Drive is Ideal for Global Travelers</h2>\r\n    </div>\r\n\r\n    <div class=\"row\">\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"luxury-card text-center h-100\">\r\n          <i class=\"fa fa-map-marked-alt luxury-icon\"></i>\r\n          <h5>Create Your Own Itinerary</h5>\r\n          <p>Enjoy complete independence to explore Sri Lanka on your own terms and timeline.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"luxury-card text-center h-100\">\r\n          <i class=\"fa fa-user-friends luxury-icon\"></i>\r\n          <h5>Complete Privacy</h5>\r\n          <p>Ideal for couples, families, and groups seeking a relaxed and personal travel experience.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"luxury-card text-center h-100\">\r\n          <i class=\"fa fa-camera luxury-icon\"></i>\r\n          <h5>Freedom to Stop Anywhere</h5>\r\n          <p>Pause for scenic moments, local cuisine, hidden beaches, and spontaneous discoveries.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"luxury-card text-center h-100\">\r\n          <i class=\"fa fa-globe luxury-icon\"></i>\r\n          <h5>Authentic Island Experience</h5>\r\n          <p>Travel deeper into Sri Lanka’s culture, heritage, and nature with total flexibility.</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"section-padding premium-section\">\r\n  <div class=\"container\">\r\n    <div class=\"row align-items-center g-5\">\r\n      <div class=\"col-lg-6\">\r\n        <div class=\"premium-image-wrap\">\r\n          <img src=\"assets/images/international/rental-fleet.jpg\" class=\"img-fluid premium-img\" alt=\"Luxury rental fleet\">\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-lg-6\">\r\n        <span class=\"section-eyebrow\">Designed for international visitors</span>\r\n        <h2 class=\"premium-heading mb-4\">Tailored Services for Global Travelers</h2>\r\n\r\n        <ul class=\"premium-list\">\r\n          <li>Wide selection of compact cars, sedans, SUVs, and premium models</li>\r\n          <li>Assistance with Sri Lanka temporary driving permits</li>\r\n          <li>Flexible rental periods from 1 day to several weeks</li>\r\n          <li>Guidance on road safety and local traffic regulations</li>\r\n          <li>Dedicated support in English and other major languages</li>\r\n          <li>Exclusive travel solutions for international guests</li>\r\n          <li>Optional navigation and accommodation assistance</li>\r\n        </ul>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"premium-highlight-section py-5\">\r\n  <div class=\"container text-center\">\r\n    <span class=\"section-eyebrow text-gold\">Drive legally with ease</span>\r\n    <h2 class=\"premium-heading text-white mb-4\">Temporary Driving Permit Assistance</h2>\r\n\r\n    <p class=\"premium-text text-light mx-auto\" style=\"max-width: 760px;\">\r\n      International travelers can legally drive in Sri Lanka using a temporary driving permit.\r\n      SR Rent A Car arranges the process in advance so your journey begins without delay.\r\n    </p>\r\n\r\n    <div class=\"row justify-content-center mt-5\">\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"permit-card\">\r\n          <i class=\"fa fa-id-card luxury-icon\"></i>\r\n          <p>Valid Driving License</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"permit-card\">\r\n          <i class=\"fa fa-passport luxury-icon\"></i>\r\n          <p>Passport Copy</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"permit-card\">\r\n          <i class=\"fa fa-plane luxury-icon\"></i>\r\n          <p>Tourist Visa</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"section-padding premium-light-bg\">\r\n  <div class=\"container\">\r\n    <div class=\"text-center mb-5\">\r\n      <span class=\"section-eyebrow\">Why book direct</span>\r\n      <h2 class=\"premium-heading\">Benefits of Booking Directly</h2>\r\n    </div>\r\n\r\n    <div class=\"row\">\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"benefit-card text-center h-100\">\r\n          <h5>No Hidden Fees</h5>\r\n          <p>Clear, transparent pricing with no surprises.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"benefit-card text-center h-100\">\r\n          <h5>Exclusive Promotions</h5>\r\n          <p>Special offers reserved for direct international bookings.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"benefit-card text-center h-100\">\r\n          <h5>Travel Guidance</h5>\r\n          <p>Helpful recommendations for routes, destinations, and travel comfort.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-3 mb-4\">\r\n        <div class=\"benefit-card text-center h-100\">\r\n          <h5>Reliable Support</h5>\r\n          <p>Professional assistance before, during, and throughout your rental.</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"section-padding premium-section\">\r\n  <div class=\"container\">\r\n    <div class=\"text-center mb-5\">\r\n      <span class=\"section-eyebrow\">Helpful information</span>\r\n      <h2 class=\"premium-heading\">Frequently Asked Questions</h2>\r\n    </div>\r\n\r\n    <div class=\"row premium-faq\">\r\n      <div class=\"col-md-6 col-lg-4 faq-item\">\r\n        <div class=\"faq-question\">Can travelers from all regions drive in Sri Lanka?</div>\r\n        <div class=\"faq-answer\">Yes. A temporary driving permit is required, and our team assists with the process.</div>\r\n      </div>\r\n\r\n      <div class=\"col-md-6 col-lg-4 faq-item\">\r\n        <div class=\"faq-question\">What documents are needed?</div>\r\n        <div class=\"faq-answer\">A valid driving license, passport copy, and tourist visa are required.</div>\r\n      </div>\r\n\r\n      <div class=\"col-md-6 col-lg-4 faq-item\">\r\n        <div class=\"faq-question\">Are vehicles insured?</div>\r\n        <div class=\"faq-answer\">Yes. All vehicles are insured, professionally maintained, and prepared for safe travel.</div>\r\n      </div>\r\n\r\n      <div class=\"col-md-6 col-lg-4 faq-item\">\r\n        <div class=\"faq-question\">Can I reserve a car before arriving? </div>\r\n        <div class=\"faq-answer\">Yes. Online reservations are available via WhatsApp, email, or website </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-6 col-lg-4 faq-item\">\r\n        <div class=\"faq-question\">Can I rent for a few days only </div>\r\n        <div class=\"faq-answer\">Yes. Rentals are flexible from 1 day to several weeks  </div>\r\n      </div>\r\n\r\n      <div class=\"col-md-6 col-lg-4 faq-item\">\r\n        <div class=\"faq-question\">What types of vehicles are available?  </div>\r\n        <div class=\"faq-answer\">Sedans, SUVs, and premium cars suitable for all travelers</div>\r\n      </div>\r\n\r\n      <div class=\"col-md-6 col-lg-4 faq-item\">\r\n        <div class=\"faq-question\">Do you provide travel guidance?   </div>\r\n        <div class=\"faq-answer\">Yes. Advice on road safety, driving tips, and local regulations is provided</div>\r\n      </div>\r\n      <div class=\"col-md-6 col-lg-4 faq-item\">\r\n        <div class=\"faq-question\">Can I extend my rental?   </div>\r\n        <div class=\"faq-answer\">Yes. Contact our team in advance </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<section class=\"premium-cta-section text-center\">\r\n  <div class=\"container\">\r\n    <span class=\"section-eyebrow text-gold\">Start your journey</span>\r\n    <h2 class=\"premium-heading text-white mb-4\">Book Your Self Drive Adventure Today</h2>\r\n\r\n    <p class=\"premium-text text-light mx-auto\" style=\"max-width: 760px;\">\r\n      Travelers from around the world are welcome. We help with vehicle selection,\r\n      temporary permits, and personalized travel guidance for a seamless Sri Lankan experience.\r\n    </p>\r\n\r\n    <div class=\"mt-4\">\r\n      <a href=\"https://wa.me/94777780729\" class=\"btn btn-light-premium btn-lg\" target=\"_blank\">WhatsApp Us</a>\r\n    </div>\r\n\r\n    <p class=\"mt-4 mb-0 text-light\"><a href=\"mailto:info@srilankarentacar.com\" class=\"text-white\">Email: info@srilankarentacar.com</a></p>\r\n  </div>\r\n</section>', 1, 2, 40, 1, 1, 1, 1773648683, 1, 1773650442, 0, 0, 0, 1773648660, 1, '', 0, 0, 0, 0, 0, 'MODX\\Revolution\\modDocument', 'web', 1, '', 0, 0, 1, NULL, 1),
(43, 'document', 'coverage-details', '', '', 'coverage-details', '', 1, 0, 0, 0, 0, '', '<section class=\"hero-wrap hero-wrap-2\" \r\n    style=\"background-image: url(\'assets/images/booking-bg.jpg\'); height: 36rem;\" \r\n    data-stellar-background-ratio=\"0.5\">\r\n		<div class=\"overlay\"></div>\r\n		<div class=\"container\">\r\n		  <div class=\"row no-gutters slider-text align-items-end justify-content-center\" style=\"height: 36rem;\">\r\n			<div class=\"col-md-9 ftco-animate text-center mb-4\">\r\n			  <h1 class=\"mb-2 bread\">Manage Booking</h1>\r\n			   <p class=\"breadcrumbs\" style=\"padding-bottom: 20px;\">\r\n          <span class=\"mr-2\"><a href=\"[[~1]]\">Home <i class=\"ion-ios-arrow-forward\"></i></a></span>\r\n          <span class=\"mr-2\"><a href=\"javascript:history.back()\">Step 2 <i class=\"ion-ios-arrow-forward\"></i></a></span>\r\n          <span>Coverage<i class=\"ion-ios-arrow-forward\"></i></span>\r\n        </p>\r\n			</div>\r\n		  </div>\r\n		</div>\r\n</section>\r\n\r\n<section class=\"bookingStepPage py-5\">\r\n  <div class=\"container\">\r\n\r\n    <div class=\"bookingSteps mb-4\">\r\n      <div class=\"bookingSteps__item bookingSteps__item--done\">\r\n        <span class=\"bookingSteps__num\">1</span>\r\n        <span class=\"bookingSteps__text\">Select vehicle</span>\r\n      </div>\r\n\r\n      <div class=\"bookingSteps__line bookingSteps__line--active\"></div>\r\n\r\n      <div class=\"bookingSteps__item bookingSteps__item--done\">\r\n        <span class=\"bookingSteps__num\">2</span>\r\n        <span class=\"bookingSteps__text\">Your deal</span>\r\n      </div>\r\n\r\n      <div class=\"bookingSteps__line bookingSteps__line--active\"></div>\r\n\r\n      <div class=\"bookingSteps__item bookingSteps__item--active\">\r\n        <span class=\"bookingSteps__num\">3</span>\r\n        <span class=\"bookingSteps__text\">Coverage</span>\r\n      </div>\r\n\r\n      <div class=\"bookingSteps__line\"></div>\r\n\r\n      <div class=\"book